module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 저작권 보호기간 만료 공공저작물."},"kids":{"label":"쉬운말","note":"쉬운말 — 어린이용 의역"}},"chapters":[{"chapter":1,"title":"말씀이 육신이 되신 예수님","verses":{"krv":[{"n":1,"t":"태초에 말씀이 계시니라 이 말씀이 하나님과 함께 계셨으니 이 말씀은 곧 하나님이시니라"},{"n":2,"t":"그가 태초에 하나님과 함께 계셨고"},{"n":3,"t":"만물이 그로 말미암아 지은바 되었으니 지은 것이 하나도 그가 없이는 된 것이 없느니라"},{"n":4,"t":"그 안에 생명이 있었으니 이 생명은 사람들의 빛이라"},{"n":5,"t":"빛이 어두움에 비취되 어두움이 깨닫지 못하더라"},{"n":6,"t":"하나님께로서 보내심을 받은 사람이 났으니 이름은 요한이라"},{"n":7,"t":"저가 증거하러 왔으니 곧 빛에 대하여 증거하고 모든 사람으로 자기를 인하여 믿게 하려 함이라"},{"n":8,"t":"그는 이 빛이 아니요 이 빛에 대하여 증거하러 온 자라"},{"n":9,"t":"참빛 곧 세상에 와서 각 사람에게 비취는 빛이 있었나니"},{"n":10,"t":"그가 세상에 계셨으며 세상은 그로 말미암아 지은바 되었으되 세상이 그를 알지 못하였고"},{"n":11,"t":"자기 땅에 오매 자기 백성이 영접지 아니하였으나"},{"n":12,"t":"영접하는 자 곧 그 이름을 믿는 자들에게는 하나님의 자녀가 되는 권세를 주셨으니"},{"n":13,"t":"이는 혈통으로나 육정으로나 사람의 뜻으로 나지 아니하고 오직 하나님께로서 난 자들이니라"},{"n":14,"t":"말씀이 육신이 되어 우리 가운데 거하시매 우리가 그 영광을 보니 아버지의 독생자의 영광이요 은혜와 진리가 충만하더라"},{"n":15,"t":"요한이 그에 대하여 증거하여 외쳐 가로되 내가 전에 말하기를 내 뒤에 오시는 이가 나보다 앞선 것은 나보다 먼저 계심이니라 한 것이 이 사람을 가리킴이라 하니라"},{"n":16,"t":"우리가 다 그의 충만한데서 받으니 은혜 위에 은혜러라"},{"n":17,"t":"율법은 모세로 말미암아 주신 것이요 은혜와 진리는 예수 그리스도로 말미암아 온 것이라"},{"n":18,"t":"본래 하나님을 본 사람이 없으되 아버지 품속에 있는 독생하신 하나님이 나타내셨느니라"},{"n":19,"t":"유대인들이 예루살렘에서 제사장들과 레위인들을 요한에게 보내어 네가 누구냐 물을 때에 요한의 증거가 이러하니라"},{"n":20,"t":"요한이 드러내어 말하고 숨기지 아니하니 드러내어 하는 말이 나는 그리스도가 아니라 한대"},{"n":21,"t":"또 묻되 그러면 무엇, 네가 엘리야냐 가로되 나는 아니라 또 묻되 네가 그 선지자냐 대답하되 아니라"},{"n":22,"t":"또 말하되 누구냐 우리를 보낸 이들에게 대답하게 하라 너는 네게 대하여 무엇이라 하느냐"},{"n":23,"t":"가로되 나는 선지자 이사야의 말과 같이 주의 길을 곧게 하라고 광야에서 외치는 자의 소리로라 하니라"},{"n":24,"t":"저희는 바리새인들에게서 보낸 자라"},{"n":25,"t":"또 물어 가로되 네가 만일 그리스도도 아니요 엘리야도 아니요 그 선지자도 아닐진대 어찌하여 세례를 주느냐"},{"n":26,"t":"요한이 대답하되 나는 물로 세례를 주거니와 너희 가운데 너희가 알지 못하는 한 사람이 섰으니"},{"n":27,"t":"곧 내 뒤에 오시는 그이라 나는 그의 신들메 풀기도 감당치 못하겠노라 하더라"},{"n":28,"t":"이 일은 요한의 세례 주던 곳 요단강 건너편 베다니에서 된 일이니라"},{"n":29,"t":"이튿날 요한이 예수께서 자기에게 나아오심을 보고 가로되 보라 세상 죄를 지고 가는 하나님의 어린 양이로다"},{"n":30,"t":"내가 전에 말하기를 내 뒤에 오는 사람이 있는데 나보다 앞선 것은 그가 나보다 먼저 계심이라 한 것이 이 사람을 가리킴이라"},{"n":31,"t":"나도 그를 알지 못하였으나 내가 와서 물로 세례를 주는 것은 그를 이스라엘에게 나타내려 함이라 하니라"},{"n":32,"t":"요한이 또 증거하여 가로되 내가 보매 성령이 비둘기 같이 하늘로서 내려와서 그의 위에 머물렀더라"},{"n":33,"t":"나도 그를 알지 못하였으나 나를 보내어 물로 세례를 주라 하신 그이가 나에게 말씀하시되 성령이 내려서 누구 위에든지 머무는 것을 보거든 그가 곧 성령으로 세례를 주는 이인줄 알라 하셨기에"},{"n":34,"t":"내가 보고 그가 하나님의 아들이심을 증거하였노라 하니라"},{"n":35,"t":"또 이튿날 요한이 자기 제자 중 두 사람과 함께 섰다가"},{"n":36,"t":"예수의 다니심을 보고 말하되 보라 하나님의 어린 양이로다"},{"n":37,"t":"두 제자가 그의 말을 듣고 예수를 좇거늘"},{"n":38,"t":"예수께서 돌이켜 그 좇는 것을 보시고 물어 가라사대 무엇을 구하느냐 가로되 랍비여 어디 계시오니이까 하니 (랍비는 번역하면 선생이라)"},{"n":39,"t":"예수께서 가라사대 와 보라 그러므로 저희가 가서 계신데를 보고 그 날 함께 거하니 때가 제 십시쯤 되었더라"},{"n":40,"t":"요한의 말을 듣고 예수를 좇는 두 사람 중에 하나는 시몬 베드로의 형제 안드레라"},{"n":41,"t":"그가 먼저 자기의 형제 시몬을 찾아 말하되 우리가 메시야를 만났다 하고 (메시야는 번역하면 그리스도라)"},{"n":42,"t":"데리고 예수께로 오니 예수께서 보시고 가라사대 네가 요한의 아들 시몬이니 장차 게바라 하리라 하시니라 (게바는 번역하면 베드로라)"},{"n":43,"t":"이튿날 예수께서 갈릴리로 나가려 하시다가 빌립을 만나 이르시되 나를 좇으라 하시니"},{"n":44,"t":"빌립은 안드레와 베드로와 한 동네 벳새다 사람이라"},{"n":45,"t":"빌립이 나다나엘을 찾아 이르되 모세가 율법에 기록하였고 여러 선지자가 기록한 그이를 우리가 만났으니 요셉의 아들 나사렛 예수니라"},{"n":46,"t":"나다나엘이 가로되 나사렛에서 무슨 선한 것이 날 수 있느냐 빌립이 가로되 와 보라 하니라"},{"n":47,"t":"예수께서 나다나엘이 자기에게 오는 것을 보시고 그를 가리켜 가라사대 보라 이는 참 이스라엘 사람이라 그 속에 간사한 것이 없도다"},{"n":48,"t":"나다나엘이 가로되 어떻게 나를 아시나이까 예수께서 대답하여 가라사대 빌립이 너를 부르기 전에 네가 무화과나무 아래 있을 때에 보았노라"},{"n":49,"t":"나다나엘이 대답하되 랍비여 당신은 하나님의 아들이시요 당신은 이스라엘의 임금이로소이다"},{"n":50,"t":"예수께서 대답하여 가라사대 내가 너를 무화과나무 아래서 보았다 하므로 믿느냐 이보다 더 큰 일을 보리라"},{"n":51,"t":"또 가라사대 진실로 진실로 너희에게 이르노니 하늘이 열리고 하나님의 사자들이 인자 위에 오르락 내리락하는 것을 보리라 하시니라"}],"kids":[{"n":1,"t":"맨 처음부터 말씀이 계셨고 말씀이 하나님과 함께 계셨고 말씀이 곧 하나님이셨어요."},{"n":2,"t":"그분이 맨 처음부터 하나님과 함께 계셨어요."},{"n":3,"t":"모든 것이 그분으로 인해 만들어졌고 만들어진 것 중에 그분 없이 만들어진 것이 하나도 없어요."},{"n":4,"t":"그분 안에 생명이 있었고 그 생명은 사람의 빛이었어요."},{"n":5,"t":"빛이 어둠 속에서 비추는데 어둠이 그 빛을 이기지 못했어요."},{"n":6,"t":"하나님이 보내신 한 사람이 있었어요. 이름은 요한이에요."},{"n":7,"t":"그가 증언하러 왔어요. 빛에 대해 증언하여 모두가 자기로 인해 믿게 하려고요."},{"n":8,"t":"그가 빛이 아니라 빛에 대해 증언하러 왔어요."},{"n":9,"t":"세상에 와서 모든 사람에게 비추는 참된 빛이 계셨어요."},{"n":10,"t":"그분이 세상에 계셨고 세상이 그분으로 인해 만들어졌는데 세상은 그분을 알지 못했어요."},{"n":11,"t":"자기 백성에게 오셨지만 자기 백성이 그분을 받아들이지 않았어요."},{"n":12,"t":"그분을 받아들이는 모든 사람, 곧 그분의 이름을 믿는 사람들에게는 하나님의 자녀가 되는 권세를 주셨어요."},{"n":13,"t":"그들은 사람의 핏줄이나 육체의 뜻이나 사람의 뜻으로가 아니라 하나님으로부터 태어났어요."},{"n":14,"t":"말씀이 육신이 되어 우리 가운데 사셨고, 우리가 그분의 영광을 보았어요. 아버지의 외아들의 영광이고 은혜와 진리가 가득했어요."},{"n":15,"t":"요한이 그분에 대해 증언하며 외쳤어요. \\"내가 말한 분이 이분이세요. \'내 뒤에 오시는 분이 나보다 앞서신 분이다. 나보다 먼저 계셨기 때문이다\'라고 했지요.\\""},{"n":16,"t":"그분의 충만함에서 우리가 다 받았고 은혜 위에 은혜가 더해졌어요."},{"n":17,"t":"율법은 모세를 통해 주어졌고 은혜와 진리는 예수 그리스도로 인해 왔어요."},{"n":18,"t":"누구도 하나님을 본 적이 없어요. 아버지 품 안에 계신 외아들 하나님이 그분을 알려 주셨어요."},{"n":19,"t":"유대인이 예루살렘에서 제사장과 레위인들을 요한에게 보내 \\"당신은 누구세요?\\" 하고 물었을 때 요한의 증언은 이것이에요."},{"n":20,"t":"그가 부인하지 않고 솔직하게 \\"나는 그리스도가 아니에요\\" 했어요."},{"n":21,"t":"\\"그러면 누구세요? 엘리야세요?\\" 하니 \\"아니에요\\" 했어요. \\"그 예언자세요?\\" 하니 \\"아니에요\\" 했어요."},{"n":22,"t":"\\"누구신지 알려 주세요. 우리를 보낸 사람들에게 답할 수 있게요. 자신에 대해 뭐라고 말하세요?\\" 했어요."},{"n":23,"t":"요한이 \\"이사야 예언자가 말한 대로, 나는 광야에서 외치는 사람의 소리예요. \'주의 길을 곧게 하라\'고요\\" 했어요."},{"n":24,"t":"보냄받은 사람들 중 어떤 사람은 바리새인이었어요."},{"n":25,"t":"그들이 \\"당신이 그리스도도 아니고 엘리야도 아니고 그 예언자도 아니면 왜 세례를 줘요?\\" 했어요."},{"n":26,"t":"요한이 \\"나는 물로 세례를 줘요. 그러나 너희 가운데 너희가 알지 못하는 분이 서 계세요.\\""},{"n":27,"t":"\\"내 뒤에 오시는 분인데 나는 그분의 신발 끈을 풀 자격도 없어요\\" 했어요."},{"n":28,"t":"이 일은 요한이 세례를 주던 요단 강 건너편 베다니에서 일어났어요."},{"n":29,"t":"이튿날 요한이 예수님이 자기에게 오시는 것을 보고 \\"보세요, 세상 죄를 지고 가시는 하나님의 어린 양이에요.\\""},{"n":30,"t":"\\"내가 \'내 뒤에 한 분이 오시는데 나보다 앞서신 분이다. 나보다 먼저 계셨다\' 한 분이 이분이에요.\\""},{"n":31,"t":"\\"나도 그분을 알지 못했지만 그분을 이스라엘에 나타내려고 내가 와서 물로 세례를 줘요\\" 했어요."},{"n":32,"t":"요한이 또 증언했어요. \\"성령이 비둘기처럼 하늘에서 내려와 그분 위에 머무시는 것을 보았어요.\\""},{"n":33,"t":"\\"나도 그분을 알지 못했지만 나를 보내 물로 세례를 주라 하신 분이 \'성령이 내려와 누구 위에 머무는 것을 보면 그가 성령으로 세례를 줄 사람이다\' 하셨어요.\\""},{"n":34,"t":"\\"내가 보았고 이분이 하나님의 아들이심을 증언해요.\\""},{"n":35,"t":"이튿날 요한이 자기 제자 두 사람과 함께 다시 서 있다가,"},{"n":36,"t":"지나가시는 예수님을 보고 \\"보세요, 하나님의 어린 양이에요\\" 했어요."},{"n":37,"t":"두 제자가 듣고 예수님을 따라갔어요."},{"n":38,"t":"예수님이 돌아서서 그들이 따라오는 것을 보고 \\"무엇을 구하니?\\" 하시니 \\"랍비여(번역하면 선생님이라는 뜻), 어디 머무세요?\\" 했어요."},{"n":39,"t":"\\"와서 봐라\\" 하시니 가서 그분이 머무시는 곳을 보고 그날 함께 머물렀어요. 그때가 제 십시쯤이에요."},{"n":40,"t":"요한의 말을 듣고 예수님을 따른 두 사람 중 하나는 시몬 베드로의 동생 안드레예요."},{"n":41,"t":"그가 먼저 자기 형 시몬을 찾아 \\"우리가 메시아를 만났어요\\" 했어요. 메시아는 번역하면 그리스도예요."},{"n":42,"t":"안드레가 시몬을 예수님께 데려가니, 예수님이 그를 보고 \\"너는 요한의 아들 시몬이다. 이제 게바라 불릴 거다\\" 하셨어요. 게바는 번역하면 베드로(돌)예요."},{"n":43,"t":"이튿날 예수님이 갈릴리로 가시려고 빌립을 만나 \\"나를 따라라\\" 하셨어요."},{"n":44,"t":"빌립은 안드레와 베드로와 같은 동네 벳새다 사람이에요."},{"n":45,"t":"빌립이 나다나엘을 찾아 \\"모세가 율법에 적었고 예언자들이 적은 분, 곧 요셉의 아들 나사렛 예수를 우리가 만났어요\\" 했어요."},{"n":46,"t":"나다나엘이 \\"나사렛에서 무슨 좋은 게 나올 수 있어요?\\" 하니 빌립이 \\"와서 봐\\" 했어요."},{"n":47,"t":"예수님이 나다나엘이 자기에게 오는 것을 보고 \\"보라, 거짓이 없는 참된 이스라엘 사람이다\\" 하셨어요."},{"n":48,"t":"나다나엘이 \\"어떻게 저를 아세요?\\" 하니 \\"빌립이 너를 부르기 전에 네가 무화과나무 아래 있을 때 너를 보았다\\" 하셨어요."},{"n":49,"t":"나다나엘이 \\"랍비여, 당신은 하나님의 아들이세요. 이스라엘의 왕이세요\\" 했어요."},{"n":50,"t":"예수님이 \\"내가 너를 무화과나무 아래에서 보았다 해서 믿니? 이보다 더 큰 일을 볼 거다\\" 하시고,"},{"n":51,"t":"\\"진정으로 너희에게 말한다. 하늘이 열리고 하나님의 천사들이 사람의 아들 위에 오르락내리락하는 것을 볼 거다\\" 하셨어요."}]}},{"chapter":2,"title":"가나의 혼인잔치와 성전 청결","verses":{"krv":[{"n":1,"t":"사흘 되던 날에 갈릴리 가나에 혼인이 있어 예수의 어머니도 거기 계시고"},{"n":2,"t":"예수와 그 제자들도 혼인에 청함을 받았더니"},{"n":3,"t":"포도주가 모자란지라 예수의 어머니가 예수에게 이르되 저희에게 포도주가 없다 하니"},{"n":4,"t":"예수께서 가라사대 여자여 나와 무슨 상관이 있나이까 내 때가 아직 이르지 못하였나이다"},{"n":5,"t":"그 어머니가 하인들에게 이르되 너희에게 무슨 말씀을 하시든지 그대로 하라 하니라"},{"n":6,"t":"거기 유대인의 결례를 따라 두 세 통 드는 돌항아리 여섯이 놓였는지라"},{"n":7,"t":"예수께서 저희에게 이르시되 항아리에 물을 채우라 하신즉 아구까지 채우니"},{"n":8,"t":"이제는 떠서 연회장에게 갖다 주라 하시매 갖다 주었더니"},{"n":9,"t":"연회장은 물로 된 포도주를 맛보고 어디서 났는지 알지 못하되 물 떠온 하인들은 알더라 연회장이 신랑을 불러"},{"n":10,"t":"말하되 사람마다 먼저 좋은 포도주를 내고 취한 후에 낮은 것을 내거늘 그대는 지금까지 좋은 포도주를 두었도다 하니라"},{"n":11,"t":"예수께서 이 처음 표적을 갈릴리 가나에서 행하여 그 영광을 나타내시매 제자들이 그를 믿으니라"},{"n":12,"t":"그 후에 예수께서 그 어머니와 형제들과 제자들과 함께 가버나움으로 내려가 거기 여러 날 계시지 아니하시니라"},{"n":13,"t":"유대인의 유월절이 가까운지라 예수께서 예루살렘으로 올라가셨더니"},{"n":14,"t":"성전 안에서 소와 양과 비둘기 파는 사람들과 돈 바꾸는 사람들의 앉은 것을 보시고"},{"n":15,"t":"노끈으로 채찍을 만드사 양이나 소를 다 성전에서 내어 쫓으시고 돈 바꾸는 사람들의 돈을 쏟으시며 상을 엎으시고"},{"n":16,"t":"비둘기 파는 사람들에게 이르시되 이것을 여기서 가져가라 내 아버지의 집으로 장사하는 집을 만들지 말라 하시니"},{"n":17,"t":"제자들이 성경 말씀에 주의 전을 사모하는 열심이 나를 삼키리라 한 것을 기억하더라"},{"n":18,"t":"이에 유대인들이 대답하여 예수께 말하기를 네가 이런 일을 행하니 무슨 표적을 우리에게 보이겠느뇨"},{"n":19,"t":"예수께서 대답하여 가라사대 너희가 이 성전을 헐라 내가 사흘 동안에 일으키리라"},{"n":20,"t":"유대인들이 가로되 이 성전은 사십 육년 동안에 지었거늘 네가 삼일 동안에 일으키겠느뇨 하더라"},{"n":21,"t":"그러나 예수는 성전된 자기 육체를 가리켜 말씀하신 것이라"},{"n":22,"t":"죽은 자 가운데서 살아나신 후에야 제자들이 이 말씀하신 것을 기억하고 성경과 및 예수의 하신 말씀을 믿었더라"},{"n":23,"t":"유월절에 예수께서 예루살렘에 계시니 많은 사람이 그 행하시는 표적을 보고 그 이름을 믿었으나"},{"n":24,"t":"예수는 그 몸을 저희에게 의탁지 아니하셨으니 이는 친히 모든 사람을 아심이요"},{"n":25,"t":"또 친히 사람의 속에 있는 것을 아시므로 사람에 대하여 아무의 증거도 받으실 필요가 없음이니라"}],"kids":[{"n":1,"t":"사흘째 되는 날 갈릴리 가나에 결혼식이 있었어요. 예수님의 어머니도 거기 있었고,"},{"n":2,"t":"예수님과 제자들도 결혼식에 초대받았어요."},{"n":3,"t":"포도주가 떨어지자 예수님의 어머니가 \\"포도주가 없네\\" 했어요."},{"n":4,"t":"예수님이 \\"여인이여, 그것이 저와 무슨 상관이에요? 제 때가 아직 이르지 않았어요\\" 하셨어요."},{"n":5,"t":"어머니가 종들에게 \\"이분이 하라는 대로 다 하세요\\" 했어요."},{"n":6,"t":"거기 유대 사람의 정결 예식에 쓰는 돌 항아리 여섯이 놓여 있었어요. 각각 두세 통이 들어가는 거예요."},{"n":7,"t":"예수님이 \\"항아리에 물을 채워라\\" 하시니 종들이 입까지 가득 채웠어요."},{"n":8,"t":"\\"이제 떠서 잔치 맡은 사람에게 갖다 주어라\\" 하시니 그렇게 했어요."},{"n":9,"t":"잔치 맡은 사람이 포도주가 된 물을 맛보고 어디서 났는지 알지 못했지만 물을 길어 온 종들은 알고 있었어요. 그가 신랑을 부르며,"},{"n":10,"t":"\\"누구나 먼저 좋은 포도주를 내고 손님이 취한 후에 못한 것을 내는데 그대는 좋은 포도주를 지금까지 두었구나\\" 했어요."},{"n":11,"t":"이것은 예수님이 행하신 첫 표적이며 갈릴리 가나에서 행하셨고 자기의 영광을 나타내셨어요. 제자들이 그분을 믿었어요."},{"n":12,"t":"이 후에 예수님이 어머니와 형제들과 제자들과 함께 가버나움에 내려가 거기 며칠 머무셨어요."},{"n":13,"t":"유대인의 유월절이 가까웠어요. 예수님이 예루살렘에 올라가셨어요."},{"n":14,"t":"성전 안에 소와 양과 비둘기 파는 사람들과 돈 바꾸는 사람들이 앉아 있는 것을 보셨어요."},{"n":15,"t":"노끈으로 채찍을 만들어 양과 소와 함께 그들을 다 성전에서 내쫓으셨어요. 돈 바꾸는 사람의 돈을 쏟으시고 상을 엎으셨어요."},{"n":16,"t":"비둘기 파는 사람들에게 \\"이것을 가져가라. 내 아버지의 집을 장사하는 집으로 만들지 마라\\" 하셨어요."},{"n":17,"t":"제자들이 \\"주님의 집을 위하는 열정이 나를 삼키리라\\"고 기록된 말씀이 생각났어요."},{"n":18,"t":"유대인들이 \\"이런 일을 하시니 무슨 표적을 우리에게 보여 주실래요?\\" 했어요."},{"n":19,"t":"예수님이 \\"이 성전을 헐어라. 내가 사흘 동안에 일으킬 거다\\" 하셨어요."},{"n":20,"t":"\\"이 성전은 짓는 데 사십육 년이나 걸렸는데 당신이 사흘 만에 일으킬 거예요?\\" 했어요."},{"n":21,"t":"그러나 예수님은 자기 몸의 성전을 말씀하신 거예요."},{"n":22,"t":"죽은 자 가운데서 살아나신 후에 제자들이 이 말씀을 기억하고 성경과 예수님이 하신 말씀을 믿었어요."},{"n":23,"t":"예수님이 유월절에 예루살렘에 계실 때 많은 사람이 그분이 행하시는 표적을 보고 그분의 이름을 믿었어요."},{"n":24,"t":"그러나 예수님은 자기를 그들에게 맡기지 않으셨어요. 그분이 사람을 다 아셨기 때문이에요."},{"n":25,"t":"누가 사람에 대해 증언할 필요가 없으셨어요. 사람의 속에 있는 것을 친히 아셨기 때문이에요."}]}},{"chapter":3,"title":"니고데모와 거듭남","verses":{"krv":[{"n":1,"t":"바리새인 중에 니고데모라 하는 사람이 있으니 유대인의 관원이라"},{"n":2,"t":"그가 밤에 예수께 와서 가로되 랍비여 우리가 당신은 하나님께로서 오신 선생인줄 아나이다 하나님이 함께 하시지 아니하시면 당신의 행하시는 이 표적을 아무라도 할 수 없음이니이다"},{"n":3,"t":"예수께서 대답하여 가라사대 진실로 진실로 네게 이르노니 사람이 거듭나지 아니하면 하나님 나라를 볼수 없느니라"},{"n":4,"t":"니고데모가 가로되 사람이 늙으면 어떻게 날 수 있삽나이까 두번째 모태에 들어갔다가 날 수 있삽나이까"},{"n":5,"t":"예수께서 대답하시되 진실로 진실로 네게 이르노니 사람이 물과 성령으로 나지 아니하면 하나님 나라에 들어갈 수 없느니라"},{"n":6,"t":"육으로 난 것은 육이요 성령으로 난 것은 영이니"},{"n":7,"t":"내가 네게 거듭나야 하겠다 하는 말을 기이히 여기지 말라"},{"n":8,"t":"바람이 임의로 불매 네가 그 소리를 들어도 어디서 오며 어디로 가는지 알지 못하나니 성령으로 난 사람은 다 이러하니라"},{"n":9,"t":"니고데모가 대답하여 가로되 어찌 이러한 일이 있을수 있나이까"},{"n":10,"t":"예수께서 가라사대 너는 이스라엘의 선생으로서 이러한 일을 알지 못하느냐"},{"n":11,"t":"진실로 진실로 네게 이르노니 우리 아는 것을 말하고 본 것을 증거하노라 그러나 너희가 우리 증거를 받지 아니하는도다"},{"n":12,"t":"내가 땅의 일을 말하여도 너희가 믿지 아니하거든 하물며 하늘 일을 말하면 어떻게 믿겠느냐"},{"n":13,"t":"하늘에서 내려온 자 곧 인자 외에는 하늘에 올라간 자가 없느니라"},{"n":14,"t":"모세가 광야에서 뱀을 든것 같이 인자도 들려야 하리니"},{"n":15,"t":"이는 저를 믿는 자마다 영생을 얻게 하려 하심이니라"},{"n":16,"t":"하나님이 세상을 이처럼 사랑하사 독생자를 주셨으니 이는 저를 믿는 자마다 멸망치 않고 영생을 얻게 하려 하심이니라"},{"n":17,"t":"하나님이 그 아들을 세상에 보내신 것은 세상을 심판하려 하심이 아니요 저로 말미암아 세상이 구원을 받게하려 하심이라"},{"n":18,"t":"저를 믿는 자는 심판을 받지 아니하는 것이요 믿지 아니하는 자는 하나님의 독생자의 이름을 믿지 아니하므로 벌써 심판을 받은 것이니라"},{"n":19,"t":"그 정죄는 이것이니 곧 빛이 세상에 왔으되 사람들이 자기 행위가 악하므로 빛보다 어두움을 더 사랑한 것이니라"},{"n":20,"t":"악을 행하는 자마다 빛을 미워하여 빛으로 오지 아니하나니 이는 그 행위가 드러날까 함이요"},{"n":21,"t":"진리를 쫓는 자는 빛으로 오나니 이는 그 행위가 하나님 안에서 행한 것임을 나타내려 함이라 하시니라"},{"n":22,"t":"이 후에 예수께서 제자들과 유대 땅으로 가서 거기 함께 유하시며 세례를 주시더라"},{"n":23,"t":"요한도 살렘 가까운 애논에서 세례를 주니 거기 물들이 많음이라 사람들이 와서 세례를 받더라"},{"n":24,"t":"요한이 아직 옥에 갇히지 아니하였더라"},{"n":25,"t":"이에 요한의 제자 중에서 한 유대인으로 더불어 결례에 대하여 변론이 되었더니"},{"n":26,"t":"저희가 요한에게 와서 가로되 랍비여 선생님과 함께 요단강 저편에 있던 자 곧 선생님이 증거하시던 자가 세례를 주매 사람이 다 그에게로 가더이다"},{"n":27,"t":"요한이 대답하여 가로되 만일 하늘에서 주신바 아니면 사람이 아무 것도 받을 수 없느니라"},{"n":28,"t":"나의 말한바 나는 그리스도가 아니요 그의 앞에 보내심을 받은 자라고 한 것을 증거할 자는 너희니라"},{"n":29,"t":"신부를 취하는 자는 신랑이나 서서 신랑의 음성을 듣는 친구가 크게 기뻐하나니 나는 이러한 기쁨이 충만하였노라"},{"n":30,"t":"그는 흥하여야 하겠고 나는 쇠하여야 하리라 하니라"},{"n":31,"t":"위로부터 오시는 이는 만물 위에 계시고 땅에서 난 이는 땅에 속하여 땅에 속한 것을 말하느니라 하늘로서 오시는 이는 만물 위에 계시나니"},{"n":32,"t":"그가 그 보고 들은 것을 증거하되 그의 증거를 받는 이가 없도다"},{"n":33,"t":"그의 증거를 받는 이는 하나님을 참되시다 하여 인쳤느니라"},{"n":34,"t":"하나님의 보내신 이는 하나님의 말씀을 하나니 이는 하나님이 성령을 한량없이 주심이니라"},{"n":35,"t":"아버지께서 아들을 사랑하사 만물을 다 그 손에 주셨으니"},{"n":36,"t":"아들을 믿는 자는 영생이 있고 아들을 순종치 아니하는 자는 영생을 보지 못하고 도리어 하나님의 진노가 그 위에 머물러 있느니라"}],"kids":[{"n":1,"t":"바리새인 중 니고데모라는 사람이 있어 유대인의 지도자였어요."},{"n":2,"t":"이 사람이 밤에 예수님께 와서 \\"랍비여, 우리가 당신이 하나님께로부터 오신 선생인 줄 알아요. 하나님이 함께하지 않으시면 당신이 행하시는 이 표적들을 아무도 할 수 없어요\\" 했어요."},{"n":3,"t":"예수님이 \\"진정으로 진정으로 너에게 말한다. 사람이 거듭나지 않으면 하나님 나라를 볼 수 없다\\" 하셨어요."},{"n":4,"t":"니고데모가 \\"사람이 늙어서 어떻게 태어날 수 있어요? 어머니 뱃속에 다시 들어가 태어날 수 있나요?\\" 했어요."},{"n":5,"t":"예수님이 \\"진정으로 진정으로 너에게 말한다. 사람이 물과 성령으로 태어나지 않으면 하나님 나라에 들어갈 수 없다.\\""},{"n":6,"t":"\\"육체로 태어난 것은 육체이고 영으로 태어난 것은 영이다.\\""},{"n":7,"t":"\\"너희가 거듭나야 한다는 내 말을 이상하게 여기지 마.\\""},{"n":8,"t":"\\"바람은 부고 싶은 대로 불고 너는 그 소리를 들어도 어디서 와서 어디로 가는지 알지 못해. 영으로 태어난 사람도 다 그와 같다\\" 하셨어요."},{"n":9,"t":"니고데모가 \\"어떻게 이런 일이 가능해요?\\" 했어요."},{"n":10,"t":"예수님이 \\"네가 이스라엘의 선생이면서 이것을 알지 못하니?\\""},{"n":11,"t":"\\"진정으로 진정으로 너에게 말한다. 우리는 아는 것을 말하고 본 것을 증언하는데 너희가 우리의 증언을 받지 않는다.\\""},{"n":12,"t":"\\"내가 땅의 일을 말해도 너희가 믿지 않으니 하늘의 일을 말하면 어떻게 믿겠니?\\""},{"n":13,"t":"\\"하늘에서 내려온 자, 곧 사람의 아들 외에는 하늘에 올라간 사람이 없다.\\""},{"n":14,"t":"\\"모세가 광야에서 뱀을 든 것 같이 사람의 아들도 들려야 한다.\\""},{"n":15,"t":"\\"이는 그를 믿는 사람마다 영생을 얻게 하려 함이다.\\""},{"n":16,"t":"\\"하나님이 세상을 이처럼 사랑하셔서 외아들을 주셨다. 이는 그를 믿는 사람마다 멸망하지 않고 영생을 얻게 하려 함이다.\\""},{"n":17,"t":"\\"하나님이 아들을 세상에 보내신 것은 세상을 심판하시려 함이 아니라 그로 인해 세상을 구원하려 함이다.\\""},{"n":18,"t":"\\"그를 믿는 사람은 심판받지 않지만 믿지 않는 사람은 이미 심판받았다. 하나님의 외아들의 이름을 믿지 않았기 때문이다.\\""},{"n":19,"t":"\\"심판은 이것이다. 빛이 세상에 왔지만 사람들이 자기 행위가 악하므로 빛보다 어둠을 더 사랑했다.\\""},{"n":20,"t":"\\"악을 행하는 사람마다 빛을 미워하여 자기 행위가 드러날까 봐 빛으로 오지 않는다.\\""},{"n":21,"t":"\\"그러나 진리를 행하는 사람은 빛으로 오니, 그의 행위가 하나님 안에서 이루어진 것임을 나타내려 함이다\\" 하셨어요."},{"n":22,"t":"이 후에 예수님과 제자들이 유대 땅으로 가셨어요. 거기서 함께 머물며 세례를 주셨어요."},{"n":23,"t":"요한도 살렘 가까운 애논에서 세례를 주었어요. 거기 물이 많기 때문이에요. 사람들이 와서 세례를 받았어요."},{"n":24,"t":"요한이 아직 옥에 갇히지 않았을 때예요."},{"n":25,"t":"요한의 제자들과 한 유대인 사이에 정결에 대해 다툼이 일어났어요."},{"n":26,"t":"그들이 요한에게 와서 \\"랍비여, 요단 강 건너편에서 당신과 함께 있던 분, 당신이 증언한 분이 세례를 주는데 모두가 그분에게 가요\\" 했어요."},{"n":27,"t":"요한이 \\"하늘에서 주어지지 않으면 사람이 아무것도 받을 수 없어요.\\""},{"n":28,"t":"\\"내가 \'나는 그리스도가 아니다. 그분 앞에 보냄받은 사람이다\' 했던 말을 너희가 직접 증언하잖아요.\\""},{"n":29,"t":"\\"신부를 차지하는 사람이 신랑이에요. 신랑의 친구는 서서 신랑의 음성을 듣고 매우 기뻐해요. 내 기쁨도 이렇게 가득해요.\\""},{"n":30,"t":"\\"그분은 흥해야 하고 나는 쇠해야 해요.\\""},{"n":31,"t":"\\"위에서 오시는 분은 모든 사람 위에 계세요. 땅에서 난 사람은 땅에 속해 땅의 일을 말해요. 하늘에서 오시는 분은 모든 것 위에 계세요.\\""},{"n":32,"t":"\\"그분이 보고 들은 것을 증언하지만 그분의 증언을 받는 사람이 없어요.\\""},{"n":33,"t":"\\"그분의 증언을 받는 사람은 하나님이 참되심을 인친 거예요.\\""},{"n":34,"t":"\\"하나님이 보내신 분이 하나님의 말씀을 하세요. 하나님이 성령을 한없이 주시기 때문이에요.\\""},{"n":35,"t":"\\"아버지가 아들을 사랑하셔서 모든 것을 그의 손에 주셨어요.\\""},{"n":36,"t":"\\"아들을 믿는 사람은 영생이 있고 아들에게 순종하지 않는 사람은 생명을 보지 못하고 도리어 하나님의 진노가 그 위에 머물러 있어요\\" 했어요."}]}},{"chapter":4,"title":"사마리아 여인과 생수","verses":{"krv":[{"n":1,"t":"예수의 제자를 삼고 세례를 주는 것이 요한보다 많다 하는 말을 바리새인들이 들은 줄을 주께서 아신지라"},{"n":2,"t":"(예수께서 친히 세례를 주신 것이 아니요 제자들이 준 것이라)"},{"n":3,"t":"유대를 떠나사 다시 갈릴리로 가실새"},{"n":4,"t":"사마리아로 통행하여야 하겠는지라"},{"n":5,"t":"사마리아에 있는 수가라 하는 동네에 이르시니 야곱이 그 아들 요셉에게 준 땅이 가깝고"},{"n":6,"t":"거기 또 야곱의 우물이 있더라 예수께서 행로에 곤하여 우물 곁에 그대로 앉으시니 때가 제 육시쯤 되었더라"},{"n":7,"t":"사마리아 여자 하나가 물을 길러 왔으매 예수께서 물을 좀 달라 하시니"},{"n":8,"t":"이는 제자들이 먹을 것을 사러 동네에 들어갔음이러라"},{"n":9,"t":"사마리아 여자가 가로되 당신은 유대인으로서 어찌하여 사마리아 여자 나에게 물을 달라 하나이까 하니 이는 유대인이 사마리아인과 상종치 아니함이러라"},{"n":10,"t":"예수께서 대답하여 가라사대 네가 만일 하나님의 선물과 또 네게 물좀 달라 하는 이가 누구인줄 알았더면 네가 그에게 구하였을 것이요 그가 생수를 네게 주었으리라"},{"n":11,"t":"여자가 가로되 주여 물 길을 그릇도 없고 이 우물은 깊은데 어디서 이 생수를 얻겠삽나이까"},{"n":12,"t":"우리 조상 야곱이 이 우물을 우리에게 주었고 또 여기서 자기와 자기 아들들과 짐승이 다 먹었으니 당신이 야곱보다 더 크니이까"},{"n":13,"t":"예수께서 대답하여 가라사대 이 물을 먹는 자마다 다시 목마르려니와"},{"n":14,"t":"내가 주는 물을 먹는 자는 영원히 목마르지 아니하리니 나의 주는 물은 그 속에서 영생하도록 솟아나는 샘물이 되리라"},{"n":15,"t":"여자가 가로되 주여 이런 물을 내게 주사 목마르지도 않고 또 여기 물 길러 오지도 않게 하옵소서"},{"n":16,"t":"가라사대 가서 네 남편을 불러 오라"},{"n":17,"t":"여자가 대답하여 가로되 나는 남편이 없나이다 예수께서 가라사대 네가 남편이 없다 하는 말이 옳도다"},{"n":18,"t":"네가 남편 다섯이 있었으나 지금 있는 자는 네 남편이 아니니 네 말이 참되도다"},{"n":19,"t":"여자가 가로되 주여 내가 보니 선지자로소이다"},{"n":20,"t":"우리 조상들은 이 산에서 예배하였는데 당신들의 말은 예배할 곳이 예루살렘에 있다 하더이다"},{"n":21,"t":"예수께서 가라사대 여자여 내 말을 믿으라 이 산에서도 말고 예루살렘에서도 말고 너희가 아버지께 예배할 때가 이르리라"},{"n":22,"t":"너희는 알지 못하는 것을 예배하고 우리는 아는 것을 예배하노니 이는 구원이 유대인에게서 남이니라"},{"n":23,"t":"아버지께 참으로 예배하는 자들은 신령과 진정으로 예배할 때가 오나니 곧 이 때라 아버지께서는 이렇게 자기에게 예배하는 자들을 찾으시느니라"},{"n":24,"t":"하나님은 영이시니 예배하는 자가 신령과 진정으로 예배할지니라"},{"n":25,"t":"여자가 가로되 메시야 곧 그리스도라 하는 이가 오실 줄을 내가 아노니 그가 오시면 모든 것을 우리에게 고하시리이다"},{"n":26,"t":"예수께서 이르시되 네게 말하는 내가 그로라 하시니라"},{"n":27,"t":"이 때에 제자들이 돌아와서 예수께서 여자와 말씀하시는 것을 이상히 여겼으나 무엇을 구하시나이까 어찌하여 저와 말씀하시니이까 묻는 이가 없더라"},{"n":28,"t":"여자가 물동이를 버려두고 동네에 들어가서 사람들에게 이르되"},{"n":29,"t":"나의 행한 모든 일을 내게 말한 사람을 와 보라 이는 그리스도가 아니냐 하니"},{"n":30,"t":"저희가 동네에서 나와 예수께로 오더라"},{"n":31,"t":"그 사이에 제자들이 청하여 가로되 랍비여 잡수소서"},{"n":32,"t":"가라사대 내게는 너희가 알지 못하는 먹을 양식이 있느니라"},{"n":33,"t":"제자들이 서로 말하되 누가 잡수실 것을 갖다 드렸는가 한대"},{"n":34,"t":"예수께서 이르시되 나의 양식은 나를 보내신 이의 뜻을 행하며 그의 일을 온전히 이루는 이것이니라"},{"n":35,"t":"너희가 넉달이 지나야 추수할 때가 이르겠다 하지 아니하느냐 내가 너희에게 이르노니 눈을 들어 밭을 보라 희어져 추수하게 되었도다"},{"n":36,"t":"거두는 자가 이미 삯도 받고 영생에 이르는 열매를 모으나니 이는 뿌리는 자와 거두는 자가 함께 즐거워하게 하려 함이니라"},{"n":37,"t":"그런즉 한 사람이 심고 다른 사람이 거둔다 하는 말이 옳도다"},{"n":38,"t":"내가 너희로 노력지 아니한 것을 거두러 보내었노니 다른 사람들은 노력하였고 너희는 그들의 노력한 것에 참예하였느니라"},{"n":39,"t":"여자의 말이 그가 나의 행한 모든 것을 내게 말하였다 증거하므로 그 동리 중에 많은 사마리아인이 예수를 믿는지라"},{"n":40,"t":"사마리아인들이 예수께 와서 자기들과 함께 유하기를 청하니 거기서 이틀을 유하시매"},{"n":41,"t":"예수의 말씀을 인하여 믿는 자가 더욱 많아"},{"n":42,"t":"그 여자에게 말하되 이제 우리가 믿는 것은 네 말을 인함이 아니니 이는 우리가 친히 듣고 그가 참으로 세상의 구주신줄 앎이니라 하였더라"},{"n":43,"t":"이틀이 지나매 예수께서 거기를 떠나 갈릴리로 가시며"},{"n":44,"t":"친히 증거하시기를 선지자가 고향에서는 높임을 받지 못한다 하시고"},{"n":45,"t":"갈릴리에 이르시매 갈릴리인들이 그를 영접하니 이는 자기들도 명절에 갔다가 예수께서 명절 중 예루살렘에서 하신 모든 일을 보았음이더라"},{"n":46,"t":"예수께서 다시 갈릴리 가나에 이르시니 전에 물로 포도주를 만드신 곳이라 왕의 신하가 있어 그 아들이 가버나움에서 병들었더니"},{"n":47,"t":"그가 예수께서 유대로부터 갈릴리에 오심을 듣고 가서 청하되 내려오셔서 내 아들의 병을 고쳐주소서 하니 저가 거의 죽게 되었음이라"},{"n":48,"t":"예수께서 가라사대 너희는 표적과 기사를 보지 못하면 도무지 믿지 아니하리라"},{"n":49,"t":"신하가 가로되 주여 내 아이가 죽기 전에 내려오소서"},{"n":50,"t":"예수께서 가라사대 가라 네 아들이 살았다 하신대 그 사람이 예수의 하신 말씀을 믿고 가더니"},{"n":51,"t":"내려가는 길에서 그 종들이 오다가 만나서 아이가 살았다 하거늘"},{"n":52,"t":"그 낫기 시작한 때를 물은즉 어제 제 칠시에 열기가 떨어졌나이다 하는지라"},{"n":53,"t":"아비가 예수께서 네 아들이 살았다 말씀하신 그 때인줄 알고 자기와 그 온 집이 다 믿으니라"},{"n":54,"t":"이것은 예수께서 유대에서 갈릴리로 오신 후 행하신 두 번째 표적이니라"}],"kids":[{"n":1,"t":"예수님이 요한보다 더 많은 제자를 삼고 세례를 준다는 말을 바리새인들이 들은 줄을 주께서 아시고,"},{"n":2,"t":"(실제로 예수님이 세례를 주신 게 아니라 제자들이 주셨어요)"},{"n":3,"t":"유대를 떠나 다시 갈릴리로 가셨어요."},{"n":4,"t":"사마리아를 지나가야 했어요."},{"n":5,"t":"그래서 사마리아의 한 동네 수가에 가셨는데 야곱이 자기 아들 요셉에게 준 땅에 가까웠어요."},{"n":6,"t":"거기에 야곱의 우물이 있었어요. 예수님이 여행에 지쳐 우물 옆에 앉으셨어요. 그때 제 육시쯤이었어요."},{"n":7,"t":"사마리아의 한 여자가 물을 길러 왔어요. 예수님이 \\"내게 마실 물을 좀 줘\\" 하셨어요."},{"n":8,"t":"제자들은 음식을 사러 동네에 들어가 있었어요."},{"n":9,"t":"사마리아 여자가 \\"당신은 유대인이면서 어떻게 사마리아 여자인 저에게 마실 것을 청하세요?\\" 했어요. 유대인은 사마리아인과 상관하지 않았거든요."},{"n":10,"t":"예수님이 \\"네가 하나님의 선물과 너에게 \'마실 것을 달라\'고 하는 사람이 누구인지 알았더라면 네가 그에게 청했을 거고 그가 생수를 주었을 거다\\" 하셨어요."},{"n":11,"t":"여자가 \\"선생님, 두레박도 없고 우물도 깊은데 그 생수를 어디서 얻으세요?\\""},{"n":12,"t":"\\"이 우물을 우리에게 주고 자기와 자녀와 짐승까지 다 여기서 마신 우리 조상 야곱보다 당신이 더 크세요?\\" 했어요."},{"n":13,"t":"예수님이 \\"이 물을 마시는 사람마다 다시 목마르겠지만,\\""},{"n":14,"t":"\\"내가 주는 물을 마시는 사람은 영원히 목마르지 않을 거다. 내가 주는 물은 그 속에서 영생에 이르는 샘물이 될 거다\\" 하셨어요."},{"n":15,"t":"\\"선생님, 이 물을 제게 주세요. 그러면 제가 목마르지도 않고 여기 물 길러 오지도 않을 거예요\\" 했어요."},{"n":16,"t":"\\"가서 네 남편을 불러 오너라\\" 하셨어요."},{"n":17,"t":"\\"저는 남편이 없어요\\" 하니 \\"네가 \'남편이 없다\' 한 말이 옳다.\\""},{"n":18,"t":"\\"너에게 다섯 남편이 있었고 지금 있는 남자도 네 남편이 아니다. 네가 옳게 말했다\\" 하셨어요."},{"n":19,"t":"\\"선생님, 당신이 예언자인 줄 알겠어요.\\""},{"n":20,"t":"\\"우리 조상은 이 산에서 예배했는데 당신네는 예배할 곳이 예루살렘에 있다고 하시잖아요\\" 했어요."},{"n":21,"t":"예수님이 \\"여인이여, 내 말을 믿어. 이 산에서도, 예루살렘에서도 아닌 곳에서 너희가 아버지께 예배할 때가 올 거다.\\""},{"n":22,"t":"\\"너희는 알지 못하는 것을 예배하지만 우리는 아는 것을 예배해. 구원이 유대인에게서 나기 때문이야.\\""},{"n":23,"t":"\\"그러나 참된 예배자가 영과 진리로 아버지께 예배할 때가 오고 지금이 그때다. 아버지께서 이러한 사람을 찾으셔.\\""},{"n":24,"t":"\\"하나님은 영이시니 예배하는 사람이 영과 진리로 예배해야 한다\\" 하셨어요."},{"n":25,"t":"여자가 \\"메시아, 곧 그리스도라 하는 분이 오시는 줄 알아요. 그분이 오시면 우리에게 다 알려 주실 거예요\\" 했어요."},{"n":26,"t":"예수님이 \\"너에게 말하는 내가 그다\\" 하셨어요."},{"n":27,"t":"그때 제자들이 돌아와 여자와 말씀하시는 것을 보고 이상하게 여겼지만 누구도 \\"무엇을 구하세요?\\" 또는 \\"왜 그녀와 말씀하세요?\\" 하지 못했어요."},{"n":28,"t":"여자가 물동이를 두고 동네에 들어가 사람들에게,"},{"n":29,"t":"\\"와서 보세요. 내가 행한 모든 일을 다 말한 분이 있어요. 이분이 그리스도일까요?\\" 했어요."},{"n":30,"t":"그들이 동네에서 나와 예수님께 갔어요."},{"n":31,"t":"그 사이에 제자들이 \\"랍비여, 잡수세요\\" 했어요."},{"n":32,"t":"예수님이 \\"내게 너희가 알지 못하는 먹을 양식이 있다\\" 하셨어요."},{"n":33,"t":"제자들이 서로 \\"누가 잡수실 것을 갖다 드렸을까?\\" 했어요."},{"n":34,"t":"예수님이 \\"내 양식은 나를 보내신 분의 뜻을 행하고 그분의 일을 이루는 거다.\\""},{"n":35,"t":"\\"너희가 \'넉 달이 지나야 추수다\' 하지 않니? 보라, 내가 너희에게 말한다. 눈을 들어 밭을 보아라. 이미 추수하게 되어 희어졌다.\\""},{"n":36,"t":"\\"거두는 사람이 일한 값을 받고 영생에 이르는 열매를 모으니, 뿌리는 사람과 거두는 사람이 함께 기뻐할 거다.\\""},{"n":37,"t":"\\"\'한 사람은 뿌리고 다른 사람은 거둔다\'는 말이 옳다.\\""},{"n":38,"t":"\\"내가 너희를 보내 너희가 수고하지 않은 것을 거두게 했다. 다른 사람이 수고했고 너희는 그 수고한 것에 들어간 거다\\" 하셨어요."},{"n":39,"t":"그 동네의 많은 사마리아 사람이 \\"그가 내가 행한 모든 일을 내게 말했어요\\" 하고 증언한 여자의 말 때문에 예수님을 믿었어요."},{"n":40,"t":"사마리아 사람들이 예수님께 와서 자기들과 함께 머물러 달라 청했고 거기서 이틀 머무셨어요."},{"n":41,"t":"그분의 말씀을 인해 더 많이 믿게 됐어요."},{"n":42,"t":"여자에게 \\"이제 당신의 말 때문에 믿는 것이 아니에요. 우리가 친히 듣고 이분이 참으로 세상의 구주이신 줄 알아요\\" 했어요."},{"n":43,"t":"이틀 후 예수님이 거기서 떠나 갈릴리로 가셨어요."},{"n":44,"t":"예수님이 친히 \\"예언자는 자기 고향에서 존경받지 못한다\\" 증언하셨어요."},{"n":45,"t":"갈릴리에 가시니 갈릴리 사람들이 그분을 영접했어요. 그들이 명절에 예루살렘에 가서 행하신 모든 일을 보았기 때문이에요."},{"n":46,"t":"예수님이 다시 갈릴리 가나에 가셨어요. 거기서 물로 포도주를 만드신 곳이에요. 거기 한 왕의 신하가 있었는데 그의 아들이 가버나움에서 병들어 있었어요."},{"n":47,"t":"이 사람이 예수님이 유대에서 갈릴리로 오신 줄 듣고 가서 자기 아들을 고쳐 달라 청했어요. 아들이 죽어 가고 있었거든요."},{"n":48,"t":"예수님이 \\"너희가 표적과 기사를 보지 않으면 결코 믿지 않을 거다\\" 하셨어요."},{"n":49,"t":"왕의 신하가 \\"주여, 제 아이가 죽기 전에 내려와 주세요\\" 했어요."},{"n":50,"t":"예수님이 \\"가라. 네 아들이 산다\\" 하시니 그가 예수님의 말씀을 믿고 갔어요."},{"n":51,"t":"내려가는 길에 그의 종들이 만나서 그의 아들이 살아 있다고 했어요."},{"n":52,"t":"그가 \\"몇 시에 좋아졌니?\\" 하니 \\"어제 오후 한 시에 열이 떨어졌어요\\" 했어요."},{"n":53,"t":"그 아버지가 예수님이 \'네 아들이 산다\' 하신 바로 그때인 줄을 알고 자기와 자기 온 집안이 믿었어요."},{"n":54,"t":"이것이 예수님이 유대에서 갈릴리로 오셔서 행하신 두 번째 표적이에요."}]}},{"chapter":5,"title":"베데스다 못과 안식일 논쟁","verses":{"krv":[{"n":1,"t":"그후에 유대인의 명절이 있어 예수께서 예루살렘에 올라가시니라"},{"n":2,"t":"예루살렘에 있는 양문 곁에 히브리 말로 베데스다라 하는 못이 있는데 거기 행각 다섯이 있고"},{"n":3,"t":"그 안에 많은 병자 소경 절뚝발이 혈기 마른 자들이 누워 (물의 동함을 기다리니"},{"n":4,"t":"이는 천사가 가끔 못에 내려와 물을 동하게 하는데 동한 후에 먼저 들어가는 자는 어떤 병에 걸렸든지 낫게 됨이러라)"},{"n":5,"t":"거기 삼십 팔년 된 병자가 있더라"},{"n":6,"t":"예수께서 그 누운 것을 보시고 병이 벌써 오랜줄 아시고 이르시되 네가 낫고자 하느냐"},{"n":7,"t":"병자가 대답하되 주여 물이 동할 때에 나를 못에 넣어 줄 사람이 없어 내가 가는 동안에 다른 사람이 먼저 내려가나이다"},{"n":8,"t":"예수께서 가라사대 일어나 네 자리를 들고 걸어가라 하시니"},{"n":9,"t":"그 사람이 곧 나아서 자리를 들고 걸어 가니라 이 날은 안식일이니"},{"n":10,"t":"유대인들이 병 나은 사람에게 이르되 안식일인데 네가 자리를 들고 가는 것이 옳지 아니하니라"},{"n":11,"t":"대답하되 나를 낫게 한 그가 자리를 들고 걸어가라 하더라 한대"},{"n":12,"t":"저희가 묻되 너더러 자리를 들고 걸어가라 한 사람이 누구냐 하되"},{"n":13,"t":"고침을 받은 사람이 그가 누구신지알지 못하니 이는 거기 사람이 많으므로 예수께서 이미 피하셨음이라"},{"n":14,"t":"그 후에 예수께서 성전에서 그 사람을 만나 이르시되 보라 네가 나았으니 더 심한 것이 생기지 않게 다시는 죄를 범치 말라 하시니"},{"n":15,"t":"그 사람이 유대인들에게 가서 자기를 고친 이는 예수라 하니라"},{"n":16,"t":"그러므로 안식일에 이러한 일을 행하신다 하여 유대인들이 예수를 핍박하게 된지라"},{"n":17,"t":"예수께서 저희에게 이르시되 내 아버지께서 이제까지 일하시니 나도 일한다 하시매"},{"n":18,"t":"유대인들이 이를 인하여 더욱 예수를 죽이고자 하니 이는 안식일만 범할 뿐 아니라 하나님을 자기의 친 아버지라 하여 자기를 하나님과 동등으로 삼으심이러라"},{"n":19,"t":"그러므로 예수께서 저희에게 이르시되 내가 진실로 진실로 너희에게 이르노니 아들이 아버지의 하시는 일을 보지 않고는 아무것도 스스로 할 수 없나니 아버지께서 행하시는 그것을 아들도 그와 같이 행하느니라"},{"n":20,"t":"아버지께서 아들을 사랑하사 자기의 행하시는 것을 다 아들에게 보이시고 또 그보다 더 큰 일을 보이사 너희로 기이히 여기게 하시리라"},{"n":21,"t":"아버지께서 죽은 자들을 일으켜 살리심 같이 아들도 자기의 원하는 자들을 살리느니라"},{"n":22,"t":"아버지께서 아무도 심판하지 아니하시고 심판을 다 아들에게 맡기셨으니"},{"n":23,"t":"이는 모든 사람으로 아버지를 공경하는 것 같이 아들을 공경하게 하려 하심이라 아들을 공경치 아니하는 자는 그를 보내신 아버지를 공경치 아니하느니라"},{"n":24,"t":"내가 진실로 진실로 너희에게 이르노니 내 말을 듣고 또 나 보내신 이를 믿는 자는 영생을 얻었고 심판에 이르지 아니하나니 사망에서 생명으로 옮겼느니라"},{"n":25,"t":"진실로 진실로 너희에게 이르노니 죽은 자들이 하나님의 아들의 음성을 들을 때가 오나니 곧 이 때라 듣는 자는 살아나리라"},{"n":26,"t":"아버지께서 자기 속에 생명이 있음 같이 아들에게도 생명을 주어 그 속에 있게 하셨고"},{"n":27,"t":"또 인자됨을 인하여 심판하는 권세를 주셨느니라"},{"n":28,"t":"이를 기이히 여기지 말라 무덤 속에 있는 자가 다 그의 음성을 들을 때가 오나니"},{"n":29,"t":"선한 일을 행한 자는 생명의 부활로 악한 일을 행한 자는 심판의 부활로 나오리라"},{"n":30,"t":"내가 아무 것도 스스로 할 수 없노라 듣는대로 심판하노니 나는 나의 원대로 하려하지 않고 나를 보내신 이의 원대로 하려는고로 내 심판은 의로우니라"},{"n":31,"t":"내가 만일 나를 위하여 증거하면 내 증거는 참되지 아니하되"},{"n":32,"t":"나를 위하여 증거하시는 이가 따로 있으니 나를 위하여 증거하시는 그 증거가 참인줄 아노라"},{"n":33,"t":"너희가 요한에게 사람을 보내매 요한이 진리에 대하여 증거하였느니라"},{"n":34,"t":"그러나 나는 사람에게서 증거를 취하지 아니하노라 다만 이 말을 하는 것은 너희로 구원을 얻게 하려 함이니라"},{"n":35,"t":"요한은 켜서 비취는 등불이라 너희가 일시 그 빛에 즐거이 있기를 원하였거니와"},{"n":36,"t":"내게는 요한의 증거보다 더 큰 증거가 있으니 아버지께서 내게 주사 이루게 하시는 역사 곧 나의 하는 그 역사가 아버지께서 나를 보내신 것을 나를 위하여 증거하는 것이요"},{"n":37,"t":"또한 나를 보내신 아버지께서 친히 나를 위하여 증거하셨느니라 너희는 아무 때에도 그 음성을 듣지 못하였고 그 형용을 보지 못하였으며"},{"n":38,"t":"그 말씀이 너희 속에 거하지 아니하니 이는 그의 보내신 자를 믿지 아니함이니라"},{"n":39,"t":"너희가 성경에서 영생을 얻는줄 생각하고 성경을 상고하거니와 이 성경이 곧 내게 대하여 증거하는 것이로다"},{"n":40,"t":"그러나 너희가 영생을 얻기 위하여 내게 오기를 원하지 아니하는도다"},{"n":41,"t":"나는 사람에게 영광을 취하지 아니하노라"},{"n":42,"t":"다만 하나님을 사랑하는 것이 너희 속에 없음을 알았노라"},{"n":43,"t":"나는 내 아버지의 이름으로 왔으매 너희가 영접지 아니하나 만일 다른 사람이 자기 이름으로 오면 영접하리라"},{"n":44,"t":"너희가 서로 영광을 취하고 유일하신 하나님께로부터 오는 영광은 구하지 아니하니 어찌 나를 믿을 수 있느냐"},{"n":45,"t":"내가 너희를 아버지께 고소할까 생각지 말라 너희를 고소하는 이가 있으니 곧 너희의 바라는 자 모세니라"},{"n":46,"t":"모세를 믿었더면 또 나를 믿었으리니 이는 그가 내게 대하여 기록하였음이라"},{"n":47,"t":"그러나 그의 글도 믿지 아니하거든 어찌 내 말을 믿겠느냐 하시니라"}],"kids":[{"n":1,"t":"이 후에 유대인의 명절이 있어 예수님이 예루살렘에 올라가셨어요."},{"n":2,"t":"예루살렘에 양 문 곁에 베데스다라는 못이 있어 다섯 행각이 있었어요."},{"n":3,"t":"그 행각 안에 많은 병자, 맹인, 절름발이, 마비된 사람들이 누워 있었어요."},{"n":4,"t":"(어떤 사본에는: 때때로 천사가 못에 내려와 물을 움직였고 물이 움직인 후 먼저 들어가는 사람이 무슨 병이든 낫게 된다는 말이 있어요.)"},{"n":5,"t":"거기에 서른여덟 해 동안 병든 사람이 있었어요."},{"n":6,"t":"예수님이 그가 누워 있는 것을 보시고 오래된 줄을 아시고 \\"네가 낫고 싶니?\\" 하셨어요."},{"n":7,"t":"병자가 \\"주여, 물이 움직일 때 못에 넣어 줄 사람이 없어요. 제가 가는 동안 다른 사람이 먼저 내려가요\\" 했어요."},{"n":8,"t":"예수님이 \\"일어나 네 침대를 들고 걸어라\\" 하셨어요."},{"n":9,"t":"그 사람이 곧 나아 침대를 들고 걸었어요. 그날은 안식일이었어요."},{"n":10,"t":"유대인들이 나은 사람에게 \\"안식일이라 침대를 드는 게 합법이 아니다\\" 했어요."},{"n":11,"t":"그가 \\"저를 낫게 하신 분이 \'침대를 들고 걸어라\' 하셨어요\\" 했어요."},{"n":12,"t":"그들이 \\"네게 \'들고 걸으라\' 한 사람이 누구냐?\\" 했어요."},{"n":13,"t":"그러나 나은 사람이 누구인지 알지 못했어요. 거기 무리가 있어 예수님이 피하셨거든요."},{"n":14,"t":"후에 예수님이 성전에서 그를 만나 \\"보라, 네가 나았으니 다시 죄짓지 마. 더 나쁜 일이 너에게 일어날까 두렵다\\" 하셨어요."},{"n":15,"t":"그 사람이 가서 유대인들에게 자기를 낫게 하신 분이 예수라고 알렸어요."},{"n":16,"t":"그래서 유대인들이 예수님을 박해했어요. 안식일에 이런 일을 하셨기 때문이에요."},{"n":17,"t":"예수님이 그들에게 \\"내 아버지께서 지금까지 일하시니 나도 일한다\\" 하셨어요."},{"n":18,"t":"이로 인해 유대인들이 그분을 더 죽이려 했어요. 안식일을 어기실 뿐 아니라 하나님을 자기 아버지라 하여 자기를 하나님과 같다고 하셨기 때문이에요."},{"n":19,"t":"예수님이 \\"진정으로 진정으로 너희에게 말한다. 아들이 스스로는 아무것도 할 수 없고 오직 아버지께서 행하시는 것을 보고 그대로 한다. 아버지께서 하시는 일은 아들도 그렇게 한다.\\""},{"n":20,"t":"\\"아버지께서 아들을 사랑하셔서 자기가 하시는 모든 일을 보여 주시고 또 이보다 더 큰 일을 보여 주실 거다. 너희가 놀라게 될 거다.\\""},{"n":21,"t":"\\"아버지께서 죽은 자들을 일으켜 살리시는 것 같이 아들도 자기가 원하는 사람을 살린다.\\""},{"n":22,"t":"\\"아버지께서는 누구도 심판하지 않으시고 모든 심판을 아들에게 맡기셨다.\\""},{"n":23,"t":"\\"이는 모든 사람이 아버지를 공경하는 것 같이 아들도 공경하게 하시려는 거다. 아들을 공경하지 않는 사람은 그를 보내신 아버지도 공경하지 않는 거다.\\""},{"n":24,"t":"\\"진정으로 진정으로 너희에게 말한다. 내 말을 듣고 나를 보내신 분을 믿는 사람은 영생을 가지고 있고 심판에 이르지 않고 사망에서 생명으로 옮겨졌다.\\""},{"n":25,"t":"\\"진정으로 진정으로 너희에게 말한다. 죽은 사람들이 하나님의 아들의 음성을 들을 때가 오고 지금이 그때다. 듣는 사람은 살 거다.\\""},{"n":26,"t":"\\"아버지께서 자기 안에 생명이 있는 것 같이 아들에게도 자기 안에 생명이 있게 하셨다.\\""},{"n":27,"t":"\\"또 인자됨으로 인하여 심판하는 권세를 그에게 주셨다.\\""},{"n":28,"t":"\\"이것을 이상히 여기지 마. 무덤 속에 있는 모든 사람이 그의 음성을 들을 때가 온다.\\""},{"n":29,"t":"\\"선한 일을 행한 사람은 생명의 부활로, 악한 일을 행한 사람은 심판의 부활로 나올 거다.\\""},{"n":30,"t":"\\"나는 스스로 아무것도 할 수 없다. 듣는 대로 심판하니 내 심판이 의롭다. 나는 내 뜻이 아니라 나를 보내신 분의 뜻을 구하기 때문이다.\\""},{"n":31,"t":"\\"내가 나를 위해 증언하면 내 증언이 참되지 않다.\\""},{"n":32,"t":"\\"나를 위해 증언하는 다른 분이 있고 그분이 나를 위해 증언하는 것이 참된 줄을 안다.\\""},{"n":33,"t":"\\"너희가 요한에게 사람을 보냈고 그가 진리를 증언했다.\\""},{"n":34,"t":"\\"내가 사람에게서 증언을 받지 않지만 이것을 말하는 것은 너희를 구원하려는 것이다.\\""},{"n":35,"t":"\\"요한은 켜서 비치는 등불이었고 너희가 한때 그의 빛 안에서 즐거워했다.\\""},{"n":36,"t":"\\"내게는 요한의 증언보다 더 큰 증언이 있다. 아버지께서 내게 행하라 주신 일, 곧 내가 행하고 있는 일이 아버지께서 나를 보내신 것을 증언한다.\\""},{"n":37,"t":"\\"또 나를 보내신 아버지께서도 친히 나를 위해 증언하셨다. 너희가 그분의 음성을 들은 적이 없고 그분의 모습을 본 적이 없다.\\""},{"n":38,"t":"\\"그분의 말씀이 너희 속에 머물러 있지 않다. 그분이 보내신 사람을 너희가 믿지 않기 때문이다.\\""},{"n":39,"t":"\\"너희가 성경에서 영생을 얻을 것 같아 그것을 연구하지만 성경이 내게 대해 증언한다.\\""},{"n":40,"t":"\\"그런데도 너희가 생명을 얻으려고 내게 오기를 원치 않는다.\\""},{"n":41,"t":"\\"나는 사람에게서 영광을 받지 않는다.\\""},{"n":42,"t":"\\"너희 속에 하나님을 사랑함이 없는 줄 안다.\\""},{"n":43,"t":"\\"내가 내 아버지의 이름으로 왔는데 너희가 나를 영접하지 않는다. 다른 사람이 자기 이름으로 오면 그 사람은 영접할 거다.\\""},{"n":44,"t":"\\"너희가 서로 영광을 받고 유일하신 하나님께로부터의 영광은 구하지 않으니 어떻게 믿을 수 있겠니?\\""},{"n":45,"t":"\\"내가 너희를 아버지께 고소할 거라 생각하지 마. 너희를 고소하는 사람은 너희가 바라는 모세다.\\""},{"n":46,"t":"\\"너희가 모세를 믿었으면 나도 믿었을 거다. 모세가 내게 대해 적었기 때문이다.\\""},{"n":47,"t":"\\"그가 쓴 글을 너희가 믿지 않으면 내 말을 어떻게 믿겠니?\\" 하셨어요."}]}},{"chapter":6,"title":"오천 명을 먹이심과 생명의 떡","verses":{"krv":[{"n":1,"t":"그 후에 예수께서 갈릴리 바다 곧 디베랴 바다 건너편으로 가시매"},{"n":2,"t":"큰 무리가 따르니 이는 병인들에게 행하시는 표적을 봄이러라"},{"n":3,"t":"예수께서 산에 오르사 제자들과 함께 거기 앉으시니"},{"n":4,"t":"마침 유대인의 명절인 유월절이 가까운지라"},{"n":5,"t":"예수께서 눈을 들어 큰 무리가 자기에게로 오는 것을 보시고 빌립에게 이르시되 우리가 어디서 떡을 사서 이 사람들로 먹게 하겠느냐 하시니"},{"n":6,"t":"이렇게 말씀하심은 친히 어떻게 하실 것을 아시고 빌립을 시험코자 하심이라"},{"n":7,"t":"빌립이 대답하되 각 사람으로 조금씩 받게 할지라도 이백 데나리온의 떡이 부족하리이다"},{"n":8,"t":"제자 중 하나 곧 시몬 베드로의 형제 안드레가 예수께 여짜 오되"},{"n":9,"t":"여기 한 아이가 있어 보리떡 다섯개와 물고기 두 마리를 가졌나이다 그러나 그것이 이 많은 사람에게 얼마나 되겠삽나이까"},{"n":10,"t":"예수께서 가라사대 이 사람들로 앉게 하라 하신대 그 곳에 잔디가 많은지라 사람들이 앉으니 수효가 오천쯤 되더라"},{"n":11,"t":"예수께서 떡을 가져 축사하신 후에 앉은 자들에게 나눠 주시고 고기도 그렇게 저희의 원대로 주시다"},{"n":12,"t":"저희가 배부른 후에 예수께서 제자들에게 이르시되 남은 조각을 거두고 버리는 것이 없게 하라 하시므로"},{"n":13,"t":"이에 거두니 보리떡 다섯개로 먹고 남은 조각이 열 두 바구니에 찼더라"},{"n":14,"t":"그 사람들이 예수의 행하신 이 표적을 보고 말하되 이는 참으로 세상에 오실 그 선지자라 하더라"},{"n":15,"t":"그러므로 예수께서 저희가 와서 자기를 억지로 잡아 임금 삼으려는줄을 아시고 다시 혼자 산으로 떠나 가시니라"},{"n":16,"t":"저물매 제자들이 바다에 내려가서"},{"n":17,"t":"배를 타고 바다를 건너 가버나움으로 가는데 이미 어두웠고 예수는 아직 저희에게 오시지 아니하셨더니"},{"n":18,"t":"큰 바람이 불어 파도가 일어나더라"},{"n":19,"t":"제자들이 노를 저어 십여리쯤 가다가 예수께서 바다 위로 걸어 배에 가까이 오심을 보고 두려워하거늘"},{"n":20,"t":"가라사대 내니 두려워 말라 하신대"},{"n":21,"t":"이에 기뻐서 배로 영접하니 배는 곧 저희의 가려던 땅에 이르렀더라"},{"n":22,"t":"이튿날 바다 건너편에 섰는 무리가 배 한척 밖에 다른 배가 거기 없는 것과 또 어제 예수께서 제자들과 함께 그 배에 오르지 아니하시고 제자들만 가는 것을 보았더니"},{"n":23,"t":"(그러나 디베랴에서 배들이 주의 축사하신 후 여럿이 떡 먹던 그 곳에 가까이 왔더라)"},{"n":24,"t":"무리가 거기 예수도 없으시고 제자들도 없음을 보고 곧 배들을 타고 예수를 찾으러 가버나움으로 가서"},{"n":25,"t":"바다 건너편에서 만나 랍비여 어느 때에 여기 오셨나이까 하니"},{"n":26,"t":"예수께서 대답하여 가라사대 내가 진실로 진실로 너희에게 이르노니 너희가 나를 찾는 것은 표적을 본 까닭이 아니요 떡을 먹고 배부른 까닭이로다"},{"n":27,"t":"썩는 양식을 위하여 일하지 말고 영생하도록 있는 양식을 위하여 하라 이 양식은 인자가 너희에게 주리니 인자는 아버지 하나님의 인치신 자니라"},{"n":28,"t":"저희가 묻되 우리가 어떻게 하여야 하나님의 일을 하오리이까"},{"n":29,"t":"예수께서 대답하여 가라사대 하나님의 보내신 자를 믿는 것이 하나님의 일이니라 하시니"},{"n":30,"t":"저희가 묻되 그러면 우리로 보고 당신을 믿게 행하시는 표적이 무엇이니이까 하시는 일이 무엇이니이까"},{"n":31,"t":"기록된 바 하늘에서 저희에게 떡을 주어 먹게 하였다 함과 같이 우리 조상들은 광야에서 만나를 먹었나이다"},{"n":32,"t":"예수께서 이르시되 내가 진실로 진실로 너희에게 이르노니 하늘에서 내린 떡은 모세가 준 것이 아니라 오직 내 아버지가 하늘에서 내린 참 떡을 너희에게 주시나니"},{"n":33,"t":"하나님의 떡은 하늘에서 내려 세상에게 생명을 주는 것이니라"},{"n":34,"t":"저희가 가로되 주여 이 떡을 항상 우리에게 주소서"},{"n":35,"t":"예수께서 가라사대 내가 곧 생명의 떡이니 내게 오는 자는 결코 주리지 아니할 터이요 나를 믿는 자는 영원히 목마르지 아니하리라"},{"n":36,"t":"그러나 내가 너희더러 이르기를 너희는 나를 보고도 믿지 아니하는도다 하였느니라"},{"n":37,"t":"아버지께서 내게 주시는 자는 다 내게로 올 것이요 내게 오는 자는 내가 결코 내어 쫓지 아니하리라"},{"n":38,"t":"내가 하늘로서 내려온 것은 내뜻을 행하려 함이 아니요"},{"n":39,"t":"나를 보내신 이의 뜻을 행하려 함이니라 나를 보내신 이의 뜻은 내게 주신 자 중에 내가 하나도 잃어 버리지 아니하고 마지막 날에 다시 살리는 이것이니라"},{"n":40,"t":"내 아버지의 뜻은 아들을 보고 믿는 자마다 영생을 얻는 이것이니 마지막 날에 내가 이를 다시 살리리라 하시니라"},{"n":41,"t":"자기가 하늘로서 내려온 떡이라 하시므로 유대인들이 예수께 대하여 수군거려"},{"n":42,"t":"가로되 이는 요셉의 아들 예수가 아니냐 그 부모를 우리가 아는데 제가 지금 어찌하여 하늘로서 내려왔다 하느냐"},{"n":43,"t":"예수께서 대답하여 가라사대 너희는 서로 수군거리지 말라"},{"n":44,"t":"나를 보내신 아버지께서 이끌지 아니하면 아무라도 내게 올 수 없으니 오는 그를 내가 마지막 날에 다시 살리리라"},{"n":45,"t":"선지자의 글에 저희가 다 하나님의 가르치심을 받으리라 기록되었은즉 아버지께 듣고 배운 사람마다 내게로 오느니라"},{"n":46,"t":"이는 아버지를 본 자가 있다는것이 아니라 오직 하나님에게서 온 자만 아버지를 보았느니라"},{"n":47,"t":"진실로 진실로 너희에게 이르노니 믿는 자는 영생을 가졌나니"},{"n":48,"t":"내가 곧 생명의 떡이로라"},{"n":49,"t":"너희 조상들은 광야에서 만나를 먹었어도 죽었거니와"},{"n":50,"t":"이는 하늘로서 내려오는 떡이니 사람으로 하여금 먹고 죽지 아니하게 하는 것이니라"},{"n":51,"t":"나는 하늘로서 내려온 산 떡이니 사람이 이 떡을 먹으면 영생하리라 나의 줄 떡은 곧 세상의 생명을 위한 내 살이로라 하시니라"},{"n":52,"t":"이러므로 유대인들이 서로 다투어 가로되 이 사람이 어찌 능히 제 살을 우리에게 주어 먹게 하겠느냐"},{"n":53,"t":"예수께서 이르시되 내가 진실로 진실로 너희에게 이르노니 인자의 살을 먹지 아니하고 인자의 피를 마시지 아니하면 너희 속에 생명이 없느니라"},{"n":54,"t":"내 살을 먹고 내 피를 마시는 자는 영생을 가졌고 마지막 날에 내가 그를 다시 살리리니"},{"n":55,"t":"내 살은 참된 양식이요 내 피는 참된 음료로다"},{"n":56,"t":"내 살을 먹고 내 피를 마시는 자는 내 안에 거하고 나도 그 안에 거하나니"},{"n":57,"t":"살아계신 아버지께서 나를 보내시매 내가 아버지로 인하여 사는것 같이 나를 먹는 그 사람도 나로 인하여 살리라"},{"n":58,"t":"이것은 하늘로서 내려온 떡이니 조상들이 먹고도 죽은 그것과 같지 아니하여 이 떡을 먹는 자는 영원히 살리라"},{"n":59,"t":"이 말씀은 예수께서 가버나움 회당에서 가르치실 때에 하셨느니라"},{"n":60,"t":"제자 중 여럿이 듣고 말하되 이 말씀은 어렵도다 누가 들을 수 있느냐 한대"},{"n":61,"t":"예수께서 스스로 제자들이 이 말씀에 대하여 수근거리는 줄 아시고 가라사대 이 말이 너희에게 걸림이 되느냐"},{"n":62,"t":"그러면 너희가 인자의 이전 있던 곳으로 올라가는 것을 볼것 같으면 어찌 하려느냐"},{"n":63,"t":"살리는 것은 영이니 육은 무익하니라 내가 너희에게 이른 말이 영이요 생명이라"},{"n":64,"t":"그러나 너희 중에 믿지 아니하는 자들이 있느니라 하시니 이는 예수께서 믿지 아니하는 자들이 누구며 자기를 팔 자가 누군지 처음부터 아심이러라"},{"n":65,"t":"또 가라사대 이러하므로 전에 너희에게 말하기를 내 아버지께서 오게 하여 주지 아니하시면 누구든지 내게 올 수 없다 하였노라 하시니라"},{"n":66,"t":"이러므로 제자 중에 많이 물러가고 다시 그와 함께 다니지 아니하더라"},{"n":67,"t":"예수께서 열 두 제자에게 이르시되 너희도 가려느냐"},{"n":68,"t":"시몬 베드로가 대답하되 주여 영생의 말씀이 계시매 우리가 뉘게로 가오리이까"},{"n":69,"t":"우리가 주는 하나님의 거룩하신 자신줄 믿고 알았삽나이다"},{"n":70,"t":"예수께서 대답하시되 내가 너희 열 둘을 택하지 아니하였느냐 그러나 너희 중에 한 사람은 마귀니라 하시니"},{"n":71,"t":"이 말씀은 가룟 시몬의 아들 유다를 가리키심이라 저는 열 둘 중의 하나로 예수를 팔 자러라"}],"kids":[{"n":1,"t":"이 후에 예수님이 갈릴리 바다, 곧 디베랴 바다 건너편으로 가셨어요."},{"n":2,"t":"큰 무리가 그분이 병자에게 행하시는 표적을 보았기 때문에 따랐어요."},{"n":3,"t":"예수님이 산에 올라 거기서 제자들과 함께 앉으셨어요."},{"n":4,"t":"마침 유대인의 명절 유월절이 가까웠어요."},{"n":5,"t":"예수님이 눈을 들어 큰 무리가 자기에게 오는 것을 보시고 빌립에게 \\"우리가 어디서 빵을 사서 이 사람들을 먹일까?\\" 하셨어요."},{"n":6,"t":"이렇게 말씀하신 것은 그를 시험하려 함이고, 친히 무엇을 하실지 알고 계셨어요."},{"n":7,"t":"빌립이 \\"이백 데나리온어치 빵으로도 각자 조금씩 받기에 부족해요\\" 했어요."},{"n":8,"t":"제자 중 하나, 시몬 베드로의 동생 안드레가,"},{"n":9,"t":"\\"여기 한 아이가 있어 보리 빵 다섯 개와 물고기 두 마리를 가졌지만 이 많은 사람에게 무엇을 하겠어요?\\" 했어요."},{"n":10,"t":"예수님이 \\"사람들이 앉게 해라\\" 하셨어요. 그곳에 잔디가 많았는데 사람들이 앉았어요. 남자만 오천 명쯤이었어요."},{"n":11,"t":"예수님이 빵을 받아 감사하시고 앉은 사람들에게 나누어 주시고 물고기도 그렇게 하여 그들 원하는 대로 주셨어요."},{"n":12,"t":"배부른 후 제자들에게 \\"남은 조각을 거두어 잃지 않게 해라\\" 하셨어요."},{"n":13,"t":"거두니 보리 빵 다섯의 조각이 사람들이 먹고 남은 것이 열두 바구니에 찼어요."},{"n":14,"t":"사람들이 예수님이 행하신 표적을 보고 \\"이분이 진실로 세상에 오실 그 예언자다\\" 했어요."},{"n":15,"t":"예수님이 그들이 와서 자기를 억지로 잡아 왕 삼으려는 것을 아시고 다시 혼자 산으로 떠나가셨어요."},{"n":16,"t":"저녁이 되자 제자들이 바다로 내려가,"},{"n":17,"t":"배에 올라 가버나움으로 건너가려 했어요. 이미 어두워졌고 예수님은 아직 오지 않으셨어요."},{"n":18,"t":"큰 바람이 불어 바다가 거칠어졌어요."},{"n":19,"t":"제자들이 한 25-30리쯤 노 저어 갔을 때 예수님이 바다 위로 걸어 배에 가까이 오시는 것을 보고 두려워했어요."},{"n":20,"t":"예수님이 \\"나다, 두려워하지 마라\\" 하셨어요."},{"n":21,"t":"그들이 기뻐 그분을 영접하니 배가 곧 가려던 땅에 닿았어요."},{"n":22,"t":"이튿날 바다 건너편에 남아 있던 무리가 거기 한 배밖에 없었고 예수님이 제자들과 함께 그 배에 타지 않으셨고 제자들만 갔던 것을 보았어요."},{"n":23,"t":"디베랴에서 다른 배들이 와서 주께서 감사하시고 빵을 잡수신 곳에 가까이 댔어요."},{"n":24,"t":"무리가 예수님도 제자들도 거기에 없는 것을 보고 배에 올라 예수님을 찾아 가버나움으로 갔어요."},{"n":25,"t":"바다 건너편에서 그분을 만나 \\"랍비여, 언제 여기 오셨어요?\\" 했어요."},{"n":26,"t":"예수님이 \\"진정으로 진정으로 너희에게 말한다. 너희가 나를 찾는 것은 표적을 보았기 때문이 아니라 빵을 먹고 배부른 까닭이다.\\""},{"n":27,"t":"\\"썩을 양식을 위해 일하지 말고 영생에 이르는 양식을 위해 일해라. 이는 사람의 아들이 너희에게 줄 거다. 아버지 하나님이 그에게 인을 치셨기 때문이다\\" 하셨어요."},{"n":28,"t":"\\"우리가 어떻게 하면 하나님의 일을 할까요?\\" 했어요."},{"n":29,"t":"예수님이 \\"하나님이 보내신 분을 너희가 믿는 것이 하나님의 일이다\\" 하셨어요."},{"n":30,"t":"\\"그러면 무슨 표적을 행하셔서 우리가 보고 믿게 하시겠어요? 무슨 일을 하시겠어요?\\""},{"n":31,"t":"\\"우리 조상은 광야에서 만나를 먹었어요. \'그가 하늘로부터 빵을 주어 먹게 했다\'고 기록된 것 같이요\\" 했어요."},{"n":32,"t":"예수님이 \\"진정으로 진정으로 너희에게 말한다. 너희에게 하늘로부터 빵을 주신 분은 모세가 아니라 내 아버지께서 하늘로부터 너희에게 참된 빵을 주신다.\\""},{"n":33,"t":"\\"하나님의 빵은 하늘에서 내려와 세상에 생명을 주는 그분이다\\" 하셨어요."},{"n":34,"t":"\\"주여, 이 빵을 항상 우리에게 주세요\\" 했어요."},{"n":35,"t":"예수님이 \\"내가 곧 생명의 빵이다. 내게 오는 사람은 결코 굶주리지 않을 거고 나를 믿는 사람은 결코 목마르지 않을 거다.\\""},{"n":36,"t":"\\"그러나 내가 너희에게 말했듯이 너희가 나를 보고도 믿지 않는다.\\""},{"n":37,"t":"\\"아버지께서 내게 주시는 모든 사람은 내게 올 거다. 내게 오는 사람을 결코 쫓아내지 않는다.\\""},{"n":38,"t":"\\"내가 하늘에서 내려온 것은 내 뜻이 아니라 나를 보내신 분의 뜻을 행하려 함이다.\\""},{"n":39,"t":"\\"나를 보내신 분의 뜻은 그가 내게 주신 사람 중 하나도 잃어버리지 않고 마지막 날에 다시 살리는 거다.\\""},{"n":40,"t":"\\"내 아버지의 뜻은 아들을 보고 믿는 사람마다 영생을 얻는 거고, 내가 마지막 날에 그를 다시 살릴 거다\\" 하셨어요."},{"n":41,"t":"유대인들이 \\"내가 하늘에서 내려온 빵이다\\" 하신 말씀에 대해 수군거리며,"},{"n":42,"t":"\\"이 사람이 요셉의 아들 예수가 아닌가? 그 아버지와 어머니를 우리가 아는데, 어떻게 \'내가 하늘에서 내려왔다\' 하는가?\\" 했어요."},{"n":43,"t":"예수님이 \\"서로 수군거리지 마.\\""},{"n":44,"t":"\\"나를 보내신 아버지께서 이끌지 않으시면 누구도 내게 올 수 없다. 마지막 날에 내가 그를 다시 살릴 거다.\\""},{"n":45,"t":"\\"예언자들의 글에 \'그들이 다 하나님께 가르침을 받을 거다\'라고 기록되었다. 아버지께 듣고 배운 사람마다 내게 온다.\\""},{"n":46,"t":"\\"이는 누가 아버지를 보았다는 게 아니다. 오직 하나님께로부터 온 자만 아버지를 보았다.\\""},{"n":47,"t":"\\"진정으로 진정으로 너희에게 말한다. 믿는 사람은 영생을 가지고 있다.\\""},{"n":48,"t":"\\"내가 곧 생명의 빵이다.\\""},{"n":49,"t":"\\"너희 조상은 광야에서 만나를 먹었지만 죽었다.\\""},{"n":50,"t":"\\"이것은 하늘에서 내려오는 빵이다. 사람이 이것을 먹으면 죽지 않을 거다.\\""},{"n":51,"t":"\\"내가 하늘에서 내려온 살아 있는 빵이다. 이 빵을 먹으면 영원히 살 거다. 내가 줄 빵은 세상의 생명을 위한 내 살이다\\" 하셨어요."},{"n":52,"t":"유대인들이 서로 다투며 \\"이 사람이 어떻게 자기 살을 우리에게 먹으라고 줄 수 있어?\\" 했어요."},{"n":53,"t":"예수님이 \\"진정으로 진정으로 너희에게 말한다. 너희가 사람의 아들의 살을 먹지 않고 그의 피를 마시지 않으면 너희 속에 생명이 없다.\\""},{"n":54,"t":"\\"내 살을 먹고 내 피를 마시는 사람은 영생을 가지고 있다. 내가 마지막 날에 그를 다시 살릴 거다.\\""},{"n":55,"t":"\\"내 살은 참된 양식이고 내 피는 참된 음료다.\\""},{"n":56,"t":"\\"내 살을 먹고 내 피를 마시는 사람은 내 안에 거하고 나도 그 안에 거한다.\\""},{"n":57,"t":"\\"살아 계신 아버지께서 나를 보내셨고 내가 아버지로 인해 사는 것 같이 나를 먹는 사람도 나로 인해 살 거다.\\""},{"n":58,"t":"\\"이것이 하늘에서 내려온 빵이다. 너희 조상이 먹고도 죽은 것과 같지 않다. 이 빵을 먹는 사람은 영원히 살 거다\\" 하셨어요."},{"n":59,"t":"이 말씀은 예수님이 가버나움 회당에서 가르치실 때 하신 거예요."},{"n":60,"t":"제자 중 많은 사람이 듣고 \\"이 말이 어려워. 누가 들을 수 있어?\\" 했어요."},{"n":61,"t":"예수님이 제자들이 이에 대해 수군거리는 것을 아시고 \\"이 말이 너희에게 걸림이 되니?\\""},{"n":62,"t":"\\"사람의 아들이 이전에 있던 곳으로 올라가는 것을 본다면 어떻겠니?\\""},{"n":63,"t":"\\"살리는 것은 영이고 육은 무익하다. 내가 너희에게 한 말은 영이요 생명이다.\\""},{"n":64,"t":"\\"그러나 너희 중 어떤 사람은 믿지 않는다.\\" 예수님은 처음부터 누가 믿지 않는지, 누가 자기를 넘길지를 아셨어요."},{"n":65,"t":"또 \\"그러므로 내가 너희에게 \'아버지께서 허락하지 않으시면 누구도 내게 올 수 없다\' 했다\\" 하셨어요."},{"n":66,"t":"이로 인해 제자 중 많은 사람이 떠나가고 더 이상 그분과 함께 다니지 않았어요."},{"n":67,"t":"예수님이 열두 제자에게 \\"너희도 가려느냐?\\" 하셨어요."},{"n":68,"t":"시몬 베드로가 \\"주여, 우리가 누구에게로 가겠어요? 영생의 말씀이 주께 있어요.\\""},{"n":69,"t":"\\"우리가 주는 하나님의 거룩하신 분인 줄 믿고 알아요\\" 했어요."},{"n":70,"t":"예수님이 \\"내가 너희 열둘을 택하지 않았느냐? 그러나 너희 중 하나는 마귀다\\" 하셨어요."},{"n":71,"t":"이는 가룟 시몬의 아들 유다를 말씀하신 거예요. 그가 열둘 중 하나이면서 예수님을 넘길 사람이거든요."}]}},{"chapter":7,"title":"초막절과 예수님","verses":{"krv":[{"n":1,"t":"이 후에 예수께서 갈릴리에서 다니시고 유대에서 다니려 아니하심은 유대인들이 죽이려 함이러라"},{"n":2,"t":"유대인의 명절인 초막절이 가까운지라"},{"n":3,"t":"그 형제들이 예수께 이르되 당신의 행하는 일을 제자들도 보게 여기를 떠나 유대로 가소서"},{"n":4,"t":"스스로 나타나기를 구하면서 묻혀서 일하는 사람이 없나니 이 일을 행하려 하거든 자신을 세상에 나타내소서 하니"},{"n":5,"t":"이는 그 형제들이라도 예수를 믿지 아니함이러라"},{"n":6,"t":"예수께서 가라사대 내 때는 아직 이르지 아니 하였거니와 너희 때는 늘 준비되어 있느니라"},{"n":7,"t":"세상이 너희를 미워하지 못하되 나를 미워하나니 이는 내가 세상의 행사를 악하다 증거함이라"},{"n":8,"t":"너희는 명절에 올라가라 나는 내 때가 아직 차지 못하였으니 이 명절에 아직 올라가지 아니하노라"},{"n":9,"t":"이 말씀을 하시고 갈릴리에 머물러 계시니라"},{"n":10,"t":"그 형제들이 명절에 올라간후 자기도 올라가시되 나타내지 않고 비밀히 하시니라"},{"n":11,"t":"명절 중에 유대인들이 예수를 찾으면서 그가 어디 있느냐 하고"},{"n":12,"t":"예수께 대하여 무리 중에서 수군거림이 많아 혹은 좋은 사람이라 하며 혹은 아니라 무리를 미혹하게 한다 하나"},{"n":13,"t":"그러나 유대인들을 두려워하므로 드러나게 그를 말하는 자가 없더라"},{"n":14,"t":"이미 명절의 중간이 되어 예수께서 성전에 올라가사 가르치시니"},{"n":15,"t":"유대인들이 기이히 여겨 가로되 이 사람은 배우지 아니하였거늘 어떻게 글을 아느냐 하니"},{"n":16,"t":"예수께서 대답하여 가라사대 내 교훈은 내 것이 아니요 나를 보내신 이의 것이니라"},{"n":17,"t":"사람이 하나님의 뜻을 행하려 하면 이 교훈이 하나님께로서 왔는지 내가 스스로 말함인지 알리라"},{"n":18,"t":"스스로 말하는 자는 자기 영광만 구하되 보내신 이의 영광을 구하는 자는 참되니 그 속에 불의가 없느니라"},{"n":19,"t":"모세가 너희에게 율법을 주지 아니하였느냐 너희 중에 율법을 지키는 자가 없도다 너희가 어찌하여 나를 죽이려 하느냐"},{"n":20,"t":"무리가 대답하되 당신은 귀신이 들렸도다 누가 당신을 죽이려 하나이까"},{"n":21,"t":"예수께서 대답하여 가라사대 내가 한 가지 일을 행하매 너희가 다 이를 인하여 괴이히 여기는도다"},{"n":22,"t":"모세가 너희에게 할례를 주었으니 (그러나 할례는 모세에게서 난 것이 아니요 조상들에게서 난 것이라)그러므로 너희가 안식일에도 사람에게 할례를 주느니라"},{"n":23,"t":"모세의 율법을 폐하지 아니하려고 사람이 안식일에도 할례를 받는 일이 있거든 내가 안식일에 사람의 전신을 건전케 한 것으로 너희가 나를 노여워하느냐"},{"n":24,"t":"외모로 판단하지 말고 공의의 판단으로 판단하라 하시니라"},{"n":25,"t":"예루살렘 사람 중에서 혹이 말하되 이는 저희가 죽이고자 하는 그 사람이 아니냐"},{"n":26,"t":"보라 드러나게 말하되 저희가 아무 말도 아니하는도다 당국자들은 이 사람을 참으로 그리스도인줄 알았는가"},{"n":27,"t":"그러나 우리는 이 사람이 어디서 왔는지 아노라 그리스도께서 오실 때에는 어디서 오시는지 아는 자가 없으리라 하는지라"},{"n":28,"t":"예수께서 성전에서 가르치시며 외쳐 가라사대 너희가 나를 알고 내가 어디서 온 것도 알거니와 내가 스스로 온 것이 아니로라 나를 보내신 이는 참이시니 너희는 그를 알지 못하나"},{"n":29,"t":"나는 아노니 이는 내가 그에게서 났고 그가 나를 보내셨음이니라 하신대"},{"n":30,"t":"저희가 예수를 잡고자 하나 손을 대는 자가 없으니 이는 그의 때가 아직 이르지 아니하였음이러라"},{"n":31,"t":"무리 중에 많은 사람이 예수를 믿고 말하되 그리스도께서 오실지라도 그 행하실 표적이 이 사람의 행한 것보다 더 많으랴 하니"},{"n":32,"t":"예수께 대하여 무리의 수군거리는 것이 바리새인들에게 들린지라 대제사장들과 바리새인들이 그를 잡으려고 하속들을 보내니"},{"n":33,"t":"예수께서 이르시되 내가 너희와 함께 조금 더 있다가 나를 보내신 이에게로 돌아가겠노라"},{"n":34,"t":"너희가 나를 찾아도 만나지 못할 터이요 나 있는 곳에 오지도 못하리라 하신대"},{"n":35,"t":"이에 유대인들이 서로 묻되 이 사람이 어디로 가기에 우리가 저를 만나지 못하리요 헬라인 중에 흩어져 사는 자들에게로 가서 헬라인을 가르칠터인가"},{"n":36,"t":"나를 찾아도 만나지 못할터이요 나 있는 곳에 오지도 못하리라 한 이 말이 무슨 말이냐 하니라"},{"n":37,"t":"명절 끝날 곧 큰날에 예수께서 서서 외쳐 가라사대 누구든지 목마르거든 내게로 와서 마시라"},{"n":38,"t":"나를 믿는 자는 성경에 이름과 같이 그 배에서 생수의 강이 흘러나리라 하시니"},{"n":39,"t":"이는 그를 믿는 자의 받을 성령을 가리켜 말씀하신 것이라 (예수께서 아직 영광을 받지 못하신 고로 성령이 아직 저희에게 계시지 아니하시더라)"},{"n":40,"t":"이 말씀을 들은 무리 중에서 혹은 이가 참으로 그 선지자라 하며"},{"n":41,"t":"혹은 그리스도라 하며 어떤이들은 그리스도가 어찌 갈릴리에서 나오겠느냐"},{"n":42,"t":"성경에 이르기를 그리스도는 다윗의 씨로 또 다윗의 살던 촌 베들레헴에서 나오리라 하지 아니하였느냐 하며"},{"n":43,"t":"예수를 인하여 무리 중에서 쟁론이 되니"},{"n":44,"t":"그 중에는 그를 잡고자 하는 자들도 있으나 손을 대는 자가 없었더라"},{"n":45,"t":"하속들이 대제사장들과 바리새인들에게로 오니 저희가 묻되 어찌하여 잡아오지 아니하였느냐"},{"n":46,"t":"하속들이 대답하되 그 사람의 말하는 것처럼 말한 사람은 이때까지 없었나이다 하니"},{"n":47,"t":"바리새인들이 대답하되 너희도 미혹되었느냐"},{"n":48,"t":"당국자들이나 바리새인 중에 그를 믿는 이가 있느냐"},{"n":49,"t":"율법을 알지 못하는 이 무리는 저주를 받은 자로다"},{"n":50,"t":"그 중에 한 사람 곧 전에 예수께 왔던 니고데모가 저희에게 말하되"},{"n":51,"t":"우리 율법은 사람의 말을 듣고 그 행한 것을 알기 전에 판결하느냐"},{"n":52,"t":"저희가 대답하여 가로되 너도 갈릴리에서 왔느냐 상고하여 보라 갈릴리에서는 선지자가 나지 못하느니라 하였더라"},{"n":53,"t":"(다 각각 집으로 돌아가고"}],"kids":[{"n":1,"t":"이 후에 예수님이 갈릴리에서 다니셨어요. 유대인들이 죽이려 했기 때문에 유대에서는 다니지 않으셨어요."},{"n":2,"t":"유대인의 명절 초막절이 가까웠어요."},{"n":3,"t":"예수님의 형제들이 \\"여기를 떠나 유대로 가셔서 형의 제자들에게도 행하시는 일을 보게 하세요.\\""},{"n":4,"t":"\\"세상에 알려지기를 바라면서 숨어 일하는 사람은 없어요. 이 일을 하시려면 자신을 세상에 나타내세요\\" 했어요."},{"n":5,"t":"형제들조차 그분을 믿지 않았어요."},{"n":6,"t":"예수님이 \\"내 때는 아직 이르지 않았지만 너희 때는 늘 준비되어 있다.\\""},{"n":7,"t":"\\"세상이 너희를 미워하지 않지만 나는 미워한다. 내가 그 행위가 악함을 증언하기 때문이다.\\""},{"n":8,"t":"\\"너희는 명절에 올라가라. 나는 이 명절에 올라가지 않는다. 내 때가 아직 차지 않았다\\" 하셨어요."},{"n":9,"t":"이 말씀을 하시고 갈릴리에 머무셨어요."},{"n":10,"t":"그의 형제들이 명절에 올라간 후 예수님도 올라가셨는데 드러나지 않게 비밀히 하셨어요."},{"n":11,"t":"유대인들이 명절에 그분을 찾으며 \\"그가 어디 있느냐?\\" 했어요."},{"n":12,"t":"무리 가운데 그분에 대해 수군거림이 많았어요. 어떤 사람들은 \\"좋은 사람이다\\", 어떤 사람들은 \\"아니다, 무리를 미혹한다\\" 했어요."},{"n":13,"t":"그러나 유대인들이 두려워서 누구도 드러내 그분에 대해 말하지 않았어요."},{"n":14,"t":"명절이 한창일 때 예수님이 성전에 올라가 가르치셨어요."},{"n":15,"t":"유대인들이 놀라며 \\"이 사람이 배운 적이 없는데 어떻게 글을 아느냐?\\" 했어요."},{"n":16,"t":"예수님이 \\"내 교훈은 내 것이 아니라 나를 보내신 분의 것이다.\\""},{"n":17,"t":"\\"누구든 그분의 뜻을 행하려 하면 이 교훈이 하나님께로부터 왔는지 내가 스스로 말하는 것인지 알 거다.\\""},{"n":18,"t":"\\"스스로 말하는 사람은 자기 영광을 구하지만 자기를 보내신 분의 영광을 구하는 사람은 참되고 그 속에 불의가 없다.\\""},{"n":19,"t":"\\"모세가 너희에게 율법을 주지 않았느냐? 너희 중 누구도 율법을 지키지 않는다. 왜 나를 죽이려 하느냐?\\" 하셨어요."},{"n":20,"t":"무리가 \\"당신은 귀신 들렸어요. 누가 당신을 죽이려 해요?\\" 했어요."},{"n":21,"t":"예수님이 \\"내가 한 가지 일을 했는데 너희 모두가 이상하게 여긴다.\\""},{"n":22,"t":"\\"모세가 너희에게 할례를 주었는데 (사실 모세가 아니라 조상들에게서 났다) 너희가 안식일에도 사람에게 할례를 행한다.\\""},{"n":23,"t":"\\"모세의 율법을 어기지 않으려고 사람이 안식일에 할례를 받는데 내가 안식일에 사람을 온전케 했다고 너희가 노여워하느냐?\\""},{"n":24,"t":"\\"외모로 판단하지 말고 의로운 판단을 하라\\" 하셨어요."},{"n":25,"t":"예루살렘 사람 중 어떤 사람이 \\"이 사람이 그들이 죽이려는 사람 아닌가?\\""},{"n":26,"t":"\\"보라, 드러내 놓고 말하는데 그들이 아무 말도 못 하는구나. 관원들이 이 사람이 진짜로 그리스도라는 것을 알았나?\\""},{"n":27,"t":"\\"그러나 우리가 이 사람이 어디서 왔는지 안다. 그리스도가 오실 때는 어디서 오는지 아무도 모를 거다\\" 했어요."},{"n":28,"t":"예수님이 성전에서 가르치며 외쳤어요. \\"너희가 나를 알고 내가 어디서 왔는지도 안다. 그러나 나는 스스로 오지 않았고 나를 보내신 분이 참되시지만 너희는 그분을 알지 못한다.\\""},{"n":29,"t":"\\"나는 그분을 안다. 그분에게서 왔고 그분이 나를 보내셨기 때문이다.\\""},{"n":30,"t":"그들이 그분을 잡으려 했지만 누구도 손을 대지 못했어요. 그분의 때가 아직 이르지 않았기 때문이에요."},{"n":31,"t":"무리 중 많은 사람이 그분을 믿으며 \\"그리스도가 오실 때 이분이 행하시는 것보다 더 많은 표적을 행하실까?\\" 했어요."},{"n":32,"t":"바리새인들이 무리가 그분에 대해 수군거리는 것을 듣고 대제사장들과 함께 그분을 잡으려고 종들을 보냈어요."},{"n":33,"t":"예수님이 \\"내가 너희와 함께 잠시 더 있다가 나를 보내신 분께 간다.\\""},{"n":34,"t":"\\"너희가 나를 찾아도 만나지 못할 거고 내가 있는 곳에는 너희가 올 수 없다\\" 하셨어요."},{"n":35,"t":"유대인들이 \\"이 사람이 어디로 가기에 우리가 만나지 못한다는 거지? 헬라인 가운데 흩어진 사람들에게 가서 헬라인을 가르치려는 건가?\\""},{"n":36,"t":"\\"\'너희가 나를 찾아도 만나지 못하리라\' \'내가 있는 곳에는 너희가 올 수 없다\' 한 이 말이 무엇이지?\\" 했어요."},{"n":37,"t":"명절 끝 날, 큰 날에 예수님이 서서 외쳤어요. \\"누구든 목마르면 내게 와서 마셔라.\\""},{"n":38,"t":"\\"나를 믿는 사람은 성경이 말한 대로 그 배에서 생수의 강이 흘러나올 거다.\\""},{"n":39,"t":"이것은 그를 믿는 사람들이 받을 성령에 대한 것이에요. 그때 성령이 아직 주어지지 않았어요. 예수님이 아직 영광을 받지 않으셨기 때문이에요."},{"n":40,"t":"무리 중 어떤 사람이 이 말씀을 듣고 \\"이분이 진실로 그 예언자다\\" 했어요."},{"n":41,"t":"어떤 사람은 \\"그리스도다\\" 했고, 어떤 사람은 \\"그리스도가 갈릴리에서 나오겠는가?\\""},{"n":42,"t":"\\"성경에 \'그리스도가 다윗의 자손이며 다윗이 살던 동네 베들레헴에서 난다\'고 하지 않았는가?\\" 했어요."},{"n":43,"t":"그분으로 인해 무리 가운데 분쟁이 일어났어요."},{"n":44,"t":"그들 중 몇 사람은 잡으려 했지만 누구도 손을 대지 못했어요."},{"n":45,"t":"종들이 대제사장과 바리새인들에게 돌아오니 \\"왜 데려오지 않았느냐?\\" 했어요."},{"n":46,"t":"종들이 \\"누구도 이 사람처럼 말한 적이 없어요\\" 했어요."},{"n":47,"t":"바리새인들이 \\"너희도 미혹된 거 아니냐?\\""},{"n":48,"t":"\\"관원이나 바리새인 중 누가 그를 믿었느냐?\\""},{"n":49,"t":"\\"율법을 알지 못하는 이 무리는 저주받았다\\" 했어요."},{"n":50,"t":"전에 예수님께 왔던 니고데모가, 그들 중 한 사람이었는데,"},{"n":51,"t":"\\"우리 율법이 사람의 말을 먼저 듣고 그가 행한 일을 알기 전에 판단합니까?\\" 했어요."},{"n":52,"t":"그들이 \\"너도 갈릴리 사람이냐? 살펴보아라. 갈릴리에서는 예언자가 나오지 않는다\\" 했어요."},{"n":53,"t":"모두가 자기 집으로 돌아갔어요."}]}},{"chapter":8,"title":"간음한 여인과 세상의 빛","verses":{"krv":[{"n":1,"t":"예수는 감람산으로 가시다"},{"n":2,"t":"아침에 다시 성전으로 들어오시니 백성이 다 나아오는지라 앉으사 저희를 가르치시더니"},{"n":3,"t":"서기관들과 바리새인들이 간음 중에 잡힌 여자를 끌고 와서 가운데 세우고"},{"n":4,"t":"예수께 말하되 선생이여 이 여자가 간음하다가 현장에서 잡혔나이다"},{"n":5,"t":"모세는 율법에 이러한 여자를 돌로 치라 명하였거니와 선생은 어떻게 말하겠나이까"},{"n":6,"t":"저희가 이렇게 말함은 고소할 조건을 얻고자하여 예수를 시험함이러라 예수께서 몸을 굽히사 손가락으로 땅에 쓰시니"},{"n":7,"t":"저희가 묻기를 마지 아니하는지라 이에 일어나 가라사대 너희 중에 죄 없는 자가 먼저 돌로 치라 하시고"},{"n":8,"t":"다시 몸을 굽히사 손가락으로 땅에 쓰시니"},{"n":9,"t":"저희가 이 말씀을 듣고 양심의 가책을 받아 어른으로 시작하여 젊은이까지 하나씩 하나씩 나가고 오직 예수와 그 가운데 섰는 여자만 남았더라"},{"n":10,"t":"예수께서 일어나사 여자 외에 아무도 없는 것을 보시고 이르시되 여자여 너를 고소하던 그들이 어디 있느냐 너를 정죄한 자가 없느냐"},{"n":11,"t":"대답하되 주여 없나이다 예수께서 가라사대 나도 너를 정죄하지 아니하노니 가서 다시는 죄를 범치 말라 하시니라)"},{"n":12,"t":"예수께서 또 일러 가라사대 나는 세상의 빛이니 나를 따르는 자는 어두움에 다니지 아니하고 생명의 빛을 얻으리라"},{"n":13,"t":"바리새인들이 가로되 네가 너를 위하여 증거하니 네 증거는 참되지 아니하도다"},{"n":14,"t":"예수께서 대답하여 가라사대 내가 나를 위하여 증거하여도 내 증거가 참되니 나는 내가 어디서 오며 어디로 가는 것을 앎이어니와 너희는 내가 어디서 오며 어디로 가는 것을 알지 못하느니라"},{"n":15,"t":"너희는 육체를 따라 판단하나 나는 아무도 판단치 아니하노라"},{"n":16,"t":"만일 내가 판단하여도 내 판단이 참되니 이는 내가 혼자 있는 것이 아니요 나를 보내신 이가 나와 함께 계심이라"},{"n":17,"t":"너희 율법에도 두 사람의 증거가 참되다 기록하였으니"},{"n":18,"t":"내가 나를 위하여 증거하는 자가 되고 나를 보내신 아버지도 나를 위하여 증거하시느니라"},{"n":19,"t":"이에 저희가 묻되 네 아버지가 어디 있느냐 예수께서 대답하시되 너희는 나를 알지 못하고 내 아버지도 알지 못하는도다 나를 알았더면 내 아버지도 알았으리라"},{"n":20,"t":"이 말씀은 성전에서 가르치실 때에 연보 궤 앞에서 하셨으나 잡는 사람이 없으니 이는 그의 때가 아직 이르지 아니하였음이러라"},{"n":21,"t":"다시 이르시되 내가 가리니 너희가 나를 찾다가 너희 죄 가운데서 죽겠고 나의 가는 곳에는 너희가 오지 못하리라"},{"n":22,"t":"유대인들이 가로되 저가 나의 가는 곳에는 너희가 오지 못하리라 하니 저가 자결하려는가"},{"n":23,"t":"예수께서 가라사대 너희는 아래서 났고 나는 위에서 났으며 너희는 이 세상에 속하였고 나는 이 세상에 속하지 아니하였느니라"},{"n":24,"t":"이러므로 내가 너희에게 말하기를 너희가 너희 죄 가운데서 죽으리라 하였노라 너희가 만일 내가 그인줄 믿지 아니하면 너희 죄 가운데서 죽으리라"},{"n":25,"t":"저희가 말하되 네가 누구냐 예수께서 가라사대 나는 처음부터 너희에게 말하여 온 자니라"},{"n":26,"t":"내가 너희를 대하여 말하고 판단할 것이 많으나 나를 보내신 이가 참되시매 내가 그에게 들은 그것을 세상에게 말하노라 하시되"},{"n":27,"t":"저희는 아버지를 가리켜 말씀하신 줄을 깨닫지 못하더라"},{"n":28,"t":"이에 예수께서 가라사대 너희는 인자를 든 후에 내가 그인 줄을 알고 또 내가 스스로 아무 것도 하지 아니하고 오직 아버지께서 가르치신대로 이런 것을 말하는 줄도 알리라"},{"n":29,"t":"나를 보내신 이가 나와 함께 하시도다 내가 항상 그의 기뻐하시는 일을 행하므로 나를 혼자 두지 아니하셨느니라"},{"n":30,"t":"이 말씀을 하시매 많은 사람이 믿더라"},{"n":31,"t":"그러므로 예수께서 자기를 믿은 유대인들에게 이르시되 너희가 내 말에 거하면 참 내 제자가 되고"},{"n":32,"t":"진리를 알지니 진리가 너희를 자유케 하리라"},{"n":33,"t":"저희가 대답하되 우리가 아브라함의 자손이라 남의 종이 된 적이 없거늘 어찌하여 우리가 자유케 되리라 하느냐"},{"n":34,"t":"예수께서 대답하시되 진실로 진실로 너희에게 이르노니 죄를 범하는 자마다 죄의 종이라"},{"n":35,"t":"종은 영원히 집에 거하지 못하되 아들은 영원히 거하나니"},{"n":36,"t":"그러므로 아들이 너희를 자유케 하면 너희가 참으로 자유하리라"},{"n":37,"t":"나도 너희가 아브라함의 자손인줄 아노라 그러나 내 말이 너희 속에 있을 곳이 없으므로 나를 죽이려 하는도다"},{"n":38,"t":"나는 내 아버지에게서 본 것을 말하고 너희는 너희 아비에게서 들은 것을 행하느니라"},{"n":39,"t":"대답하여 가로되 우리 아버지는 아브라함이라 하니 예수께서 가라사대 너희가 아브라함의 자손이면 아브라함의 행사를 할것이어늘"},{"n":40,"t":"지금 하나님께 들은 진리를 너희에게 말한 사람인 나를 죽이려 하는도다 아브라함은 이렇게 하지 아니하였느니라"},{"n":41,"t":"너희는 너희 아비의 행사를 하는도다 대답하되 우리가 음란한데서 나지 아니하였고 아버지는 한분 뿐이시니 곧 하나님이시로다"},{"n":42,"t":"예수께서 가라사대 하나님이 너희 아버지였으면 너희가 나를 사랑하였으리니 이는 내가 하나님께로 나서 왔음이라 나는 스스로 온 것이 아니요 아버지께서 나를 보내신 것이니라"},{"n":43,"t":"어찌하여 내 말을 깨닫지 못하느냐 이는 내 말을 들을줄 알지 못함이로다"},{"n":44,"t":"너희는 너희 아비 마귀에게서 났으니 너희 아비의 욕심을 너희도 행하고자 하느니라 저는 처음부터 살인한 자 요 진리가 그 속에 없으므로 진리에 서지 못하고 거짓을 말할 때마다 제 것으로 말하나니 이는 저가 거짓말장이요 거짓의 아비가 되었음이니라"},{"n":45,"t":"내가 진리를 말하므로 너희가 나를 믿지 아니하는도다"},{"n":46,"t":"너희 중에 누가 나를 죄로 책잡겠느냐 내가 진리를 말하매 어찌하여 나를 믿지 아니하느냐"},{"n":47,"t":"하나님께 속한 자는 하나님의 말씀을 듣나니 너희가 듣지 아니함은 하나님께 속하지 아니하였음이로다"},{"n":48,"t":"유대인들이 대답하여 가로되 우리가 너를 사마리아 사람이라 또는 귀신이 들렸다 하는 말이 옳지 아니하냐"},{"n":49,"t":"예수께서 대답하시되 나는 귀신 들린 것이 아니라 오직 내 아버지를 공경함이어늘 너희가 나를 무시하는도다"},{"n":50,"t":"나는 내 영광을 구치 아니하나 구하고 판단하시는 이가 계시니라"},{"n":51,"t":"진실로 진실로 너희에게 이르노니 사람이 내 말을 지키면 죽음을 영원히 보지 아니하리라"},{"n":52,"t":"유대인들이 가로되 지금 네가 귀신 들린 줄을 아노라 아브라함과 선지자들도 죽었거늘 네 말은 사람이 내말을 지키면 죽음을 영원히 맛보지 아니하리라 하니"},{"n":53,"t":"너는 이미 죽은 우리 조상 아브라함보다 크냐 또 선지자들도 죽었거늘 너는 너를 누구라 하느냐"},{"n":54,"t":"예수께서 대답하시되 내가 내게 영광을 돌리면 내 영광이 아무 것도 아니어니와 내게 영광을 돌리시는 이는 내 아버지시니 곧 너희가 너희 하나님이라 칭하는 그이시라"},{"n":55,"t":"너희는 그를 알지 못하되 나는 아노니 만일 내가 알지 못한다 하면 나도 너희 같이 거짓말장이가 되리라 나는 그를 알고 또 그의 말씀을 지키노라"},{"n":56,"t":"너희 조상 아브라함은 나의 때 볼 것을 즐거워하다가 보고 기뻐하였느니라"},{"n":57,"t":"유대인들이 가로되 네가 아직 오십도 못되었는데 아브라함을 보았느냐"},{"n":58,"t":"예수께서 가라사대 진실로 진실로 너희에게 이르노니 아브라함이 나기 전부터 내가 있느니라 하시니"},{"n":59,"t":"저희가 돌을 들어 치려하거늘 예수께서 숨어 성전에서 나가시니라"}],"kids":[{"n":1,"t":"예수님이 감람산으로 가셨어요."},{"n":2,"t":"이른 아침에 다시 성전에 가시니 모든 백성이 그분께 나아왔어요. 예수님이 앉아 그들을 가르치셨어요."},{"n":3,"t":"율법 학자와 바리새인들이 간음하다 잡힌 여자를 끌고 와서 가운데 세우고,"},{"n":4,"t":"\\"선생님, 이 여자가 간음하다 잡혔어요.\\""},{"n":5,"t":"\\"모세는 율법에 이런 사람을 돌로 치라고 우리에게 명령했어요. 당신은 어떻게 말씀하시겠어요?\\" 했어요."},{"n":6,"t":"이는 그분을 시험하여 고소할 거리를 얻으려고 한 거예요. 예수님이 몸을 굽혀 손가락으로 땅에 무언가를 쓰셨어요."},{"n":7,"t":"그들이 계속 묻자 일어나 \\"너희 중에 죄 없는 사람이 먼저 그녀에게 돌을 던져라\\" 하셨어요."},{"n":8,"t":"다시 몸을 굽혀 땅에 무언가를 쓰셨어요."},{"n":9,"t":"그들이 이 말씀을 듣고 양심에 가책을 받아 어른부터 시작하여 한 사람씩 떠나갔고 여자만 가운데 남아 있었어요."},{"n":10,"t":"예수님이 일어나 \\"여인이여, 그 사람들이 어디 있느냐? 너를 정죄한 사람이 없느냐?\\" 하셨어요."},{"n":11,"t":"\\"주여, 없어요\\" 하니 \\"나도 너를 정죄하지 않는다. 가서 이제부터 다시는 죄짓지 마라\\" 하셨어요."},{"n":12,"t":"예수님이 다시 그들에게 \\"나는 세상의 빛이다. 나를 따르는 사람은 어둠에 다니지 않고 생명의 빛을 얻을 거다\\" 하셨어요."},{"n":13,"t":"바리새인들이 \\"네가 너 자신에 대해 증언하니 네 증언은 참되지 않다\\" 했어요."},{"n":14,"t":"예수님이 \\"내가 나에 대해 증언해도 내 증언은 참되다. 내가 어디서 왔고 어디로 가는지 알지만 너희는 내가 어디서 왔고 어디로 가는지 알지 못한다.\\""},{"n":15,"t":"\\"너희는 육체로 판단하지만 나는 누구도 판단하지 않는다.\\""},{"n":16,"t":"\\"내가 판단한다면 내 판단이 참되다. 내가 혼자가 아니라 나를 보내신 아버지와 함께 있기 때문이다.\\""},{"n":17,"t":"\\"너희 율법에도 두 사람의 증언이 참되다고 기록되었다.\\""},{"n":18,"t":"\\"내가 나에 대해 증언하는 사람이고 나를 보내신 아버지도 나에 대해 증언하신다\\" 하셨어요."},{"n":19,"t":"그들이 \\"네 아버지가 어디 있느냐?\\" 하니 예수님이 \\"너희는 나도 모르고 내 아버지도 모른다. 나를 알았다면 내 아버지도 알았을 거다\\" 하셨어요."},{"n":20,"t":"이 말씀은 성전에서 헌금함 곁에서 가르치실 때 하신 거예요. 누구도 그분을 잡지 못했어요. 그분의 때가 아직 이르지 않았기 때문이에요."},{"n":21,"t":"예수님이 다시 \\"내가 가니 너희가 나를 찾다가 너희 죄 가운데서 죽을 거다. 내가 가는 곳에 너희는 올 수 없다\\" 하셨어요."},{"n":22,"t":"유대인들이 \\"그가 \'내가 가는 곳에 너희는 올 수 없다\' 하니 자살하려는가?\\" 했어요."},{"n":23,"t":"예수님이 \\"너희는 아래에서 났고 나는 위에서 났다. 너희는 이 세상에 속했고 나는 이 세상에 속하지 않았다.\\""},{"n":24,"t":"\\"그래서 내가 너희에게 \'너희가 너희 죄 가운데서 죽을 거다\' 했다. 너희가 내가 그인 줄을 믿지 않으면 너희 죄 가운데서 죽을 거다\\" 하셨어요."},{"n":25,"t":"\\"너는 누구냐?\\" 하니 \\"처음부터 너희에게 말한 그 사람이다.\\""},{"n":26,"t":"\\"내가 너희에 대해 말하고 판단할 일이 많지만 나를 보내신 분이 참되시니 내가 그분에게서 들은 것을 세상에 말한다\\" 하셨어요."},{"n":27,"t":"그들은 그분이 아버지에 대해 말씀하시는 줄을 깨닫지 못했어요."},{"n":28,"t":"예수님이 \\"너희가 사람의 아들을 든 후에 내가 그인 줄을 알고 또 내가 스스로 아무것도 하지 않고 아버지께서 가르치신 대로 말하는 줄을 알 거다.\\""},{"n":29,"t":"\\"나를 보내신 분이 나와 함께 계신다. 그분이 나를 혼자 두지 않으셨다. 내가 항상 그분이 기뻐하시는 일을 행하기 때문이다\\" 하셨어요."},{"n":30,"t":"이 말씀을 하시니 많은 사람이 그분을 믿었어요."},{"n":31,"t":"예수님이 자기를 믿은 유대인들에게 \\"너희가 내 말에 거하면 진정 내 제자이고,\\""},{"n":32,"t":"\\"진리를 알 거고 진리가 너희를 자유롭게 할 거다\\" 하셨어요."},{"n":33,"t":"그들이 \\"우리는 아브라함의 자손이라 누구에게 종이 된 적이 없는데 어떻게 \'너희가 자유롭게 될 거다\' 하느냐?\\" 했어요."},{"n":34,"t":"예수님이 \\"진정으로 진정으로 너희에게 말한다. 죄를 짓는 사람마다 죄의 종이다.\\""},{"n":35,"t":"\\"종은 영원히 집에 머물지 못하지만 아들은 영원히 머문다.\\""},{"n":36,"t":"\\"그러므로 아들이 너희를 자유롭게 하면 진정 자유로울 거다.\\""},{"n":37,"t":"\\"너희가 아브라함의 자손인 줄 안다. 그러나 내 말이 너희 안에 있을 곳이 없기 때문에 나를 죽이려 한다.\\""},{"n":38,"t":"\\"나는 내 아버지에게서 본 것을 말하고 너희는 너희 아버지에게서 들은 것을 행한다\\" 하셨어요."},{"n":39,"t":"그들이 \\"우리 아버지는 아브라함이에요\\" 하니 예수님이 \\"너희가 아브라함의 자녀라면 아브라함의 일을 행할 거다.\\""},{"n":40,"t":"\\"그러나 이제 너희가 하나님께 들은 진리를 너희에게 말한 사람인 나를 죽이려 한다. 아브라함은 이런 일을 하지 않았다.\\""},{"n":41,"t":"\\"너희는 너희 아비의 일을 행하고 있다.\\" 그들이 \\"우리는 음행으로 태어나지 않았어요. 우리에게 한 아버지가 계신데 곧 하나님이에요\\" 했어요."},{"n":42,"t":"예수님이 \\"하나님이 너희 아버지였다면 너희가 나를 사랑했을 거다. 내가 하나님께로부터 나와 왔다. 내가 스스로 온 것이 아니라 그분이 나를 보내셨다.\\""},{"n":43,"t":"\\"너희가 어찌하여 내 말을 깨닫지 못하느냐? 내 말을 들을 줄 모르기 때문이다.\\""},{"n":44,"t":"\\"너희는 너희 아비 마귀에게서 났고 너희 아비의 욕망을 행하려 한다. 그는 처음부터 살인한 사람이고 진리가 그 속에 없어 진리에 서지 못한다. 거짓을 말할 때 자기에게서 나오는 대로 말한다. 그는 거짓말쟁이고 거짓의 아비다.\\""},{"n":45,"t":"\\"내가 진리를 말하므로 너희가 나를 믿지 않는다.\\""},{"n":46,"t":"\\"너희 중에 누가 나의 죄를 지적할 수 있느냐? 내가 진리를 말하는데 어찌하여 나를 믿지 않느냐?\\""},{"n":47,"t":"\\"하나님께 속한 사람은 하나님의 말씀을 듣는데, 너희가 듣지 않는 것은 하나님께 속하지 않았기 때문이다\\" 하셨어요."},{"n":48,"t":"유대인들이 \\"너는 사마리아 사람이고 귀신 들렸다고 한 우리 말이 옳지 않으냐?\\" 했어요."},{"n":49,"t":"예수님이 \\"나는 귀신 들리지 않았다. 내 아버지를 공경하고 너희는 나를 모욕한다.\\""},{"n":50,"t":"\\"나는 내 영광을 구하지 않는다. 구하시고 판단하시는 분이 계신다.\\""},{"n":51,"t":"\\"진정으로 진정으로 너희에게 말한다. 누구든 내 말을 지키면 영원히 죽음을 보지 않을 거다\\" 하셨어요."},{"n":52,"t":"유대인들이 \\"이제 네가 귀신 들린 줄 안다. 아브라함도 예언자들도 죽었는데 너는 \'내 말을 지키면 영원히 죽음을 맛보지 않을 거다\' 하는구나.\\""},{"n":53,"t":"\\"네가 우리 조상 아브라함보다 크냐? 그도 죽었고 예언자들도 죽었다. 너는 너 자신을 누구로 만드느냐?\\" 했어요."},{"n":54,"t":"예수님이 \\"내가 나를 영화롭게 하면 내 영광은 헛것이다. 나를 영화롭게 하시는 분은 너희가 \'우리 하나님\'이라 부르는 내 아버지시다.\\""},{"n":55,"t":"\\"너희는 그분을 알지 못하지만 나는 안다. 만약 모른다 한다면 너희와 같은 거짓말쟁이가 될 거다. 그러나 나는 그분을 알고 그분의 말씀을 지킨다.\\""},{"n":56,"t":"\\"너희 조상 아브라함은 내 날 볼 것을 즐거워하다가 보고 기뻐했다.\\""},{"n":57,"t":"유대인들이 \\"네가 아직 오십도 안 됐는데 아브라함을 보았다고?\\" 했어요."},{"n":58,"t":"예수님이 \\"진정으로 진정으로 너희에게 말한다. 아브라함이 나기 전부터 내가 있다\\" 하셨어요."},{"n":59,"t":"그들이 돌을 들어 치려 했지만 예수님이 숨어 성전에서 나가셨어요."}]}},{"chapter":9,"title":"맹인이 보게 됨","verses":{"krv":[{"n":1,"t":"예수께서 길 가실 때에 날 때부터 소경 된 사람을 보신지라"},{"n":2,"t":"제자들이 물어 가로되 랍비여 이 사람이 소경으로 난 것이 뉘 죄로 인함이오니이까 자기오니이까 그 부모오니이까"},{"n":3,"t":"예수께서 대답하시되 이 사람이나 그 부모가 죄를 범한 것이 아니라 그에게서 하나님의 하시는 일을 나타내고자 하심이니라"},{"n":4,"t":"때가 아직 낮이매 나를 보내신 이의 일을 우리가 하여야 하리라 밤이 오리니 그때는 아무도 일할 수 없느니라"},{"n":5,"t":"내가 세상에 있는 동안에는 세상의 빛이로라"},{"n":6,"t":"이 말씀을 하시고 땅에 침을 뱉아 진흙을 이겨 그의 눈에 바르시고"},{"n":7,"t":"이르시되 실로암 못에 가서 씻으라 하시니 (실로암은 번역하면 보냄을 받았다는 뜻이라) 이에 가서 씻고 밝은 눈으로 왔더라"},{"n":8,"t":"이웃 사람들과 및 전에 저가 걸인인 것을 보았던 사람들이 가로되 이는 앉아서 구걸하던 자가 아니냐"},{"n":9,"t":"혹은 그 사람이라 하며 혹은 아니라 그와 비슷하다 하거늘 제 말은 내가 그로라 하니"},{"n":10,"t":"저희가 묻되 그러면 네 눈이 어떻게 떠졌느냐"},{"n":11,"t":"대답하되 예수라 하는 그 사람이 진흙을 이겨 내 눈에 바르고 나더러 실로암에 가서 씻으라 하기에 가서 씻었더니 보게 되었노라"},{"n":12,"t":"저희가 가로되 그가 어디 있느냐 가로되 알지 못하노라 하니라"},{"n":13,"t":"저희가 전에 소경 되었던 사람을 데리고 바리새인들에게 갔더라"},{"n":14,"t":"예수께서 진흙을 이겨 눈을 뜨게 하신 날은 안식일이라"},{"n":15,"t":"그러므로 바리새인들도 그 어떻게 보게 된 것을 물으니 가로되 그 사람이 진흙을 내 눈에 바르매 내가 씻고 보나이다 하니"},{"n":16,"t":"바리새인 중에 혹은 말하되 이 사람이 안식일을 지키지 아니하니 하나님께로서 온 자가 아니라 하며 혹은 말하되 죄인으로서 어떻게 이러한 표적을 행하겠느냐 하여 피차 쟁론이 되었더니"},{"n":17,"t":"이에 소경 되었던 자에게 다시 묻되 그 사람이 네 눈을 뜨게 하였으니 너는 그를 어떠한 사람이라 하느냐 대답하되 선지자니이다 한대"},{"n":18,"t":"유대인들이 저가 소경으로 있다가 보게 된 것을 믿지 아니하고 그 부모를 불러 묻되"},{"n":19,"t":"이는 너희 말에 소경으로 났다 하는 너희 아들이냐 그러면 지금은 어떻게 되어 보느냐"},{"n":20,"t":"그 부모가 대답하여 가로되 이가 우리 아들인 것과 소경으로 난 것을 아나이다"},{"n":21,"t":"그러나 지금 어떻게 되어 보는지 또는 누가 그 눈을 뜨게 하였는지 우리는 알지 못하나이다 저에게 물어 보시오 저가 장성하였으니 자기 일을 말하리이다"},{"n":22,"t":"그 부모가 이렇게 말한 것은 이미 유대인들이 누구든지 예수를 그리스도로 시인하는 자는 출교하기로 결의하였으므로 저희를 무서워함이러라"},{"n":23,"t":"이러므로 그 부모가 말하기를 저가 장성하였으니 저에게 물어 보시오 하였더라"},{"n":24,"t":"이에 저희가 소경 되었던 사람을 두번째 불러 이르되 너는 영광을 하나님께 돌리라 우리는 저 사람이 죄인인줄 아노라"},{"n":25,"t":"대답하되 그가 죄인인지 내가 알지 못하나 한 가지 아는 것은 내가 소경으로 있다가 지금 보는 그것이니이다"},{"n":26,"t":"저희가 가로되 그 사람이 네게 무엇을 하였느냐 어떻게 네 눈을 뜨게 하였느냐"},{"n":27,"t":"대답하되 내가 이미 일렀어도 듣지 아니하고 어찌하여 다시 듣고자 하나이까 당신들도 그 제자가 되려 하나이까"},{"n":28,"t":"저희가 욕하여 가로되 너는 그의 제자나 우리는 모세의 제자라"},{"n":29,"t":"하나님이 모세에게는 말씀하신 줄을 우리가 알거니와 이 사람은 어디서 왔는지 알지 못하노라"},{"n":30,"t":"그 사람이 대답하여 가로되 이상하다 이 사람이 내 눈을 뜨게 하였으되 당신들이 그가 어디서 왔는지 알지 못하는도다"},{"n":31,"t":"하나님이 죄인을 듣지 아니하시고 경건하여 그의 뜻대로 행하는 자는 들으시는 줄을 우리가 아나이다"},{"n":32,"t":"창세 이후로 소경으로난 자의 눈을 뜨게 하였다 함을 듣지 못하였으니"},{"n":33,"t":"이 사람이 하나님께로부터 오지 아니하였으면 아무 일도 할 수 없으리이다"},{"n":34,"t":"저희가 대답하여 가로되 네가 온전히 죄 가운데서 나서 우리를 가르치느냐 하고 이에 쫓아내어 보내니라"},{"n":35,"t":"예수께서 저희가 그 사람을 쫓아냈다 하는 말을 들으셨더니 그를 만나사 가라사대 네가 인자를 믿느냐"},{"n":36,"t":"대답하여 가로되 주여 그가 누구시오니이까 내가 믿고자 하나이다"},{"n":37,"t":"예수께서 가라사대 네가 그를 보았거니와 지금 너와 말하는 자가 그이니라"},{"n":38,"t":"가로되 주여 내가 믿나이다 하고 절하는지라"},{"n":39,"t":"예수께서 가라사대 내가 심판하러 이 세상에 왔으니 보지 못하는 자들은 보게 하고 보는 자들은 소경되게 하려 함이라 하시니"},{"n":40,"t":"바리새인 중에 예수와 함께 있던 자들이 이 말씀을 듣고 가로되 우리도 소경인가"},{"n":41,"t":"예수께서 가라사대 너희가 소경 되었더면 죄가 없으려니와 본다고 하니 너희 죄가 그저 있느니라"}],"kids":[{"n":1,"t":"예수님이 길을 가실 때 태어날 때부터 맹인인 사람을 보셨어요."},{"n":2,"t":"제자들이 \\"랍비여, 이 사람이 맹인으로 태어난 것이 누구의 죄 때문이에요? 자기의 죄예요, 부모의 죄예요?\\" 했어요."},{"n":3,"t":"예수님이 \\"이 사람이나 부모의 죄가 아니다. 그에게서 하나님의 일이 나타나려는 거다.\\""},{"n":4,"t":"\\"낮이 있을 때 우리는 나를 보내신 분의 일을 행해야 한다. 누구도 일할 수 없는 밤이 온다.\\""},{"n":5,"t":"\\"내가 세상에 있는 동안 세상의 빛이다\\" 하셨어요."},{"n":6,"t":"이 말씀을 하시고 땅에 침을 뱉어 진흙을 만들어 그의 눈에 바르시고,"},{"n":7,"t":"\\"실로암 못에 가서 씻으라\\" 하셨어요. 실로암은 \'보냄받은\'이란 뜻이에요. 그가 가서 씻고 보게 되어 돌아왔어요."},{"n":8,"t":"이웃과 그가 구걸하던 것을 본 사람들이 \\"이 사람이 앉아서 구걸하던 사람 아닌가?\\" 했어요."},{"n":9,"t":"어떤 사람은 \\"그 사람이다\\", 어떤 사람은 \\"그와 비슷하다\\" 했어요. 그가 \\"내가 그 사람이에요\\" 했어요."},{"n":10,"t":"\\"네 눈이 어떻게 열렸느냐?\\" 했어요."},{"n":11,"t":"\\"예수라 하는 사람이 진흙을 만들어 내 눈에 발랐어요. \'실로암에 가서 씻으라\' 하시기에 가서 씻으니 보게 됐어요\\" 했어요."},{"n":12,"t":"\\"그가 어디 있느냐?\\" 하니 \\"몰라요\\" 했어요."},{"n":13,"t":"그들이 전에 맹인이었던 사람을 바리새인들에게 데려갔어요."},{"n":14,"t":"예수님이 진흙을 만들어 눈을 뜨게 하신 그날은 안식일이었어요."},{"n":15,"t":"바리새인들도 그가 어떻게 보게 됐는지 물었어요. 그가 \\"그분이 내 눈에 진흙을 발랐고 내가 씻었더니 보게 됐어요\\" 했어요."},{"n":16,"t":"바리새인 중 어떤 사람은 \\"이 사람은 안식일을 지키지 않으니 하나님께로부터 온 사람이 아니다\\" 하고, 어떤 사람은 \\"죄인이 어떻게 이런 표적을 행하겠는가?\\" 하여 그들 사이에 분쟁이 있었어요."},{"n":17,"t":"다시 맹인이었던 사람에게 \\"그가 네 눈을 뜨게 했으니 그에 대해 너는 무엇이라 하느냐?\\" 하니 \\"예언자세요\\" 했어요."},{"n":18,"t":"유대인들이 그가 맹인이었다가 보게 된 것을 믿지 않고 그의 부모를 불렀어요."},{"n":19,"t":"\\"이가 너희가 맹인으로 태어났다는 아들이냐? 그가 이제 어떻게 보게 됐느냐?\\" 했어요."},{"n":20,"t":"부모가 \\"이가 우리 아들이고 맹인으로 태어난 줄을 압니다.\\""},{"n":21,"t":"\\"그가 이제 어떻게 보는지, 누가 눈을 뜨게 했는지 모릅니다. 그에게 물어 보세요. 다 자랐으니 스스로 말할 수 있어요\\" 했어요."},{"n":22,"t":"그의 부모가 유대인들을 두려워해서 이렇게 말했어요. 누구든 예수를 그리스도로 시인하면 회당에서 쫓겨나기로 유대인들이 이미 결정해 놓았기 때문이에요."},{"n":23,"t":"그래서 부모가 \\"그가 다 자랐으니 그에게 물어 보세요\\" 한 거예요."},{"n":24,"t":"두 번째로 맹인이었던 사람을 불러 \\"하나님께 영광을 돌리라. 우리는 이 사람이 죄인인 줄 안다\\" 했어요."},{"n":25,"t":"그가 \\"죄인인지 모르겠어요. 한 가지는 알아요. 내가 맹인이었다가 이제 본다는 거예요\\" 했어요."},{"n":26,"t":"\\"그가 네게 무엇을 했느냐? 어떻게 네 눈을 뜨게 했느냐?\\" 했어요."},{"n":27,"t":"\\"내가 이미 말했는데 듣지 않으셨네요. 왜 다시 들으려 하세요? 당신들도 그분의 제자가 되고 싶어요?\\" 했어요."},{"n":28,"t":"그들이 그를 욕하며 \\"너는 그의 제자이지만 우리는 모세의 제자다.\\""},{"n":29,"t":"\\"하나님이 모세에게 말씀하신 줄 알지만 이 사람은 어디서 왔는지도 모른다\\" 했어요."},{"n":30,"t":"그가 \\"이상하군요. 그분이 내 눈을 뜨게 하셨는데 어디서 왔는지 모른다고요?\\""},{"n":31,"t":"\\"하나님이 죄인의 말은 듣지 않으시지만 경건하여 그분의 뜻을 행하는 사람의 말은 들으시는 줄 우리가 알아요.\\""},{"n":32,"t":"\\"태어날 때부터 맹인이었던 사람의 눈을 뜨게 한 일은 옛부터 들어 본 적이 없어요.\\""},{"n":33,"t":"\\"이분이 하나님께로부터 오지 않았다면 아무것도 할 수 없었을 거예요\\" 했어요."},{"n":34,"t":"그들이 \\"네가 온통 죄 가운데서 났는데 우리를 가르치느냐?\\" 하고 그를 쫓아냈어요."},{"n":35,"t":"예수님이 그가 쫓겨난 것을 들으시고 그를 만나 \\"네가 사람의 아들을 믿느냐?\\" 하셨어요."},{"n":36,"t":"그가 \\"주여, 그가 누구세요? 제가 그분을 믿게요\\" 했어요."},{"n":37,"t":"예수님이 \\"네가 그를 보았다. 너와 말하는 사람이 그다\\" 하셨어요."},{"n":38,"t":"그가 \\"주여, 믿어요\\" 하고 절했어요."},{"n":39,"t":"예수님이 \\"내가 심판하러 이 세상에 왔다. 보지 못하는 사람들은 보게 하고 보는 사람들은 맹인 되게 하려 함이다\\" 하셨어요."},{"n":40,"t":"바리새인 중 그분과 함께 있던 사람들이 듣고 \\"우리도 맹인이냐?\\" 했어요."},{"n":41,"t":"예수님이 \\"너희가 맹인이라면 죄가 없을 거다. 그러나 너희가 \'본다\' 하니 너희 죄가 그대로 있다\\" 하셨어요."}]}},{"chapter":10,"title":"선한 목자","verses":{"krv":[{"n":1,"t":"내가 진실로 진실로 너희에게 이르노니 양의 우리에 문으로 들어가지 아니하고 다른데로 넘어가는 자는 절도며 강도요"},{"n":2,"t":"문으로 들어가는 이가 양의 목자라"},{"n":3,"t":"문지기는 그를 위하여 문을 열고 양은 그의 음성을 듣나니 그가 자기 양의 이름을 각각 불러 인도하여 내느니라"},{"n":4,"t":"자기 양을 다 내어 놓은 후에 앞서 가면 양들이 그의 음성을 아는고로 따라 오되"},{"n":5,"t":"타인의 음성은 알지 못하는고로 타인을 따르지 아니하고 도리어 도망하느니라"},{"n":6,"t":"예수께서 이 비유로 저희에게 말씀하셨으나 저희는 그 하신 말씀이 무엇인지 알지 못하니라"},{"n":7,"t":"그러므로 예수께서 다시 이르시되 내가 진실로 진실로 너희에게 말하노니 나는 양의 문이라"},{"n":8,"t":"나보다 먼저 온 자는 다 절도요 강도니 양들이 듣지 아니하였느니라"},{"n":9,"t":"내가 문이니 누구든지 나로 말미암아 들어가면 구원을 얻고 또는 들어가며 나오며 꼴을 얻으리라"},{"n":10,"t":"도적이 오는 것은 도적질하고 죽이고 멸망시키려는 것뿐이요 내가 온 것은 양으로 생명을 얻게 하고 더 풍성히 얻게 하려는 것이라"},{"n":11,"t":"나는 선한 목자라 선한 목자는 양들을 위하여 목숨을 버리거니와"},{"n":12,"t":"삯군은 목자도 아니요 양도 제 양이 아니라 이리가 오는 것을 보면 양을 버리고 달아나나니 이리가 양을 늑탈하고 또 헤치느니라"},{"n":13,"t":"달아나는 것은 저가 삯군인 까닭에 양을 돌아보지 아니함이나"},{"n":14,"t":"나는 선한 목자라 내가 내 양을 알고 양도 나를 아는 것이"},{"n":15,"t":"아버지께서 나를 아시고 내가 아버지를 아는 것 같으니 나는 양을 위하여 목숨을 버리노라"},{"n":16,"t":"또 이 우리에 들지 아니한 다른 양들이 내게 있어 내가 인도하여야 할터이니 저희도 내 음성을 듣고 한 무리가 되어 한 목자에게 있으리라"},{"n":17,"t":"아버지께서 나를 사랑하시는 것은 내가 다시 목숨을 얻기 위하여 목숨을 버림이라"},{"n":18,"t":"이를 내게서 빼앗는 자가 있는 것이 아니라 내가 스스로 버리노라 나는 버릴 권세도 있고 다시 얻을 권세도 있으니 이 계명은 내 아버지에게서 받았노라 하시니라"},{"n":19,"t":"이 말씀을 인하여 유대인 중에 다시 분쟁이 일어나니"},{"n":20,"t":"그 중에 많은 사람이 말하되 저가 귀신 들려 미쳤거늘 어찌하여 그 말을 듣느냐 하며"},{"n":21,"t":"혹은 말하되 이 말은 귀신 들린 자의 말이 아니라 귀신이 소경의 눈을 뜨게 할 수 있느냐 하더라"},{"n":22,"t":"예루살렘에 수전절이 이르니 때는 겨울이라"},{"n":23,"t":"예수께서 성전 안 솔로몬 행각에서 다니시니"},{"n":24,"t":"유대인들이 에워싸고 가로되 당신이 언제까지나 우리 마음을 의혹케 하려나이까 그리스도여든 밝히 말하시오 하니"},{"n":25,"t":"예수께서 대답하시되 내가 너희에게 말하였으되 믿지 아니하는도다 내가 내 아버지의 이름으로 행하는 일들이 나를 증거하는 것이어늘"},{"n":26,"t":"너희가 내 양이 아니므로 믿지 아니하는도다"},{"n":27,"t":"내 양은 내 음성을 들으며 나는 저희를 알며 저희는 나를 따르느니라"},{"n":28,"t":"내가 저희에게 영생을 주노니 영원히 멸망치 아니할 터이요 또 저희를 내 손에서 빼앗을 자가 없느니라"},{"n":29,"t":"저희를 주신 내 아버지는 만유보다 크시매 아무도 아버지 손에서 빼앗을 수 없느니라"},{"n":30,"t":"나와 아버지는 하나이니라 하신대"},{"n":31,"t":"유대인들이 다시 돌을 들어 치려 하거늘"},{"n":32,"t":"예수께서 대답하시되 내가 아버지께로 말미암아 여러가지 선한 일을 너희에게 보였거늘 그 중에 어떤 일로 나를 돌로 치려하느냐"},{"n":33,"t":"유대인들이 대답하되 선한 일을 인하여 우리가 너를 돌로 치려는 것이 아니라 참람함을 인함이니 네가 사람이 되어 자칭 하나님이라 함이로라"},{"n":34,"t":"예수께서 가라사대 너희 율법에 기록한바 내가 너희를 신이라 하였노라 하지 아니하였느냐"},{"n":35,"t":"성경은 폐하지 못하나니 하나님의 말씀을 받은 사람들을 신이라 하셨거든"},{"n":36,"t":"하물며 아버지께서 거룩하게 하사 세상에 보내신 자가 나는 하나님 아들이라 하는 것으로 너희가 어찌 참람하다 하느냐"},{"n":37,"t":"만일 내가 내 아버지의 일을 행치 아니하거든 나를 믿지 말려니와"},{"n":38,"t":"내가 행하거든 나를 믿지 아니할지라도 그 일은 믿으라 그러면 너희가 아버지께서 내 안에 계시고 내가 아버지 안에 있음을 깨달아 알리라 하신대"},{"n":39,"t":"저희가 다시 예수를 잡고자 하였으나 그 손에서 벗어나 나가시니라"},{"n":40,"t":"다시 요단강 저편 요한이 처음으로 세례 주던 곳에 가사 거기 거하시니"},{"n":41,"t":"많은 사람이 왔다가 말하되 요한은 아무 표적도 행치 아니하였으나 요한이 이 사람을 가리켜 말한 것은 다 참이라 하더라"},{"n":42,"t":"그리하여 거기서 많은 사람이 예수를 믿으니라"}],"kids":[{"n":1,"t":"\\"진정으로 진정으로 너희에게 말한다. 양 우리에 문으로 들어가지 않고 다른 데로 넘어가는 사람은 도둑이며 강도다.\\""},{"n":2,"t":"\\"문으로 들어가는 사람이 양의 목자다.\\""},{"n":3,"t":"\\"문 지키는 사람이 그에게 문을 열어 주고 양들이 그의 음성을 듣고 그가 자기 양의 이름을 각각 불러 인도하여 나간다.\\""},{"n":4,"t":"\\"자기 양을 다 내놓은 후 그들 앞에 가니 양들이 그의 음성을 알아 그를 따른다.\\""},{"n":5,"t":"\\"다른 사람의 음성은 알지 못하므로 따르지 않고 도리어 도망친다\\" 하셨어요."},{"n":6,"t":"예수님이 이 비유로 말씀하셨지만 그들이 무엇을 말씀하시는지 깨닫지 못했어요."},{"n":7,"t":"예수님이 다시 \\"진정으로 진정으로 너희에게 말한다. 내가 양의 문이다.\\""},{"n":8,"t":"\\"나보다 먼저 온 사람은 다 도둑이고 강도다. 양들이 듣지 않았다.\\""},{"n":9,"t":"\\"내가 문이다. 누구든 나로 인해 들어가면 구원받고 들어가고 나가며 꼴을 얻을 거다.\\""},{"n":10,"t":"\\"도둑은 훔치고 죽이고 멸하려고만 온다. 내가 온 것은 양으로 생명을 얻게 하고 더 풍성히 얻게 하려는 거다.\\""},{"n":11,"t":"\\"나는 선한 목자다. 선한 목자는 양들을 위해 자기 목숨을 버린다.\\""},{"n":12,"t":"\\"목자가 아닌 고용된 일꾼은 양이 자기 것이 아니므로 늑대가 오는 것을 보면 양을 버리고 도망친다. 늑대가 양을 잡고 흩는다.\\""},{"n":13,"t":"\\"고용된 일꾼이라 양에 대해 관심이 없기 때문이다.\\""},{"n":14,"t":"\\"나는 선한 목자다. 내가 내 양을 알고 양도 나를 안다.\\""},{"n":15,"t":"\\"아버지께서 나를 아시고 내가 아버지를 아는 것 같다. 나는 양을 위해 목숨을 버린다.\\""},{"n":16,"t":"\\"이 우리에 들지 않은 다른 양들이 내게 있다. 그들도 내가 데려와야 한다. 그들도 내 음성을 들을 거고 한 무리, 한 목자가 될 거다.\\""},{"n":17,"t":"\\"내 아버지께서 나를 사랑하시는 것은 내가 목숨을 다시 얻으려고 버리기 때문이다.\\""},{"n":18,"t":"\\"누구도 내게서 빼앗지 못한다. 내가 스스로 버린다. 버릴 권세도 있고 다시 얻을 권세도 있다. 이 명령을 내 아버지께 받았다\\" 하셨어요."},{"n":19,"t":"이 말씀으로 인해 유대인 가운데 분쟁이 다시 일어났어요."},{"n":20,"t":"많은 사람이 \\"그가 귀신 들렸고 미쳤다. 왜 그의 말을 듣느냐?\\" 했어요."},{"n":21,"t":"어떤 사람은 \\"이는 귀신 들린 사람의 말이 아니다. 귀신이 맹인의 눈을 뜨게 할 수 있느냐?\\" 했어요."},{"n":22,"t":"예루살렘에 수전절이 있었어요. 그때가 겨울이었어요."},{"n":23,"t":"예수님이 성전 안 솔로몬 행각에서 거니셨어요."},{"n":24,"t":"유대인들이 둘러서서 \\"언제까지 우리 마음을 졸이게 하실 거예요? 당신이 그리스도면 명백히 말해 주세요\\" 했어요."},{"n":25,"t":"예수님이 \\"내가 너희에게 말했지만 너희가 믿지 않는다. 내가 내 아버지의 이름으로 행하는 일들이 나를 증언한다.\\""},{"n":26,"t":"\\"너희가 내 양이 아니므로 믿지 않는다.\\""},{"n":27,"t":"\\"내 양은 내 음성을 듣고 나는 그들을 알며 그들은 나를 따른다.\\""},{"n":28,"t":"\\"내가 그들에게 영생을 주고 영원히 멸망하지 않을 거고 그들을 내 손에서 빼앗을 사람이 없을 거다.\\""},{"n":29,"t":"\\"그들을 내게 주신 내 아버지는 만물보다 크시고 누구도 아버지의 손에서 빼앗을 수 없다.\\""},{"n":30,"t":"\\"나와 아버지는 하나다\\" 하셨어요."},{"n":31,"t":"유대인들이 다시 돌을 들어 치려 했어요."},{"n":32,"t":"예수님이 \\"내가 아버지에게서 온 많은 선한 일을 너희에게 보였다. 그중 어떤 일로 인해 돌로 치려 하느냐?\\" 하셨어요."},{"n":33,"t":"유대인들이 \\"선한 일로 인해 돌로 치려는 게 아니라 신성 모독 때문이다. 네가 사람이면서 자기를 하나님으로 만들기 때문이다\\" 했어요."},{"n":34,"t":"예수님이 \\"너희 율법에 \'내가 너희를 신이라 했다\' 기록되지 않았느냐?\\""},{"n":35,"t":"\\"성경은 폐할 수 없는데 하나님의 말씀을 받은 사람을 신이라 했다.\\""},{"n":36,"t":"\\"아버지께서 거룩하게 하시고 세상에 보내신 사람이 \'나는 하나님의 아들이다\' 하는 게 신성 모독이냐?\\""},{"n":37,"t":"\\"내 아버지의 일을 행하지 않으면 나를 믿지 마라.\\""},{"n":38,"t":"\\"그러나 행하면 비록 나를 믿지 않아도 그 일은 믿어라. 그래야 아버지께서 내 안에, 내가 아버지 안에 있는 줄을 알 거다\\" 하셨어요."},{"n":39,"t":"그들이 다시 잡으려 했지만 그분이 그 손에서 벗어나셨어요."},{"n":40,"t":"다시 요단강 건너편 요한이 처음 세례 주던 곳에 가셔서 거기 머무셨어요."},{"n":41,"t":"많은 사람이 그분께 와서 \\"요한은 아무 표적도 행하지 않았지만 이 사람에 대해 한 말은 다 참되었다\\" 했어요."},{"n":42,"t":"거기서 많은 사람이 그분을 믿었어요."}]}},{"chapter":11,"title":"나사로를 살리심","verses":{"krv":[{"n":1,"t":"어떤 병든 자가 있으니 이는 마리아와 그 형제 마르다의 촌 베다니에 사는 나사로라"},{"n":2,"t":"이 마리아는 향유를 주께 붓고 머리털로 주의 발을 씻기던 자요 병든 나사로는 그의 오라비러라"},{"n":3,"t":"이에 그 누이들이 예수께 사람을 보내어 가로되 주여 보시옵소서 사랑하시는 자가 병들었나이다 하니"},{"n":4,"t":"예수께서 들으시고 가라사대 이 병은 죽을 병이 아니라 하나님의 영광을 위함이요 하나님의 아들로 이를 인하여 영광을 얻게 하려함이라 하시더라"},{"n":5,"t":"예수께서 본래 마르다와 그 동생과 나사로를 사랑하시더니"},{"n":6,"t":"나사로가 병들었다 함을 들으시고 그 계시던 곳에 이틀을 더 유하시고"},{"n":7,"t":"그 후에 제자들에게 이르시되 유대로 다시 가자 하시니"},{"n":8,"t":"제자들이 말하되 랍비여 방금도 유대인들이 돌로 치려 하였는데 또 그리로 가시려 하나이까"},{"n":9,"t":"예수께서 대답하시되 낮이 열 두시가 아니냐 사람이 낮에 다니면 이 세상의 빛을 보므로 실족하지 아니하고"},{"n":10,"t":"밤에 다니면 빛이 그 사람 안에 없는고로 실족하느니라"},{"n":11,"t":"이 말씀을 하신 후에 또 가라사대 우리 친구 나사로가 잠들었도다 그러나 내가 깨우러 가노라"},{"n":12,"t":"제자들이 가로되 주여 잠들었으면 낫겠나이다 하더라"},{"n":13,"t":"예수는 그의 죽음을 가리켜 말씀하신 것이나 저희는 잠들어 쉬는것을 가리켜 말씀하심인줄 생각하는지라"},{"n":14,"t":"이에 예수께서 밝히 이르시되 나사로가 죽었느니라"},{"n":15,"t":"내가 거기 있지 아니한 것을 너희를 위하여 기뻐하노니 이는 너희로 믿게 하려함이라 그러나 그에게로 가자 하신대"},{"n":16,"t":"디두모라 하는 도마가 다른 제자들에게 말하되 우리도 주와 함께 죽으러 가자 하니라"},{"n":17,"t":"예수께서 와서 보시니 나사로가 무덤에 있은지 이미 나흘이라"},{"n":18,"t":"베다니는 예루살렘에서 가깝기가 한 오 리쯤 되매"},{"n":19,"t":"많은 유대인이 마르다와 마리아에게 그 오라비의 일로 위문하러 왔더니"},{"n":20,"t":"마르다는 예수 오신다는 말을 듣고 곧 나가 맞되 마리아는 집에 앉았더라"},{"n":21,"t":"마르다가 예수께 여짜오되 주께서 여기 계셨더면 내 오라비가 죽지 아니하였겠나이다"},{"n":22,"t":"그러나 나는 이제라도 주께서 무엇이든지 하나님께 구하시는 것을 하나님이 주실 줄을 아나이다"},{"n":23,"t":"예수께서 가라사대 네 오라비가 다시 살리라"},{"n":24,"t":"마르다가 가로되 마지막 날 부활에는 다시 살 줄을 내가 아나이다"},{"n":25,"t":"예수께서 가라사대 나는 부활이요 생명이니 나를 믿는 자는 죽어도 살겠고"},{"n":26,"t":"무릇 살아서 나를 믿는 자는 영원히 죽지 아니하리니 이것을 네가 믿느냐"},{"n":27,"t":"가로되 주여 그러하외다 주는 그리스도시요 세상에 오시는 하나님의 아들이신줄 내가 믿나이다"},{"n":28,"t":"이 말을 하고 돌아가서 가만히 그 형제 마리아를 불러 말하되 선생님이 오셔서 너를 부르신다 하니"},{"n":29,"t":"마리아가 이 말을 듣고 급히 일어나 예수께 나아가매"},{"n":30,"t":"예수는 아직 마을로 들어오지 아니하시고 마르다의 맞던 곳에 그저 계시더라"},{"n":31,"t":"마리아와 함께 집에 있어 위로하던 유대인들은 그의 급히 일어나 나가는 것을 보고 곡하러 무덤에 가는 줄로 생각하고 따라가더니"},{"n":32,"t":"마리아가 예수 계신 곳에 와서 보이고 그 발 앞에 엎드리어 가로되 주께서 여기 계셨더면 내 오라비가 죽지 아니하였겠나이다 하더라"},{"n":33,"t":"예수께서 그의 우는 것과 또 함께 온 유대인들의 우는 것을 보시고 심령에 통분히 여기시고 민망히 여기사"},{"n":34,"t":"가라사대 그를 어디 두었느냐 가로되 주여 와서 보옵소서 하니"},{"n":35,"t":"예수께서 눈물을 흘리시더라"},{"n":36,"t":"이에 유대인들이 말하되 보라 그를 어떻게 사랑하였는가 하며"},{"n":37,"t":"그 중 어떤이는 말하되 소경의 눈을 뜨게 한 이 사람이 그 사람은 죽지 않게 할 수 없었더냐 하더라"},{"n":38,"t":"이에 예수께서 다시 속으로 통분히 여기시며 무덤에 가시니 무덤이 굴이라 돌로 막았거늘"},{"n":39,"t":"예수께서 가라사대 돌을 옮겨 놓으라 하시니 그 죽은 자의 누이 마르다가 가로되 주여 죽은 지가 나흘이 되었으매 벌써 냄새가 나나이다"},{"n":40,"t":"예수께서 가라사대 내 말이 네가 믿으면 하나님의 영광을 보리라 하지 아니하였느냐 하신대"},{"n":41,"t":"돌을 옮겨 놓으니 예수께서 눈을 들어 우러러 보시고 가라사대 아버지여 내 말을 들으신 것을 감사하나이다"},{"n":42,"t":"항상 내 말을 들으시는 줄을 내가 알았나이다 그러나 이 말씀 하옵는 것은 둘러선 무리를 위함이니 곧 아버지께서 나를 보내신 것을 저희로 믿게 하려 함이니이다"},{"n":43,"t":"이 말씀을 하시고 큰 소리로 나사로야 나오라 부르시니"},{"n":44,"t":"죽은 자가 수족을 베로 동인채로 나오는데 그 얼굴은 수건에 싸였더라 예수께서 가라사대 풀어 놓아 다니게 하라 하시니라"},{"n":45,"t":"마리아에게 와서 예수의 하신 일을 본 많은 유대인이 저를 믿었으나"},{"n":46,"t":"그 중에 어떤 자는 바리새인들에게 가서 예수의 하신 일을 고하니라"},{"n":47,"t":"이에 대제사장들과 바리새인들이 공회를 모으고 가로되 이 사람이 많은 표적을 행하니 우리가 어떻게 하겠느냐"},{"n":48,"t":"만일 저를 이대로 두면 모든 사람이 저를 믿을 것이요 그리고 로마인들이 와서 우리 땅과 민족을 빼앗아 가리라 하니"},{"n":49,"t":"그 중에 한 사람 그 해 대제사장인 가야바가 저희에게 말하되 너희가 아무 것도 알지 못하는도다"},{"n":50,"t":"한 사람이 백성을 위하여 죽어서 온 민족이 망하지 않게 되는 것이 너희에게 유익한 줄을 생각지 아니하는도다 하였으니"},{"n":51,"t":"이 말은 스스로 함이 아니요 그 해에 대제사장이므로 예수께서 그 민족을 위하시고"},{"n":52,"t":"또 그 민족만 위할뿐 아니라 흩어진 하나님의 자녀를 모아 하나가 되게 하기 위하여 죽으실 것을 미리 말함이러라"},{"n":53,"t":"이날부터는 저희가 예수를 죽이려고 모의하니라"},{"n":54,"t":"그러므로 예수께서 다시 유대인 가운데 드러나게 다니지 아니하시고 여기를 떠나 빈 들 가까운 곳인 에브라임이라는 동리에 가서 제자들과 함께 거기 유하시니라"},{"n":55,"t":"유대인의 유월절이 가까우매 많은 사람이 자기를 성결케 하기 위하여 유월절 전에 시골서 예루살렘으로 올라갔더니"},{"n":56,"t":"저희가 예수를 찾으며 성전에 서서 서로 말하되 너희 생각에는 어떠하뇨 저가 명절에 오지 아니하겠느냐 하니"},{"n":57,"t":"이는 대제사장들과 바리새인들이 누구든지 예수 있는 곳을 알거든 고하여 잡게 하라 명령하였음이러라"}],"kids":[{"n":1,"t":"베다니에 나사로라는 사람이 병들어 있었어요. 그는 마리아와 그 동생 마르다의 동네 사람이에요."},{"n":2,"t":"이 마리아는 주께 향유를 부었고 자기 머리카락으로 그분의 발을 닦았던 사람이고 그녀의 오빠 나사로가 병들었어요."},{"n":3,"t":"누이들이 예수님께 사람을 보내 \\"주여, 보세요, 주께서 사랑하시는 사람이 병들었어요\\" 했어요."},{"n":4,"t":"예수님이 듣고 \\"이 병은 죽음으로 끝나는 게 아니라 하나님의 영광을 위한 거다. 하나님의 아들이 이로 인해 영광을 받게 하려는 거다\\" 하셨어요."},{"n":5,"t":"예수님이 마르다와 그 동생과 나사로를 사랑하셨어요."},{"n":6,"t":"나사로가 병들었다는 말을 들으시고도 그 계신 곳에서 이틀 더 머무셨어요."},{"n":7,"t":"그 후 제자들에게 \\"다시 유대로 가자\\" 하셨어요."},{"n":8,"t":"제자들이 \\"랍비여, 방금 유대인들이 돌로 치려 했는데 또 그리로 가실 거예요?\\" 했어요."},{"n":9,"t":"예수님이 \\"낮이 열두 시간 아니냐? 낮에 다니는 사람은 이 세상의 빛을 보기 때문에 걸려 넘어지지 않는다.\\""},{"n":10,"t":"\\"밤에 다니는 사람은 자기 안에 빛이 없으므로 걸려 넘어진다\\" 하셨어요."},{"n":11,"t":"이 말씀을 하시고 \\"우리 친구 나사로가 잠들어 있다. 깨우러 간다\\" 하셨어요."},{"n":12,"t":"제자들이 \\"주여, 잠들었다면 살아날 거예요\\" 했어요."},{"n":13,"t":"예수님은 그의 죽음에 대해 말씀하셨는데 그들은 잠자는 것에 대해 말씀하시는 줄로 알았어요."},{"n":14,"t":"예수님이 분명히 \\"나사로가 죽었다.\\""},{"n":15,"t":"\\"내가 거기 없었던 것을 너희를 위해 기뻐한다. 너희가 믿게 하려는 거다. 그러나 그에게 가자\\" 하셨어요."},{"n":16,"t":"디두모라 하는 도마가 다른 제자들에게 \\"우리도 가서 함께 죽자\\" 했어요."},{"n":17,"t":"예수님이 가서 보니 나사로가 이미 무덤에 있은 지 나흘이 되었어요."},{"n":18,"t":"베다니는 예루살렘에서 15스타디온쯤 떨어진 곳이에요."},{"n":19,"t":"많은 유대인이 마르다와 마리아에게 그 오빠 때문에 위로하러 와 있었어요."},{"n":20,"t":"마르다는 예수님이 오신다는 말을 듣고 만나러 갔고 마리아는 집에 앉아 있었어요."},{"n":21,"t":"마르다가 예수님께 \\"주여, 여기 계셨더라면 내 오빠가 죽지 않았을 거예요.\\""},{"n":22,"t":"\\"그러나 지금이라도 주께서 하나님께 무엇을 구하시든 하나님이 주실 줄 알아요\\" 했어요."},{"n":23,"t":"예수님이 \\"네 오빠가 다시 살아날 거다\\" 하셨어요."},{"n":24,"t":"마르다가 \\"마지막 날 부활 때 다시 살아날 줄 알아요\\" 했어요."},{"n":25,"t":"예수님이 \\"나는 부활이요 생명이다. 나를 믿는 사람은 죽어도 살 거다.\\""},{"n":26,"t":"\\"살아서 나를 믿는 사람은 영원히 죽지 않을 거다. 이것을 믿느냐?\\" 하셨어요."},{"n":27,"t":"마르다가 \\"네, 주여. 주는 세상에 오실 그리스도, 하나님의 아들이심을 믿어요\\" 했어요."},{"n":28,"t":"이 말을 하고 가서 자기 동생 마리아를 가만히 불러 \\"선생님이 오셨고 너를 부르신다\\" 했어요."},{"n":29,"t":"마리아가 듣고 곧 일어나 그분께 갔어요."},{"n":30,"t":"예수님이 아직 동네에 들어가지 않으시고 마르다가 만난 곳에 계셨어요."},{"n":31,"t":"집에서 마리아와 함께 있던 위로하던 유대인들이 그녀가 일어나 빨리 나가는 것을 보고 무덤에 울러 가는 줄로 알고 따라갔어요."},{"n":32,"t":"마리아가 예수님이 계신 곳에 와서 보고 발 앞에 엎드려 \\"주여, 여기 계셨더라면 내 오빠가 죽지 않았을 거예요\\" 했어요."},{"n":33,"t":"예수님이 그녀가 우는 것과 함께 온 유대인들도 우는 것을 보시고 심령에 비통히 여기시고 괴로워하셨어요."},{"n":34,"t":"\\"그를 어디 두었느냐?\\" 하니 \\"주여, 와서 보세요\\" 했어요."},{"n":35,"t":"예수님이 우셨어요."},{"n":36,"t":"유대인들이 \\"보세요, 그를 얼마나 사랑하셨는지!\\" 했어요."},{"n":37,"t":"그중 어떤 사람은 \\"맹인의 눈을 뜨게 하신 이분이 이 사람도 죽지 않게 할 수 없었나?\\" 했어요."},{"n":38,"t":"예수님이 다시 마음에 비통하시며 무덤에 오셨어요. 그것은 굴이었고 돌로 막혀 있었어요."},{"n":39,"t":"\\"돌을 옮겨라\\" 하시니 죽은 자의 누이 마르다가 \\"주여, 죽은 지 나흘이 되어 이미 냄새가 나요\\" 했어요."},{"n":40,"t":"예수님이 \\"네가 믿으면 하나님의 영광을 볼 거라고 너에게 말하지 않았느냐?\\" 하셨어요."},{"n":41,"t":"돌을 옮기니 예수님이 눈을 들어 \\"아버지여, 내 말을 들어 주심을 감사해요.\\""},{"n":42,"t":"\\"아버지께서 항상 내 말을 들으시는 줄을 아는데 둘러선 무리를 위해 말씀드려요. 아버지께서 나를 보내신 것을 그들이 믿게 하려는 거예요\\" 하셨어요."},{"n":43,"t":"이 말씀을 하시고 큰 소리로 \\"나사로야, 나오너라!\\" 하셨어요."},{"n":44,"t":"죽었던 사람이 손과 발이 천에 묶이고 얼굴이 수건에 싸인 채로 나왔어요. 예수님이 \\"풀어 가게 해라\\" 하셨어요."},{"n":45,"t":"마리아에게 와서 예수님이 행하신 일을 본 많은 유대인이 그분을 믿었어요."},{"n":46,"t":"그러나 그중 어떤 사람은 바리새인들에게 가서 예수님이 행하신 일을 알렸어요."},{"n":47,"t":"대제사장과 바리새인들이 공회를 모으고 \\"이 사람이 많은 표적을 행하니 어떻게 할까?\\""},{"n":48,"t":"\\"이대로 두면 모든 사람이 그를 믿을 거고 로마인이 와서 우리 땅과 민족을 빼앗을 거다\\" 했어요."},{"n":49,"t":"그중 한 사람, 그 해 대제사장인 가야바가 \\"너희가 아무것도 모르는구나.\\""},{"n":50,"t":"\\"한 사람이 백성을 위해 죽어 온 민족이 망하지 않게 하는 게 너희에게 유익한 줄을 생각하지 못하는구나\\" 했어요."},{"n":51,"t":"이는 스스로 한 말이 아니에요. 그 해의 대제사장으로서 예수님이 그 민족을 위해 죽으실 것을 예언한 거예요."},{"n":52,"t":"이 민족뿐 아니라 흩어진 하나님의 자녀를 모아 하나가 되게 하시려고요."},{"n":53,"t":"그날부터 그들이 예수님을 죽이려 의논했어요."},{"n":54,"t":"예수님이 다시는 유대인 가운데 드러나게 다니지 않으시고 광야에 가까운 동네 에브라임으로 가서 거기 제자들과 머무셨어요."},{"n":55,"t":"유대인의 유월절이 가까웠어요. 많은 사람이 자기를 정결하게 하려고 명절 전에 시골에서 예루살렘으로 올라갔어요."},{"n":56,"t":"그들이 예수님을 찾으며 성전에 서서 서로 \\"너희 생각에는 어떠하냐? 그가 명절에 오지 않을 것 같으냐?\\" 했어요."},{"n":57,"t":"대제사장과 바리새인들이 누구든 그분이 어디 있는 줄을 알면 신고하여 잡게 하라고 명령해 두었거든요."}]}},{"chapter":12,"title":"예루살렘 입성과 헬라인의 방문","verses":{"krv":[{"n":1,"t":"유월절 엿새 전에 예수께서 베다니에 이르시니 이곳은 예수께서 죽은 자 가운데서 살리신 나사로의 있는 곳이라"},{"n":2,"t":"거기서 예수를 위하여 잔치할새 마르다는 일을 보고 나사로는 예수와 함께 앉은자 중에 있더라"},{"n":3,"t":"마리아는 지극히 비싼 향유 곧 순전한 나드 한 근을 가져다가 예수의 발에 붓고 자기 머리털로 그의 발을 씻으니 향유 냄새가 집에 가득하더라"},{"n":4,"t":"제자 중 하나로서 예수를 잡아 줄 가룟 유다가 말하되"},{"n":5,"t":"이 향유를 어찌하여 삼백 데나리온에 팔아 가난한 자들에게 주지 아니하였느냐 하니"},{"n":6,"t":"이렇게 말함은 가난한 자들을 생각함이 아니요 저는 도적이라 돈 궤를 맡고 거기 넣는 것을 훔쳐 감이러라"},{"n":7,"t":"예수께서 가라사대 저를 가만 두어 나의 장사 할 날을 위하여 이를두게 하라"},{"n":8,"t":"가난한 자들은 항상 너희와 함께 있거니와 나는 항상 있지 아니하리라 하시니라"},{"n":9,"t":"유대인의 큰 무리가 예수께서 여기 계신줄을 알고 오니 이는 예수만 위함이 아니요 죽은 자 가운데서 살리신 나사로도 보려 함이러라"},{"n":10,"t":"대제사장들이 나사로까지 죽이려고 모의하니"},{"n":11,"t":"나사로 까닭에 많은 유대인이 가서 예수를 믿음이러라"},{"n":12,"t":"그 이튿날에는 명절에 온 큰 무리가 예수께서 예루살렘으로 오신다 함을 듣고"},{"n":13,"t":"종려나무 가지를 가지고 맞으러 나가 외치되 호산나 찬송하리로다 주의 이름으로 오시는 이 곧 이스라엘의 왕이시여 하더라"},{"n":14,"t":"예수는 한 어린 나귀를 만나서 타시니"},{"n":15,"t":"이는 기록된바 시온 딸아 두려워 말라 보라 너의 왕이 나귀 새끼를 타고 오신다 함과 같더라"},{"n":16,"t":"제자들은 처음에 이 일을 깨닫지 못하였다가 예수께서 영광을 얻으신 후에야 이것이 예수께 대하여 기록된 것임과 사람들이 예수께 이같이 한것인줄 생각났더라"},{"n":17,"t":"나사로를 무덤에서 불러내어 죽은 자 가운데서 살리실 때에 함께 있던 무리가 증거한지라"},{"n":18,"t":"이에 무리가 예수를 맞음은 이 표적 행하심을 들었음이러라"},{"n":19,"t":"바리새인들이 서로 말하되 볼지어다 너희 하는 일이 쓸 데 없다 보라 온 세상이 저를 좇는도다 하니라"},{"n":20,"t":"명절에 예배하러 올라온 사람 중에 헬라인 몇이 있는데"},{"n":21,"t":"저희가 갈릴리 벳새다 사람 빌립에게 가서 청하여 가로되 선생이여 우리가 예수를 뵈옵고자 하나이다 하니"},{"n":22,"t":"빌립이 안드레에게 가서 말하고 안드레와 빌립이 예수께 가서 여짜온대"},{"n":23,"t":"예수께서 대답하여 가라사대 인자의 영광을 얻을 때가 왔도다"},{"n":24,"t":"내가 진실로 진실로 너희에게 이르노니 한 알의 밀이 땅에 떨어져 죽지 아니하면 한 알 그대로 있고 죽으면 많은 열매를 맺느니라"},{"n":25,"t":"자기 생명을 사랑하는 자는 잃어버릴 것이요 이 세상에서 자기 생명을 미워하는 자는 영생하도록 보존하리라"},{"n":26,"t":"사람이 나를 섬기려면 나를 따르라 나 있는 곳에 나를 섬기는 자도 거기 있으리니 사람이 나를 섬기면 내 아버지께서 저를 귀히 여기시리라"},{"n":27,"t":"지금 내 마음이 민망하니 무슨 말을 하리요 아버지여 나를 구원하여 이 때를 면하게 하여 주옵소서 그러나 내가 이를 위하여 이 때에 왔나이다"},{"n":28,"t":"아버지여 아버지의 이름을 영광스럽게 하옵소서 하시니 이에 하늘에서 소리가 나서 가로되 내가 이미 영광스럽게 하였고 또 다시 영광스럽게 하리라 하신대"},{"n":29,"t":"곁에 서서 들은 무리는 우뢰가 울었다고도 하며 또 어떤이들은 천사가 저에게 말하였다고도 하니"},{"n":30,"t":"예수께서 대답하여 가라사대 이 소리가 난 것은 나를 위한 것이 아니요 너희를 위한 것이니라"},{"n":31,"t":"이제 이 세상의 심판이 이르렀으니 이 세상 임금이 쫓겨나리라"},{"n":32,"t":"내가 땅에서 들리면 모든 사람을 내게로 이끌겠노라 하시니"},{"n":33,"t":"이렇게 말씀하심은 자기가 어떠한 죽음으로 죽을 것을 보이심이러라"},{"n":34,"t":"이에 무리가 대답하되 우리는 율법에서 그리스도가 영원히 계신다 함을 들었거늘 너는 어찌하여 인자가 들려야 하리라 하느냐 이 인자는 누구냐"},{"n":35,"t":"예수께서 가라사대 아직 잠시 동안 빛이 너희 중에 있으니 빛이 있을 동안에 다녀 어두움에 붙잡히지 않게 하라 어두움에 다니는자는 그 가는 바를 알지 못하느니라"},{"n":36,"t":"너희에게 아직 빛이 있을 동안에 빛을 믿으라 그리하면 빛의 아들이 되리라 예수께서 이 말씀을 하시고 저희를 떠나가서 숨으시니라"},{"n":37,"t":"이렇게 많은 표적을 저희 앞에서 행하셨으나 저를 믿지 아니하니"},{"n":38,"t":"이는 선지자 이사야의 말씀을 이루려 하심이라 가로되 주여 우리에게 들은 바를 누가 믿었으며 주의 팔이 뉘게 나타났나이까 하였더라"},{"n":39,"t":"저희가 능히 믿지 못한 것은 이 까닭이니 곧 이사야가 다시 일렀으되"},{"n":40,"t":"저희 눈을 멀게 하시고 저희 마음을 완고하게 하셨으니 이는 저희로 하여금 눈으로 보고 마음으로 깨닫고 돌이켜 내게 고침을 받지 못하게 하려 함이니라 하였음이더라"},{"n":41,"t":"이사야가 이렇게 말한 것은 주의 영광을 보고 주를 가리켜 말한 것이라"},{"n":42,"t":"그러나 관원 중에도 저를 믿는 자가 많되 바리새인들을 인하여 드러나게 말하지 못하니 이는 출회를 당할까 두려워함이라"},{"n":43,"t":"저희는 사람의 영광을 하나님의 영광보다 더 사랑하였더라"},{"n":44,"t":"예수께서 외쳐 가라사대 나를 믿는 자는 나를 믿는 것이 아니요 나를 보내신 이를 믿는 것이며"},{"n":45,"t":"나를 보는 자는 나를 보내신 이를 보는 것이니라"},{"n":46,"t":"나는 빛으로 세상에 왔나니 무릇 나를 믿는 자로 어두움에 거하 지 않게 하려 함이로라"},{"n":47,"t":"사람이 내 말을 듣고 지키지 아니할지라도 내가 저를 심판하지 아니하노라 내가 온 것은 세상을 심판하려 함이 아니요 세상을 구원하려 함이로라"},{"n":48,"t":"나를 저버리고 내 말을 받지 아니하는 자를 심판할 이가 있으니 곧 나의 한 그 말이 마지막 날에 저를 심판하리라"},{"n":49,"t":"내가 내 자의로 말한 것이 아니요 나를 보내신 아버지께서 나의 말할 것과 이를 것을 친히 명령하여 주셨으니"},{"n":50,"t":"나는 그의 명령이 영생인줄 아노라 그러므로 나의 이르는 것은 내 아버지께서 내게 말씀하신 그대로 이르노라 하시니라"}],"kids":[{"n":1,"t":"유월절 엿새 전 예수님이 베다니에 오셨어요. 거기는 죽은 자 가운데서 살리신 나사로가 있는 곳이에요."},{"n":2,"t":"거기서 예수님을 위해 잔치를 마련했어요. 마르다는 시중을 들고 나사로는 함께 앉은 사람 중에 있었어요."},{"n":3,"t":"마리아가 매우 값진 순전한 나드 한 근을 가져다 예수님의 발에 붓고 자기 머리카락으로 닦으니 향기가 집에 가득했어요."},{"n":4,"t":"그분을 넘길 제자 중 하나, 가룟 유다가,"},{"n":5,"t":"\\"이 향유를 삼백 데나리온에 팔아 가난한 사람들에게 주지 않았어?\\" 했어요."},{"n":6,"t":"그가 이렇게 말한 것은 가난한 사람을 생각해서가 아니라 도둑이기 때문이에요. 돈주머니를 맡고 거기 있는 것을 훔쳤어요."},{"n":7,"t":"예수님이 \\"그녀를 두어라. 내 장사할 날을 위해 간직한 거다.\\""},{"n":8,"t":"\\"가난한 사람은 늘 너희와 함께 있겠지만 나는 늘 함께 있지 않을 거다\\" 하셨어요."},{"n":9,"t":"유대인의 큰 무리가 예수님이 거기 계신 줄을 알고 왔는데 예수님 때문만 아니라 그분이 죽은 자 가운데서 살리신 나사로를 보려고요."},{"n":10,"t":"대제사장들이 나사로도 죽이려고 의논했어요."},{"n":11,"t":"그로 인해 많은 유대인이 떠나가 예수님을 믿었기 때문이에요."},{"n":12,"t":"이튿날 명절에 온 큰 무리가 예수님이 예루살렘에 오신다는 말을 듣고,"},{"n":13,"t":"종려나무 가지를 가지고 마중하러 나가 외쳤어요. \\"호산나! 주의 이름으로 오시는 분, 이스라엘의 왕에게 복이 있다!\\""},{"n":14,"t":"예수님이 어린 나귀를 보시고 그 위에 앉으셨어요. 기록된 것 같이요."},{"n":15,"t":"\\"시온의 딸아, 두려워 마라. 보라, 네 왕이 어린 나귀를 타고 오신다.\\""},{"n":16,"t":"제자들은 처음에는 이 일을 깨닫지 못했지만 예수님이 영광을 받으신 후에야 이 일이 그분에 대해 기록된 것과 사람들이 그분께 그렇게 행한 것을 기억했어요."},{"n":17,"t":"예수님이 나사로를 무덤에서 불러 죽은 자 가운데서 살리실 때 함께 있던 무리가 증언했어요."},{"n":18,"t":"이 표적을 행하신 것을 들었으므로 무리가 그분을 맞으러 나간 거예요."},{"n":19,"t":"바리새인들이 서로 \\"보라, 너희가 어떻게 해도 소용없다. 보라, 온 세상이 그를 따라간다\\" 했어요."},{"n":20,"t":"명절에 예배하러 올라온 사람 중에 헬라인 몇이 있었어요."},{"n":21,"t":"그들이 갈릴리 벳새다 사람 빌립에게 와서 \\"선생님, 우리가 예수를 뵙고 싶어요\\" 했어요."},{"n":22,"t":"빌립이 안드레에게 알리고 안드레와 빌립이 예수님께 알렸어요."},{"n":23,"t":"예수님이 \\"사람의 아들이 영광을 받을 때가 왔다.\\""},{"n":24,"t":"\\"진정으로 진정으로 너희에게 말한다. 한 알의 밀이 땅에 떨어져 죽지 않으면 한 알로 그대로 있지만 죽으면 많은 열매를 맺는다.\\""},{"n":25,"t":"\\"자기 목숨을 사랑하는 사람은 잃고 이 세상에서 자기 목숨을 미워하는 사람은 영원한 생명으로 보존할 거다.\\""},{"n":26,"t":"\\"누구든 나를 섬기려면 나를 따라야 한다. 내가 있는 곳에 내 종도 있을 거다. 누구든 나를 섬기면 아버지께서 그를 영광스럽게 하실 거다\\" 하셨어요."},{"n":27,"t":"\\"지금 내 영혼이 답답하다. 무슨 말을 할까? \'아버지여, 이 때에서 나를 구원하소서\' 할까? 그러나 이 때를 위해 내가 왔다.\\""},{"n":28,"t":"\\"아버지여, 아버지의 이름을 영광스럽게 하소서!\\" 하늘에서 소리가 났어요. \\"내가 영광스럽게 했고 또다시 영광스럽게 할 거다.\\""},{"n":29,"t":"옆에 서서 들은 무리가 \\"천둥이 쳤다\\" 했고 어떤 사람은 \\"천사가 그에게 말했다\\" 했어요."},{"n":30,"t":"예수님이 \\"이 소리는 나를 위해서가 아니라 너희를 위해 났다.\\""},{"n":31,"t":"\\"이제 이 세상에 대한 심판이 임했다. 이제 이 세상의 임금이 쫓겨날 거다.\\""},{"n":32,"t":"\\"내가 땅에서 들리면 모든 사람을 내게로 이끌어 올 거다\\" 하셨어요."},{"n":33,"t":"이는 자기가 어떤 죽음으로 죽을 것을 보이려고 하신 말씀이에요."},{"n":34,"t":"무리가 \\"우리는 율법에서 그리스도가 영원히 계신다고 들었는데 어찌하여 사람의 아들이 들려야 한다 하세요? 이 사람의 아들이 누구세요?\\" 했어요."},{"n":35,"t":"예수님이 \\"빛이 너희 가운데 잠시 있다. 빛이 있을 때 다녀라. 어둠이 너희에게 임하지 않게 하라. 어둠에 다니는 사람은 자기가 어디로 가는지 모른다.\\""},{"n":36,"t":"\\"빛이 있는 동안 빛을 믿어라. 그래야 빛의 자녀가 될 거다.\\" 예수님이 이 말씀을 하시고 떠나 그들에게서 숨으셨어요."},{"n":37,"t":"그분이 그들 앞에서 많은 표적을 행하셨지만 그들이 그분을 믿지 않았어요."},{"n":38,"t":"이사야 예언자의 말씀이 이루어졌어요. \\"주여, 우리에게 들은 것을 누가 믿었습니까? 주의 팔이 누구에게 나타났습니까?\\""},{"n":39,"t":"이로 인해 그들이 믿을 수 없었어요. 이사야가 또 말했기 때문이에요."},{"n":40,"t":"\\"그분이 그들의 눈을 멀게 하고 그들의 마음을 굳게 하여 눈으로 보지 못하고 마음으로 깨닫지 못하게 하셨다. 그래야 그들이 돌이켜 내가 고치지 않으리라.\\""},{"n":41,"t":"이사야가 이렇게 말한 것은 그분의 영광을 보고 그에 대해 말한 거예요."},{"n":42,"t":"관원 중에도 그분을 믿는 사람이 많았지만 바리새인들로 인해 드러내 말하지 못했어요. 회당에서 쫓겨날까 두려웠기 때문이에요."},{"n":43,"t":"하나님의 영광보다 사람의 영광을 더 사랑했기 때문이에요."},{"n":44,"t":"예수님이 외쳤어요. \\"나를 믿는 사람은 나를 믿는 게 아니라 나를 보내신 분을 믿는 거다.\\""},{"n":45,"t":"\\"나를 보는 사람은 나를 보내신 분을 보는 거다.\\""},{"n":46,"t":"\\"나는 빛으로 세상에 왔다. 누구든 나를 믿으면 어둠에 머물지 않게 하려는 거다.\\""},{"n":47,"t":"\\"누가 내 말을 듣고 지키지 않아도 나는 그를 심판하지 않는다. 내가 세상을 심판하러 온 게 아니라 구원하러 왔기 때문이다.\\""},{"n":48,"t":"\\"나를 거부하고 내 말을 받지 않는 사람을 심판할 분이 있다. 곧 내가 한 말이 마지막 날에 그를 심판할 거다.\\""},{"n":49,"t":"\\"나는 스스로 말하지 않았고 나를 보내신 아버지께서 무엇을 말하고 무엇을 이를지 친히 내게 명령하셨다.\\""},{"n":50,"t":"\\"나는 그분의 명령이 영생인 줄 안다. 그러므로 내가 하는 말은 아버지께서 내게 말씀하신 대로 한다\\" 하셨어요."}]}},{"chapter":13,"title":"발을 씻기시고 새 계명을 주심","verses":{"krv":[{"n":1,"t":"유월절 전에 예수께서 자기가 세상을 떠나 아버지께로 돌아가실 때가 이른줄 아시고 세상에 있는 자기 사람들을 사랑하시되 끝까지 사랑하시니라"},{"n":2,"t":"마귀가 벌써 시몬의 아들 가룟 유다의 마음에 예수를 팔려는 생각을 넣었더니"},{"n":3,"t":"저녁 먹는 중 예수는 아버지께서 모든 것을 자기 손에 맡기신 것과 또 자기가 하나님께로부터 오셨다가 하나님께로 돌아가실 것을 아시고"},{"n":4,"t":"저녁 잡수시던 자리에서 일어나 겉옷을 벗고 수건을 가져다가 허리에 두르시고"},{"n":5,"t":"이에 대야에 물을 담아 제자들의 발을 씻기시고 그 두르신 수건으로 씻기기를 시작하여"},{"n":6,"t":"시몬 베드로에게 이르시니 가로되 주여 주께서 내 발을 씻기시나이까"},{"n":7,"t":"예수께서 대답하여 가라사대 나의 하는 것을 네가 이제는 알지 못하나 이 후에는 알리라"},{"n":8,"t":"베드로가 가로되 내 발을 절대로 씻기지 못하시리이다 예수께서 대답하시되 내가 너를 씻기지 아니하면 네가 나와 상관이 없느니라"},{"n":9,"t":"시몬 베드로가 가로되 주여 내 발 뿐아니라 손과 머리도 씻겨 주옵소서"},{"n":10,"t":"예수께서 가라사대 이미 목욕한 자는 발 밖에 씻을 필요가 없느니라 온 몸이 깨끗하니라 너희가 깨끗하나 다는 아니니라 하시니"},{"n":11,"t":"이는 자기를 팔 자가 누구인지 아심이라 그러므로 다는 깨끗지 아니하다 하시니라"},{"n":12,"t":"저희 발을 씻기신 후에 옷을 입으시고 다시 앉아 저희에게 이르시되 내가 너희에게 행한 것을 너희가 아느냐"},{"n":13,"t":"너희가 나를 선생이라 또는 주라 하니 너희 말이 옳도다 내가 그러하다"},{"n":14,"t":"내가 주와 또는 선생이 되어 너희 발을 씻겼으니 너희도 서로 발을 씻기는 것이 옳으니라"},{"n":15,"t":"내가 너희에게 행한것 같이 너희도 행하게 하려하여 본을 보였노라"},{"n":16,"t":"내가 진실로 진실로 너희에게 이르노니 종이 상전보다 크지 못하고 보냄을 받은 자가 보낸 자보다 크지 못하니"},{"n":17,"t":"너희가 이것을 알고 행하면 복이 있으리라"},{"n":18,"t":"내가 너희를 다 가리켜 말하는 것이 아니라 내가 나의 택한 자들이 누구인지 앎이라 그러나 내 떡을 먹는 자가 내게 발꿈치를 들었다 한 성경을 응하게 하려는 것이니라"},{"n":19,"t":"지금부터 일이 이루기 전에 미리 너희에게 이름은 일이 이룰 때에 내가 그인줄 너희로 믿게 하려 함이로라"},{"n":20,"t":"내가 진실로 진실로 너희에게 이르노니 나의 보낸 자를 영접하는 자는 나를 영접하는 것이요 나를 영접하는 자는 나를 보내신 이를 영접하는 것이니라"},{"n":21,"t":"예수께서 이 말씀을 하시고 심령에 민망하여 증거하여 가라사대 내가 진실로 진실로 너희에게 이르노니 너희 중 하나가 나를 팔리라 하시니"},{"n":22,"t":"제자들이 서로 보며 뉘게 대하여 말씀하시는지 의심하더라"},{"n":23,"t":"예수의 제자 중 하나 곧 그의 사랑하시는 자가 예수의 품에 의지하여 누웠는지라"},{"n":24,"t":"시몬 베드로가 머릿짓을 하여 말하되 말씀하신 자가 누구인지 말하라 한대"},{"n":25,"t":"그가 예수의 가슴에 그대로 의지하여 말하되 주여 누구오니이까"},{"n":26,"t":"예수께서 대답하시되 내가 한 조각을 찍어다가 주는 자가 그니라 하시고 곧 한 조각을 찍으셔다가 가룟 시몬의 아들 유다를 주시니"},{"n":27,"t":"조각을 받은 후 곧 사단이 그 속에 들어간지라 이에 예수께서 유다에게 이르시되 네 하는 일을 속히 하라 하시니"},{"n":28,"t":"이 말씀을 무슨 뜻으로 하셨는지 그 앉은 자 중에 아는 이가 없고"},{"n":29,"t":"어떤이들은 유다가 돈 궤를 맡았으므로 명절에 우리의 쓸 물건을 사라 하시는지 혹 가난한 자들에게 무엇을 주라 하시는 줄로 생각하더라"},{"n":30,"t":"유다가 그 조각을 받고 곧 나가니 밤이러라"},{"n":31,"t":"저가 나간 후에 예수께서 가라사대 지금 인자가 영광을 얻었고 하나님도 인자를 인하여 영광을 얻으셨도다"},{"n":32,"t":"만일 하나님이 저로 인하여 영광을 얻으셨으면 하나님도 자기로 인하여 저에게 영광을 주시리니 곧 주시리라"},{"n":33,"t":"소자들아 내가 아직 잠시 너희와 함께 있겠노라 너희가 나를 찾을터이나 그러나 일찍 내가 유대인들에게 너희는 나의 가는 곳에 올 수 없다고 말한 것과 같이 지금 너희에게도 이르노라"},{"n":34,"t":"새 계명을 너희에게 주노니 서로 사랑하라 내가 너희를 사랑한것 같이 너희도 서로 사랑하라"},{"n":35,"t":"너희가 서로 사랑하면 이로써 모든 사람이 너희가 내 제자인줄 알리라"},{"n":36,"t":"시몬 베드로가 가로되 주여 어디로 가시나이까 예수께서 대답하시되 나의 가는 곳에 네가 지금은 따라 올 수 없으나 후에는 따라 오리라"},{"n":37,"t":"베드로가 가로되 주여 내가 지금은 어찌하여 따를 수 없나이까 주를 위하여 내 목숨을 버리겠나이다"},{"n":38,"t":"예수께서 대답하시되 네가 나를 위하여 네 목숨을 버리겠느냐 내가 진실로 진실로 네게 이르노니 닭 울기 전에 네가 세번 나를 부인하리라"}],"kids":[{"n":1,"t":"유월절 전에 예수님이 이 세상을 떠나 아버지께 갈 때가 된 줄을 아시고 세상에 있는 자기 사람들을 사랑하시되 끝까지 사랑하셨어요."},{"n":2,"t":"저녁 잡수실 때 마귀는 이미 시몬의 아들 가룟 유다의 마음에 예수님을 넘길 생각을 넣었어요."},{"n":3,"t":"예수님은 아버지께서 모든 것을 자기 손에 맡기신 것과 자기가 하나님께로부터 와서 하나님께로 가시는 것을 아시고,"},{"n":4,"t":"저녁 식사 자리에서 일어나 겉옷을 벗고 수건을 가져다 허리에 매시고,"},{"n":5,"t":"대야에 물을 부어 제자들의 발을 씻으시고 매신 수건으로 닦기 시작하셨어요."},{"n":6,"t":"시몬 베드로 차례가 되자 그가 \\"주여, 주께서 제 발을 씻으세요?\\" 했어요."},{"n":7,"t":"예수님이 \\"내가 하는 일을 네가 지금은 알지 못하지만 나중에는 알게 될 거다\\" 하셨어요."},{"n":8,"t":"베드로가 \\"내 발을 절대로 씻지 못하세요\\" 하니, 예수님이 \\"내가 너를 씻지 않으면 너는 나와 상관이 없다\\" 하셨어요."},{"n":9,"t":"베드로가 \\"주여, 발뿐 아니라 손과 머리도 씻어 주세요\\" 했어요."},{"n":10,"t":"예수님이 \\"이미 목욕한 사람은 발만 씻으면 된다. 온몸이 깨끗하기 때문이다. 너희가 깨끗하지만 다 그런 게 아니다\\" 하셨어요."},{"n":11,"t":"이는 자기를 넘길 사람이 누구인지 아셨기 때문에 \\"다 깨끗한 게 아니다\\" 하신 거예요."},{"n":12,"t":"그들의 발을 씻으신 후 옷을 입으시고 다시 앉으셔서 \\"내가 너희에게 행한 일을 아느냐?\\""},{"n":13,"t":"\\"너희가 나를 \'선생\', \'주\'라 하는데 옳다. 내가 그러하다.\\""},{"n":14,"t":"\\"주이자 선생인 내가 너희 발을 씻었으니 너희도 서로 발을 씻어 주어야 한다.\\""},{"n":15,"t":"\\"내가 한 것 같이 너희도 행하라고 본을 보였다.\\""},{"n":16,"t":"\\"진정으로 진정으로 너희에게 말한다. 종이 주인보다, 보냄받은 사람이 보낸 사람보다 크지 않다.\\""},{"n":17,"t":"\\"너희가 이것을 알고 행하면 복이 있다\\" 하셨어요."},{"n":18,"t":"\\"내가 너희 모두에 대해 말하는 게 아니다. 내가 택한 사람들을 안다. 그러나 \'내 빵을 먹은 사람이 내게 발꿈치를 들었다\'고 한 성경 말씀이 이루어지려는 거다.\\""},{"n":19,"t":"\\"일이 일어나기 전에 미리 너희에게 말한다. 일이 일어날 때 내가 그인 줄을 너희가 믿게 하려는 거다.\\""},{"n":20,"t":"\\"진정으로 진정으로 너희에게 말한다. 내가 보낸 사람을 받는 사람은 나를 받는 거고 나를 받는 사람은 나를 보내신 분을 받는 거다\\" 하셨어요."},{"n":21,"t":"이 말씀을 하시고 예수님이 심령이 답답하셔서 \\"진정으로 진정으로 너희에게 말한다. 너희 중 하나가 나를 넘길 거다\\" 하셨어요."},{"n":22,"t":"제자들이 누구를 말씀하시는지 의심하여 서로 보았어요."},{"n":23,"t":"제자 중 하나, 예수님이 사랑하시는 사람이 예수님 품에 의지해 누워 있었어요."},{"n":24,"t":"시몬 베드로가 그에게 머리짓하며 누구에 대해 말씀하시는지 물어 보라 했어요."},{"n":25,"t":"그가 예수님의 품에 그대로 의지하여 \\"주여, 누구예요?\\" 했어요."},{"n":26,"t":"예수님이 \\"내가 빵 조각을 적셔 주는 사람이 그다\\" 하시고 빵 조각을 적셔 시몬의 아들 가룟 유다에게 주셨어요."},{"n":27,"t":"그가 빵 조각을 받자 사탄이 그 속에 들어갔어요. 예수님이 \\"네가 하는 일을 빨리 해라\\" 하셨어요."},{"n":28,"t":"앉아 있던 사람 중 누구도 무슨 뜻으로 그렇게 말씀하시는지 알지 못했어요."},{"n":29,"t":"어떤 사람들은 유다가 돈주머니를 맡았기 때문에 \\"명절에 우리가 쓸 물건을 사라\\" 또는 \\"가난한 사람에게 무엇을 주라\\" 하시는 줄로 생각했어요."},{"n":30,"t":"유다가 빵 조각을 받고 곧 나갔는데 그때가 밤이었어요."},{"n":31,"t":"그가 나간 후 예수님이 \\"이제 사람의 아들이 영광을 받았고 하나님도 사람의 아들로 인해 영광을 받으셨다.\\""},{"n":32,"t":"\\"하나님이 그로 인해 영광을 받으셨다면 하나님도 자기로 인해 그에게 영광을 주실 거고 곧 영광스럽게 하실 거다.\\""},{"n":33,"t":"\\"작은 자녀들아, 내가 너희와 함께 잠시 더 있다. 너희가 나를 찾을 거고 내가 유대인들에게 한 것 같이 너희에게도 \'내가 가는 곳에 너희는 올 수 없다\'고 말한다.\\""},{"n":34,"t":"\\"새 계명을 너희에게 준다. 서로 사랑하라. 내가 너희를 사랑한 것 같이 너희도 서로 사랑하라.\\""},{"n":35,"t":"\\"너희가 서로 사랑하면 이것으로 모든 사람이 너희가 내 제자인 줄 알 거다\\" 하셨어요."},{"n":36,"t":"시몬 베드로가 \\"주여, 어디로 가세요?\\" 했어요. 예수님이 \\"내가 가는 곳에 네가 지금은 따를 수 없지만 나중에는 따라올 거다\\" 하셨어요."},{"n":37,"t":"베드로가 \\"주여, 제가 왜 지금 따를 수 없어요? 주를 위해 제 목숨도 버리겠어요\\" 했어요."},{"n":38,"t":"예수님이 \\"네가 나를 위해 목숨을 버린다고? 진정으로 진정으로 너에게 말한다. 닭이 울기 전에 네가 나를 세 번 부인할 거다\\" 하셨어요."}]}},{"chapter":14,"title":"내가 길이요 진리요 생명이다","verses":{"krv":[{"n":1,"t":"너희는 마음에 근심하지 말라 하나님을 믿으니 또 나를 믿으라"},{"n":2,"t":"내 아버지 집에 거할 곳이 많도다 그렇지 않으면 너희에게 일렀으리라 내가 너희를 위하여 처소를 예비하러 가노니"},{"n":3,"t":"가서 너희를 위하여 처소를 예비하면 내가 다시 와서 너희를 내게로 영접하여 나 있는 곳에 너희도 있게 하리라"},{"n":4,"t":"내가 가는 곳에 그 길을 너희가 알리라"},{"n":5,"t":"도마가 가로되 주여 어디로 가시는지 우리가 알지 못하거늘 그 길을 어찌 알겠삽나이까"},{"n":6,"t":"예수께서 가라사대 내가 곧 길이요 진리요 생명이니 나로 말미암지 않고는 아버지께로 올 자가 없느니라"},{"n":7,"t":"너희가 나를 알았더면 내 아버지도 알았으리로다 이제부터는 너희가 그를 알았고 또 보았느니라"},{"n":8,"t":"빌립이 가로되 주여 아버지를 우리에게 보여 주옵소서 그리하면 족하겠나이다"},{"n":9,"t":"예수께서 가라사대 빌립아 내가 이렇게 오래 너희와 함께 있으되 네가 나를 알지 못하느냐 나를 본 자는 아버지를 보았거늘 어찌하여 아버지를 보이라 하느냐"},{"n":10,"t":"나는 아버지 안에 있고 아버지는 내 안에 계신 것을 네가 믿지 아니하느냐 내가 너희에게 이르는 말이 스스로 하는 것이 아니라 아버지께서 내 안에 계셔 그의 일을 하시는 것이라"},{"n":11,"t":"내가 아버지 안에 있고 아버지께서 내 안에 계심을 믿으라 그렇지 못하겠거든 행하는 그 일을 인하여 나를 믿으라"},{"n":12,"t":"내가 진실로 진실로 너희에게 이르노니 나를 믿는 자는 나의 하는 일을 저도 할 것이요 또한 이보다 큰 것도 하리니 이는 내가 아버지께로 감이니라"},{"n":13,"t":"너희가 내 이름으로 무엇을 구하든지 내가 시행하리니 이는 아버지로 하여금 아들을 인하여 영광을 얻으시게 하려 함이라"},{"n":14,"t":"내 이름으로 무엇이든지 내게 구하면 내가 시행하리라"},{"n":15,"t":"너희가 나를 사랑하면 나의 계명을 지키리라"},{"n":16,"t":"내가 아버지께 구하겠으니 그가 또 다른 보혜사를 너희에게 주사 영원토록 너희와 함께 있게 하시리니"},{"n":17,"t":"저는 진리의 영이라 세상은 능히 저를 받지 못하나니 이는 저를 보지도 못하고 알지도 못함이라 그러나 너희는 저를 아나니 저는 너희와 함께 거하심이요 또 너희 속에 계시겠음이라"},{"n":18,"t":"내가 너희를 고아와 같이 버려두지 아니하고 너희에게로 오리라"},{"n":19,"t":"조금 있으면 세상은 다시 나를 보지 못할 터이로되 너희는 나를 보리니 이는 내가 살았고 너희도 살겠음이라"},{"n":20,"t":"그 날에는 내가 아버지 안에 너희가 내 안에 내가 너희 안에 있는 것을 너희가 알리라"},{"n":21,"t":"나의 계명을 가지고 지키는 자라야 나를 사랑하는 자니 나를 사랑하는 자는 내 아버지께 사랑을 받을 것이요 나도 그를 사랑하여 그에게 나를 나타내리라"},{"n":22,"t":"가룟인 아닌 유다가 가로되 주여 어찌하여 자기를 우리에게는 나타내시고 세상에게는 아니하려 하시나이까"},{"n":23,"t":"예수께서 대답하여 가라사대 사람이 나를 사랑하면 내 말을 지키리니 내 아버지께서 저를 사랑하실 것이요 우리가 저에게 와서 거처를 저와 함께 하리라"},{"n":24,"t":"나를 사랑하지 아니하는 자는 내 말을 지키지 아니하나니 너희의 듣는 말은 내 말이 아니요 나를 보내신 아버지의 말씀이니라"},{"n":25,"t":"내가 아직 너희와 함께 있어서 이 말을 너희에게 하였거니와"},{"n":26,"t":"보혜사 곧 아버지께서 내 이름으로 보내실 성령 그가 너희에게 모든 것을 가르치시고 내가 너희에게 말한 모든 것을 생각나게 하시리라"},{"n":27,"t":"평안을 너희에게 끼치노니 곧 나의 평안을 너희에게 주노라 내가 너희에게 주는 것은 세상이 주는 것 같지 아니하니라 너희는 마음에 근심도 말고 두려워하지도 말라"},{"n":28,"t":"내가 갔다가 너희에게로 온다 하는 말을 너희가 들었나니 나를 사랑하였더면 나의 아버지께로 감을 기뻐하였으리라 아버지는 나보다 크심이니라"},{"n":29,"t":"이제 일이 이루기 전에 너희에게 말한 것은 일이 이룰 때에 너희로 믿게 하려 함이라"},{"n":30,"t":"이 후에는 내가 너희와 말을 많이 하지 아니하리니 이 세상 임금이 오겠음이라 그러나 저는 내게 관계할 것이 없으니"},{"n":31,"t":"오직 내가 아버지를 사랑하는 것과 아버지의 명하신대로 행하는것을 세상으로 알게 하려 함이로라 일어나라 여기를 떠나자 하시니라"}],"kids":[{"n":1,"t":"\\"너희 마음에 근심하지 마라. 하나님을 믿으니 또 나도 믿어라.\\""},{"n":2,"t":"\\"내 아버지의 집에는 거할 곳이 많다. 그렇지 않으면 내가 너희에게 말했을 거다. 너희를 위해 자리를 마련하러 간다.\\""},{"n":3,"t":"\\"내가 가서 너희를 위해 자리를 마련하면 다시 와서 너희를 내게로 데려가 내가 있는 곳에 너희도 있게 할 거다.\\""},{"n":4,"t":"\\"내가 가는 곳에 너희가 길을 안다\\" 하셨어요."},{"n":5,"t":"도마가 \\"주여, 어디로 가시는지 우리가 모르는데 어떻게 길을 알겠어요?\\" 했어요."},{"n":6,"t":"예수님이 \\"내가 곧 길이요 진리요 생명이다. 나로 인하지 않고는 누구도 아버지께로 올 수 없다.\\""},{"n":7,"t":"\\"너희가 나를 알았다면 내 아버지도 알았을 거다. 이제부터는 너희가 그분을 알고 보았다\\" 하셨어요."},{"n":8,"t":"빌립이 \\"주여, 아버지를 우리에게 보여 주세요. 그러면 만족하겠어요\\" 했어요."},{"n":9,"t":"예수님이 \\"빌립아, 내가 이렇게 오래 너희와 함께 있었는데도 네가 나를 알지 못하느냐? 나를 본 사람은 아버지를 본 거다. 어떻게 \'아버지를 우리에게 보여 주세요\' 하느냐?\\""},{"n":10,"t":"\\"내가 아버지 안에 있고 아버지께서 내 안에 계신 것을 네가 믿지 않느냐? 내가 너희에게 하는 말은 스스로 하는 게 아니라 내 안에 계신 아버지께서 자기 일을 하시는 거다.\\""},{"n":11,"t":"\\"내가 아버지 안에 있고 아버지께서 내 안에 계신 것을 믿어라. 그렇지 않으면 행하는 일들로 인해서라도 나를 믿어라.\\""},{"n":12,"t":"\\"진정으로 진정으로 너희에게 말한다. 나를 믿는 사람은 내가 하는 일을 할 거고 이보다 더 큰 일도 할 거다. 내가 아버지께 가기 때문이다.\\""},{"n":13,"t":"\\"내 이름으로 무엇을 구하든지 내가 행할 거다. 아버지께서 아들로 인해 영광을 받으시게 하려는 거다.\\""},{"n":14,"t":"\\"내 이름으로 내게 무엇이든 구하면 내가 행할 거다.\\""},{"n":15,"t":"\\"너희가 나를 사랑하면 내 계명을 지킬 거다.\\""},{"n":16,"t":"\\"내가 아버지께 청하면 다른 보혜사를 너희에게 주어 영원히 너희와 함께 있게 하실 거다.\\""},{"n":17,"t":"\\"그분은 진리의 영이다. 세상은 그분을 보지도 못하고 알지도 못하여 받을 수 없지만 너희는 그분을 안다. 너희와 함께 거하시고 너희 속에 계실 거다.\\""},{"n":18,"t":"\\"내가 너희를 고아처럼 두지 않을 거다. 너희에게 갈 거다.\\""},{"n":19,"t":"\\"조금 후면 세상이 다시는 나를 보지 못하지만 너희는 나를 볼 거다. 내가 살고 너희도 살 거다.\\""},{"n":20,"t":"\\"그날에 너희가 내가 아버지 안에 있고 너희가 내 안에 있고 내가 너희 안에 있는 줄을 알 거다.\\""},{"n":21,"t":"\\"내 계명을 가지고 지키는 사람이 나를 사랑하는 사람이다. 나를 사랑하는 사람은 내 아버지께 사랑을 받을 거고 나도 그를 사랑하여 그에게 나를 나타낼 거다\\" 하셨어요."},{"n":22,"t":"가룟인 아닌 유다가 \\"주여, 어찌하여 우리에게는 자기를 나타내시고 세상에는 그렇지 않으세요?\\" 했어요."},{"n":23,"t":"예수님이 \\"누구든 나를 사랑하면 내 말을 지킬 거다. 내 아버지께서 그를 사랑하시고 우리가 그에게 가서 함께 거할 거다.\\""},{"n":24,"t":"\\"나를 사랑하지 않는 사람은 내 말을 지키지 않는다. 너희가 듣는 말은 내 것이 아니라 나를 보내신 아버지의 것이다.\\""},{"n":25,"t":"\\"내가 너희와 함께 있을 때 이것을 너희에게 말했다.\\""},{"n":26,"t":"\\"보혜사, 곧 아버지께서 내 이름으로 보내실 성령께서 너희에게 모든 것을 가르치시고 내가 말한 모든 것을 기억나게 하실 거다.\\""},{"n":27,"t":"\\"평안을 너희에게 둔다. 내 평안을 너희에게 준다. 내가 너희에게 주는 것은 세상이 주는 것과 같지 않다. 너희 마음에 근심하지도 두려워하지도 마라.\\""},{"n":28,"t":"\\"내가 \'갔다가 다시 너희에게 온다\'고 한 말을 들었다. 너희가 나를 사랑하면 내가 아버지께 가는 것을 기뻐할 거다. 아버지께서 나보다 크시기 때문이다.\\""},{"n":29,"t":"\\"이 일이 일어나기 전에 미리 말한다. 일이 일어날 때 너희가 믿게 하려는 거다.\\""},{"n":30,"t":"\\"이후로는 내가 너희와 많이 말하지 않을 거다. 이 세상의 임금이 오기 때문이다. 그가 내게 대해 가질 것이 없다.\\""},{"n":31,"t":"\\"세상이 내가 아버지를 사랑하고 아버지께서 명령하신 대로 행하는 줄을 알 거다. 일어나라, 여기를 떠나자\\" 하셨어요."}]}},{"chapter":15,"title":"참 포도나무","verses":{"krv":[{"n":1,"t":"내가 참 포도나무요 내 아버지는 그 농부라"},{"n":2,"t":"무릇 내게 있어 과실을 맺지 아니하는 가지는 아버지께서 이를 제해 버리시고 무릇 과실을 맺는 가지는 더 과실을 맺게 하려하여 이를 깨끗케 하시느니라"},{"n":3,"t":"너희는 내가 일러 준 말로 이미 깨끗하였으니"},{"n":4,"t":"내 안에 거하라 나도 너희 안에 거하리라 가지가 포도나무에 붙어 있지 아니하면 절로 과실을 맺을 수 없음 같이 너희도 내 안에 있지 아니하면 그러하리라"},{"n":5,"t":"나는 포도나무요 너희는 가지니 저가 내 안에 내가 저 안에 있으면 이 사람은 과실을 많이 맺나니 나를 떠나서는 너희가 아무 것도 할 수 없음이라"},{"n":6,"t":"사람이 내 안에 거하지 아니하면 가지처럼 밖에 버리워 말라지나니 사람들이 이것을 모아다가 불에 던져 사르느니라"},{"n":7,"t":"너희가 내 안에 거하고 내 말이 너희 안에 거하면 무엇이든지 원하는대로 구하라 그리하면 이루리라"},{"n":8,"t":"너희가 과실을 많이 맺으면 내 아버지께서 영광을 받으실 것이요 너희가 내 제자가 되리라"},{"n":9,"t":"아버지께서 나를 사랑하신 것 같이 나도 너희를 사랑하였으니 나의 사랑 안에 거하라"},{"n":10,"t":"내가 아버지의 계명을 지켜 그의 사랑 안에 거하는것 같이 너희도 내 계명을 지키면 내 사랑 안에 거하리라"},{"n":11,"t":"내가 이것을 너희에게 이름은 내 기쁨이 너희 안에 있어 너희 기쁨을 충만하게 하려함이니라"},{"n":12,"t":"내 계명은 곧 내가 너희를 사랑한 것 같이 너희도 서로 사랑하라 하는 이것이니라"},{"n":13,"t":"사람이 친구를 위하여 자기 목숨을 버리면 이에서 더 큰 사랑이 없나니"},{"n":14,"t":"너희가 나의 명하는대로 행하면 곧 나의 친구라"},{"n":15,"t":"이제부터는 너희를 종이라 하지 아니하리니 종은 주인의 하는 것을 알지 못함이라 너희를 친구라 하였노니 내가 내 아버지께 들은 것을 다 너희에게 알게 하였음이니라"},{"n":16,"t":"너희가 나를 택한 것이 아니요 내가 너희를 택하여 세웠나니 이는 너희로 가서 과실을 맺게 하고 또 너희 과실이 항상 있게 하여 내 이름으로 아버지께 무엇을 구하든지 다 받게 하려 함이니라"},{"n":17,"t":"내가 이것을 너희에게 명함은 너희로 서로 사랑하게 하려 함이로라"},{"n":18,"t":"세상이 너희를 미워하면 너희보다 먼저 나를 미워한 줄을 알라"},{"n":19,"t":"너희가 세상에 속하였으면 세상이 자기의 것을 사랑할 터이나 너희는 세상에 속한 자가 아니요 도리어 세상에서 나의 택함을 입은 자인고로 세상이 너희를 미워하느니라"},{"n":20,"t":"내가 너희더러 종이 주인보다 더 크지 못하다 한 말을 기억하라 사람들이 나를 핍박하였은즉 너희도 핍박할 터이요 내 말을 지켰은즉 너희 말도 지킬 터이라"},{"n":21,"t":"그러나 사람들이 내 이름을 인하여 이 모든 일을 너희에게 하리니 이는 나 보내신 이를 알지 못함이니라"},{"n":22,"t":"내가 와서 저희에게 말하지 아니하였더면 죄가 없었으려니와 지금은 그 죄를 핑계할 수 없느니라"},{"n":23,"t":"나를 미워하는 자는 또 내 아버지를 미워하느니라"},{"n":24,"t":"내가 아무도 못한 일을 저희 중에서 하지 아니하였더면 저희가 죄 없었으려니와 지금은 저희가 나와 및 내 아버지를 보았고 또 미워하였도다"},{"n":25,"t":"그러나 이는 저희 율법에 기록된바 저희가 연고 없이 나를 미워하였다한 말을 응하게 하려 함이니라"},{"n":26,"t":"내가 아버지께로서 너희에게 보낼 보혜사 곧 아버지께로서 나오시는 진리의 성령이 오실 때에 그가 나를 증거하실 것이요"},{"n":27,"t":"너희도 처음부터 나와 함께 있었으므로 증거하느니라"}],"kids":[{"n":1,"t":"\\"나는 참 포도나무고 내 아버지는 농부다.\\""},{"n":2,"t":"\\"내 안에서 열매를 맺지 않는 가지는 모두 제거하시고 열매를 맺는 가지는 더 많은 열매를 맺게 하려고 깨끗하게 하신다.\\""},{"n":3,"t":"\\"내가 너희에게 일러 준 말로 너희는 이미 깨끗하다.\\""},{"n":4,"t":"\\"내 안에 거하라. 나도 너희 안에 거할 거다. 가지가 포도나무에 붙어 있지 않으면 스스로 열매를 맺을 수 없는 것 같이 너희도 내 안에 거하지 않으면 그러하다.\\""},{"n":5,"t":"\\"나는 포도나무고 너희는 가지다. 누구든 내 안에 거하고 나도 그 안에 거하면 그 사람은 많은 열매를 맺는다. 너희는 나를 떠나서는 아무것도 할 수 없다.\\""},{"n":6,"t":"\\"누구든 내 안에 거하지 않으면 가지처럼 밖에 버려져 마른다. 사람들이 모아 불에 던져 태운다.\\""},{"n":7,"t":"\\"너희가 내 안에 거하고 내 말이 너희 안에 거하면 무엇을 구하든지 이루어질 거다.\\""},{"n":8,"t":"\\"너희가 많은 열매를 맺으면 내 아버지께서 영광을 받으실 거고 너희가 내 제자가 될 거다.\\""},{"n":9,"t":"\\"아버지께서 나를 사랑하신 것 같이 나도 너희를 사랑했다. 내 사랑 안에 거하라.\\""},{"n":10,"t":"\\"내가 내 아버지의 계명을 지켜 그분의 사랑 안에 거하는 것 같이 너희가 내 계명을 지키면 내 사랑 안에 거할 거다.\\""},{"n":11,"t":"\\"내가 이것을 너희에게 말한 것은 내 기쁨이 너희 안에 있고 너희 기쁨이 가득하게 하려는 거다.\\""},{"n":12,"t":"\\"내 계명은 이것이다. 내가 너희를 사랑한 것 같이 너희도 서로 사랑하라.\\""},{"n":13,"t":"\\"누가 자기 친구를 위해 자기 목숨을 버리면 이보다 더 큰 사랑이 없다.\\""},{"n":14,"t":"\\"너희가 내가 명령하는 것을 행하면 너희는 내 친구다.\\""},{"n":15,"t":"\\"이제는 너희를 종이라 부르지 않을 거다. 종은 주인이 하는 일을 알지 못하기 때문이다. 너희를 친구라 했다. 내 아버지께 들은 모든 것을 너희에게 알게 했기 때문이다.\\""},{"n":16,"t":"\\"너희가 나를 택한 게 아니라 내가 너희를 택해 세웠다. 너희가 가서 열매를 맺고 너희 열매가 머물게 하려는 거다. 너희가 내 이름으로 아버지께 무엇을 구하든지 주실 거다.\\""},{"n":17,"t":"\\"내가 너희에게 이것을 명령한다. 서로 사랑하라.\\""},{"n":18,"t":"\\"세상이 너희를 미워하면 너희보다 먼저 나를 미워한 줄을 알아라.\\""},{"n":19,"t":"\\"너희가 세상에 속했다면 세상이 자기 것을 사랑할 거다. 너희는 세상에 속하지 않고 내가 너희를 세상에서 택했기 때문에 세상이 너희를 미워한다.\\""},{"n":20,"t":"\\"내가 너희에게 한 말을 기억해라. \'종이 주인보다 크지 않다.\' 사람들이 나를 박해했으면 너희도 박해할 거다. 내 말을 지켰으면 너희 말도 지킬 거다.\\""},{"n":21,"t":"\\"그러나 이 모든 일을 내 이름 때문에 너희에게 할 거다. 이는 나를 보내신 분을 알지 못하기 때문이다.\\""},{"n":22,"t":"\\"내가 와서 그들에게 말하지 않았다면 그들에게 죄가 없었겠지만 이제는 그들이 그들의 죄에 대한 변명이 없다.\\""},{"n":23,"t":"\\"나를 미워하는 사람은 내 아버지도 미워한다.\\""},{"n":24,"t":"\\"내가 누구도 행한 적 없는 일을 그들 가운데 행하지 않았다면 그들에게 죄가 없었겠지만 이제 그들이 내 일을 보았고 나와 내 아버지를 미워했다.\\""},{"n":25,"t":"\\"그들의 율법에 \'이유 없이 나를 미워했다\'고 기록된 말을 이루려는 거다.\\""},{"n":26,"t":"\\"내가 아버지께로부터 너희에게 보낼 보혜사, 곧 아버지께로부터 나오시는 진리의 영이 오시면 나에 대해 증언하실 거다.\\""},{"n":27,"t":"\\"너희도 처음부터 나와 함께 있었으므로 증언할 거다\\" 하셨어요."}]}},{"chapter":16,"title":"성령에 대한 약속","verses":{"krv":[{"n":1,"t":"내가 이것을 너희에게 이름은 너희로 실족지 않게 하려 함이니"},{"n":2,"t":"사람들이 너희를 출회할 뿐아니라 때가 이르면 무릇 너희를 죽이는 자가 생각하기를 이것이 하나님을 섬기는 예라 하리라"},{"n":3,"t":"저희가 이런 일을 할 것은 아버지와 나를 알지 못함이라"},{"n":4,"t":"오직 너희에게 이 말을 이른 것은 너희로 그 때를 당하면 내가 너희에게 이 말 한 것을 기억나게 하려 함이요 처음부터 이 말을 하지 아니한 것은 내가 너희와 함께 있었음이니라"},{"n":5,"t":"지금 내가 나를 보내신 이에게로 가는데 너희 중에서 나더러 어디로 가느냐 묻는 자가 없고"},{"n":6,"t":"도리어 내가 이 말을 하므로 너희 마음에 근심이 가득하였도다"},{"n":7,"t":"그러하나 내가 너희에게 실상을 말하노니 내가 떠나가는 것이 너희에게 유익이라 내가 떠나가지 아니하면 보혜사가 너희에게로 오시지 아니할 것이요 가면 내가 그를 너희에게로 보내리니"},{"n":8,"t":"그가 와서 죄에 대하여 의에 대하여 심판에 대하여 세상을 책망하시리라"},{"n":9,"t":"죄에 대하여라 함은 저희가 나를 믿지 아니함이요"},{"n":10,"t":"의에 대하여라 함은 내가 아버지께로 가니 너희가 다시 나를 보지 못함이요"},{"n":11,"t":"심판에 대하여라 함은 이 세상 임금이 심판을 받았음이니라"},{"n":12,"t":"내가 아직도 너희에게 이를 것이 많으나 지금은 너희가 감당치 못하리라"},{"n":13,"t":"그러하나 진리의 성령이 오시면 그가 너희를 모든 진리 가운데로 인도하시리니 그가 자의로 말하지 않고 오직 듣는 것을 말하시며 장래 일을 너희에게 알리시리라"},{"n":14,"t":"그가 내 영광을 나타내리니 내 것을 가지고 너희에게 알리겠음이니라"},{"n":15,"t":"무릇 아버지께 있는 것은 다 내 것이라 그러므로 내가 말하기를 그가 내 것을 가지고 너희에게 알리리라 하였노라"},{"n":16,"t":"조금 있으면 너희가 나를 보지 못하겠고 또 조금 있으면 나를 보리라 하신대"},{"n":17,"t":"제자 중에서 서로 말하되 우리에게 말씀하신바 조금 있으면 나를 보지 못하겠고 또 조금 있으면 나를 보리라 하시며 또 내가 아버지께로 감이라 하신 것이 무슨 말씀이뇨 하고"},{"n":18,"t":"또 말하되 조금 있으면이라한 말씀이 무슨 말씀이뇨 무엇을 말씀하시는지 알지 못하노라 하거늘"},{"n":19,"t":"예수께서 그 묻고자 함을 아시고 가라사대 내 말이 조금 있으면 나를 보지 못하겠고 또 조금 있으면 나를 보리라 하므로 서로 문의하느냐"},{"n":20,"t":"내가 진실로 진실로 너희에게 이르노니 너희는 곡하고 애통하겠으나 세상은 기뻐하리라 너희는 근심하겠으나 너희 근심이 도리어 기쁨이 되리라"},{"n":21,"t":"여자가 해산하게 되면 그 때가 이르렀으므로 근심하나 아이를 낳으면 세상에 사람 난 기쁨을 인하여 그 고통을 다시 기억지 아니하느니라"},{"n":22,"t":"지금은 너희가 근심하나 내가 다시 너희를 보리니 너희 마음이 기쁠 것이요 너희 기쁨을 빼앗을 자가 없느니라"},{"n":23,"t":"그 날에는 너희가 아무 것도 내게 묻지 아니하리라 내가 진실로 진실로 너희에게 이르노니 너희가 무엇이든지 아버지께 구하는 것을 내 이름으로 주시리라"},{"n":24,"t":"지금까지는 너희가 내 이름으로 아무 것도 구하지 아니하였으나 구하라 그리하면 받으리니 너희 기쁨이 충만하리라"},{"n":25,"t":"이것을 비사로 너희에게 일렀거니와 때가 이르면 다시 비사로 너희에게 이르지 않고 아버지에 대한 것을 밝히 이르리라"},{"n":26,"t":"그 날에 너희가 내 이름으로 구할 것이요 내가 너희를 위하여 아버지께 구하겠다 하는 말이 아니니"},{"n":27,"t":"이는 너희가 나를 사랑하고 또 나를 하나님께로서 온줄 믿은 고로 아버지께서 친히 너희를 사랑하심이니라"},{"n":28,"t":"내가 아버지께로 나와서 세상에 왔고 다시 세상을 떠나 아버지께로 가노라 하시니"},{"n":29,"t":"제자들이 말하되 지금은 밝히 말씀하시고 아무 비사도 하지 아니하시니"},{"n":30,"t":"우리가 지금에야 주께서 모든 것을 아시고 또 사람의 물음을 기다리시지 않는줄 아나이다 이로써 하나님께로서 나오심을 우리가 믿삽나이다"},{"n":31,"t":"예수께서 대답하시되 이제는 너희가 믿느냐"},{"n":32,"t":"보라 너희가 다 각각 제 곳으로 흩어지고 나를 혼자 둘 때가 오나니 벌써 왔도다 그러나 내가 혼자 있는 것이 아니라 아버지께서 나와 함께 계시느니라"},{"n":33,"t":"이것을 너희에게 이름은 너희로 내 안에서 평안을 누리게 하려함이라 세상에서는 너희가 환난을 당하나 담대하라 내가 세상을 이기었노라 하시니라"}],"kids":[{"n":1,"t":"\\"내가 너희에게 이것을 말한 것은 너희가 걸려 넘어지지 않게 하려는 거다.\\""},{"n":2,"t":"\\"사람들이 너희를 회당에서 쫓아낼 거다. 너희를 죽이는 사람이 자기가 하나님을 섬긴다고 생각할 때가 올 거다.\\""},{"n":3,"t":"\\"그들이 이런 일을 하는 것은 아버지나 나를 알지 못하기 때문이다.\\""},{"n":4,"t":"\\"내가 이것을 너희에게 말한 것은 그때가 와서 내가 너희에게 말한 것을 기억하게 하려는 거다. 처음부터 이것을 말하지 않은 것은 내가 너희와 함께 있었기 때문이다.\\""},{"n":5,"t":"\\"이제 나를 보내신 분께 간다. 그런데 너희 중 누구도 \'어디로 가세요?\' 하고 묻지 않는다.\\""},{"n":6,"t":"\\"내가 이것을 너희에게 말했기 때문에 너희 마음에 슬픔이 가득하다.\\""},{"n":7,"t":"\\"그러나 진실을 말한다. 내가 떠나가는 것이 너희에게 유익이다. 내가 가지 않으면 보혜사가 너희에게 오지 않으실 거고 내가 가면 그분을 너희에게 보낼 거다.\\""},{"n":8,"t":"\\"그분이 오시면 죄와 의와 심판에 대해 세상을 책망하실 거다.\\""},{"n":9,"t":"\\"죄에 대해서는 그들이 나를 믿지 않기 때문이다.\\""},{"n":10,"t":"\\"의에 대해서는 내가 아버지께로 가서 너희가 다시는 나를 보지 못하기 때문이다.\\""},{"n":11,"t":"\\"심판에 대해서는 이 세상의 임금이 심판받았기 때문이다.\\""},{"n":12,"t":"\\"내가 아직 너희에게 말할 것이 많지만 지금은 너희가 감당할 수 없다.\\""},{"n":13,"t":"\\"그러나 진리의 영이 오시면 너희를 모든 진리 가운데 인도하실 거다. 그분은 자기 스스로 말씀하지 않으시고 듣는 것을 말씀하시고 장차 일을 너희에게 알리실 거다.\\""},{"n":14,"t":"\\"그분이 나를 영화롭게 하실 거다. 내 것을 받아 너희에게 알리실 것이기 때문이다.\\""},{"n":15,"t":"\\"아버지께서 가지신 모든 것이 내 것이다. 그러므로 그분이 내 것을 받아 너희에게 알리실 거라 했다.\\""},{"n":16,"t":"\\"조금 있으면 너희가 나를 보지 못하다가 또 조금 있으면 다시 볼 거다\\" 하셨어요."},{"n":17,"t":"제자 중 어떤 사람이 서로 \\"우리에게 하시는 \'조금 있으면 너희가 나를 보지 못하다가 또 조금 있으면 다시 보겠다\' 한 말과 \'내가 아버지께로 간다\'고 한 말이 무슨 뜻이지?\\" 했어요."},{"n":18,"t":"\\"이 \'조금 있으면\'이 무슨 말씀인지 모르겠다\\" 했어요."},{"n":19,"t":"예수님이 그들이 묻고 싶어 하는 것을 아시고 \\"내가 \'조금 있으면 너희가 나를 보지 못하다가 또 조금 있으면 다시 볼 거다\'라고 한 말에 대해 서로 묻느냐?\\""},{"n":20,"t":"\\"진정으로 진정으로 너희에게 말한다. 너희는 울고 슬퍼하지만 세상은 기뻐할 거다. 너희는 근심하지만 너희 근심이 도리어 기쁨이 될 거다.\\""},{"n":21,"t":"\\"여자가 해산하려 할 때는 자기 때가 이르렀으므로 근심하지만 아기를 낳으면 세상에 사람이 태어난 기쁨으로 그 고통을 다시 기억하지 않는다.\\""},{"n":22,"t":"\\"이와 같이 너희도 지금은 근심하지만 내가 다시 너희를 볼 거고 너희 마음이 기쁠 거고 너희 기쁨을 누구도 빼앗을 수 없을 거다.\\""},{"n":23,"t":"\\"그날에는 너희가 내게 아무것도 묻지 않을 거다. 진정으로 진정으로 너희에게 말한다. 너희가 내 이름으로 아버지께 무엇을 구하든지 그분이 너희에게 주실 거다.\\""},{"n":24,"t":"\\"지금까지는 너희가 내 이름으로 아무것도 구하지 않았다. 구해라. 그러면 받을 거다. 너희 기쁨이 가득할 거다.\\""},{"n":25,"t":"\\"이것을 비유로 너희에게 말했지만 더 이상 비유로 말하지 않고 아버지에 대해 너희에게 명백히 알릴 때가 올 거다.\\""},{"n":26,"t":"\\"그날에는 너희가 내 이름으로 구할 거고 내가 너희를 위해 아버지께 구한다고 말하지 않을 거다.\\""},{"n":27,"t":"\\"아버지께서 친히 너희를 사랑하시기 때문이다. 너희가 나를 사랑하고 내가 하나님께로부터 왔음을 믿었기 때문이다.\\""},{"n":28,"t":"\\"내가 아버지께로부터 나와 세상에 왔다. 다시 세상을 떠나 아버지께 간다\\" 하셨어요."},{"n":29,"t":"제자들이 \\"이제 명백히 말씀하시고 비유로 하지 않으세요.\\""},{"n":30,"t":"\\"이제 우리는 주께서 모든 것을 아시고 누가 묻기를 기다리지 않으심을 압니다. 이로 인해 주께서 하나님께로부터 나오신 줄을 믿어요\\" 했어요."},{"n":31,"t":"예수님이 \\"이제는 너희가 믿느냐?\\""},{"n":32,"t":"\\"보라, 너희가 다 흩어져 각자 자기 집으로 가고 나를 혼자 둘 때가 온다. 사실은 이미 왔다. 그러나 나는 혼자가 아니다. 아버지께서 나와 함께 계신다.\\""},{"n":33,"t":"\\"내가 이것을 너희에게 말한 것은 너희가 내 안에서 평안을 누리게 하려는 거다. 세상에서는 너희가 환난을 당할 거다. 그러나 담대해라. 내가 세상을 이겼다\\" 하셨어요."}]}},{"chapter":17,"title":"예수님의 기도","verses":{"krv":[{"n":1,"t":"예수께서 이 말씀을 하시고 눈을 들어 하늘을 우러러 가라사대 아버지여 때가 이르렀사오니 아들을 영화롭게 하사 아들로 아버지를 영화롭게 하게 하옵소서"},{"n":2,"t":"아버지께서 아들에게 주신 모든 자에게 영생을 주게 하시려고 만민을 다스리는 권세를 아들에게 주셨음이로소이다"},{"n":3,"t":"영생은 곧 유일하신 참 하나님과 그의 보내신 자 예수 그리스도를 아는 것이니이다"},{"n":4,"t":"아버지께서 내게 하라고 주신 일을 내가 이루어 아버지를 이 세상에서 영화롭게 하였사오니"},{"n":5,"t":"아버지여 창세 전에 내가 아버지와 함께 가졌던 영화로써 지금도 아버지와 함께 나를 영화롭게 하옵소서"},{"n":6,"t":"세상 중에서 내게 주신 사람들에게 내가 아버지의 이름을 나타내었나이다 저희는 아버지의 것이었는데 내게 주셨으며 저희는 아버지의 말씀을 지키었나이다"},{"n":7,"t":"지금 저희는 아버지께서 내게 주신 것이 다 아버지께로서 온 것인줄 알았나이다"},{"n":8,"t":"나는 아버지께서 내게 주신 말씀들을 저희에게 주었사오며 저희는 이것을 받고 내가 아버지께로부터 나온 줄을 참으로 아오며 아버지께서 나를 보내신 줄도 믿었사옵나이다"},{"n":9,"t":"내가 저희를 위하여 비옵나니 내가 비옵는 것은 세상을 위함이 아니요 내게 주신 자들을 위함이니이다 저희는 아버지의 것이로소이다"},{"n":10,"t":"내 것은 다 아버지의 것이요 아버지의 것은 내 것이온데 내가 저희로 말미암아 영광을 받았나이다"},{"n":11,"t":"나는 세상에 더 있지 아니하오나 저희는 세상에 있사옵고 나는 아버지께로 가옵나니 거룩하신 아버지여 내게 주신 아버지의 이름으로 저희를 보전하사 우리와 같이 저희도 하나가 되게 하옵소서"},{"n":12,"t":"내가 저희와 함께 있을 때에 내게 주신 아버지의 이름으로 저희를 보전하와 지키었나이다 그 중에 하나도 멸망치 않고 오직 멸망의 자식 뿐이오니 이는 성경을 응하게 함이니이다"},{"n":13,"t":"지금 내가 아버지께로 가오니 내가 세상에서 이 말을 하옵는 것은 저희로 내 기쁨을 저희 안에 충만히 가지게하려 함이니이다"},{"n":14,"t":"내가 아버지의 말씀을 저희에게 주었사오매 세상이 저희를 미워하였사오니 이는 내가 세상에 속하지 아니함 같이 저희도 세상에 속하지 아니함을 인함이니이다"},{"n":15,"t":"내가 비옵는 것은 저희를 세상에서 데려가시기를 위함이 아니요 오직 악에 빠지지 않게 보전하시기를 위함이니이다"},{"n":16,"t":"내가 세상에 속하지 아니함 같이 저희도 세상에 속하지 아니하였삽나이다"},{"n":17,"t":"저희를 진리로 거룩하게 하옵소서 아버지의 말씀은 진리니이다"},{"n":18,"t":"아버지께서 나를 세상에 보내신 것 같이 나도 저희를 세상에 보내었고"},{"n":19,"t":"또 저희를 위하여 내가 나를 거룩하게 하오니 이는 저희도 진리로 거룩함을 얻게 하려 함이니이다"},{"n":20,"t":"내가 비옵는 것은 이 사람들만 위함이 아니요 또 저희 말을 인하여 나를 믿는 사람들도 위함이니"},{"n":21,"t":"아버지께서 내 안에 내가 아버지 안에 있는 것 같이 저희도 다 하나가 되어 우리 안에 있게 하사 세상으로 아버지께서 나를 보내신 것을 믿게 하옵소서"},{"n":22,"t":"내게 주신 영광을 내가 저희에게 주었사오니 이는 우리가 하나가 된것 같이 저희도 하나가 되게 하려 함이니이다"},{"n":23,"t":"곧 내가 저희 안에 아버지께서 내 안에 계셔 저희로 온전함을 이루어 하나가 되게 하려 함은 아버지께서 나를 보내신것과 또 나를 사랑하심 같이 저희도 사랑하신 것을 세상으로 알게 하려 함이로소이다"},{"n":24,"t":"아버지여 내게 주신 자도 나 있는 곳에 나와 함께 있어 아버지께서 창세 전부터 나를 사랑하시므로 내게 주신 나의 영광을 저희로 보게 하시기를 원하옵나이다"},{"n":25,"t":"의로우신 아버지여 세상이 아버지를 알지 못하여도 나는 아버지를 알았삽고 저희도 아버지께서 나를 보내신줄 알았삽나이다"},{"n":26,"t":"내가 아버지의 이름을 저희에게 알게 하였고 또 알게 하리니 이는 나를 사랑하신 사랑이 저희 안에 있고 나도 저희 안에 있게 하려 함이니이다"}],"kids":[{"n":1,"t":"예수님이 이 말씀을 하시고 눈을 들어 하늘을 보며 \\"아버지여, 때가 되었어요. 아버지의 아들을 영화롭게 하셔서 아들이 아버지를 영화롭게 하게 하소서.\\""},{"n":2,"t":"\\"아버지께서 아들에게 모든 사람을 다스릴 권세를 주셨고 아들이 아버지께서 주신 모든 사람에게 영생을 주게 하셨어요.\\""},{"n":3,"t":"\\"영생은 곧 유일하신 참 하나님과 그가 보내신 예수 그리스도를 아는 거예요.\\""},{"n":4,"t":"\\"아버지께서 내게 행하라 주신 일을 내가 이루어 아버지를 땅에서 영화롭게 했어요.\\""},{"n":5,"t":"\\"아버지여, 이제 세상 있기 전에 내가 아버지와 함께 가진 그 영광으로 나를 아버지와 함께 영화롭게 하소서.\\""},{"n":6,"t":"\\"세상 중에서 내게 주신 사람들에게 내가 아버지의 이름을 나타냈어요. 그들은 아버지의 것이었고 내게 주셨고 그들이 아버지의 말씀을 지켰어요.\\""},{"n":7,"t":"\\"이제 그들이 내게 주신 모든 것이 아버지께로부터 온 것인 줄 알았어요.\\""},{"n":8,"t":"\\"내가 받은 말씀을 그들에게 주었고 그들은 그것을 받아 내가 아버지께로부터 나온 것을 진실로 알고 아버지께서 나를 보내신 것을 믿었어요.\\""},{"n":9,"t":"\\"내가 그들을 위해 비는 거예요. 세상을 위해서가 아니라 아버지께서 내게 주신 사람들을 위해서요. 그들이 아버지의 것이거든요.\\""},{"n":10,"t":"\\"내 것은 다 아버지의 것이고 아버지의 것은 내 것이고 나는 그들로 인해 영광을 받았어요.\\""},{"n":11,"t":"\\"이제부터 나는 세상에 있지 않지만 그들은 세상에 있고 나는 아버지께로 가요. 거룩하신 아버지여, 내게 주신 아버지의 이름으로 그들을 지켜서 우리가 하나인 것 같이 그들도 하나가 되게 하소서.\\""},{"n":12,"t":"\\"내가 그들과 함께 있을 때 내게 주신 아버지의 이름으로 그들을 보전하여 지켰어요. 멸망의 아들 외에는 아무도 멸망하지 않았고 이는 성경 말씀을 이루기 위함이에요.\\""},{"n":13,"t":"\\"이제 내가 아버지께 가요. 내가 세상에서 이것을 말하는 것은 내 기쁨이 그들 안에 가득하게 하려는 거예요.\\""},{"n":14,"t":"\\"내가 아버지의 말씀을 그들에게 주었더니 세상이 그들을 미워해요. 내가 세상에 속하지 않은 것 같이 그들도 세상에 속하지 않았기 때문이에요.\\""},{"n":15,"t":"\\"세상에서 그들을 데려가시기를 비는 게 아니라 악에서 그들을 지켜 주시기를 비는 거예요.\\""},{"n":16,"t":"\\"내가 세상에 속하지 않은 것 같이 그들도 세상에 속하지 않았어요.\\""},{"n":17,"t":"\\"진리로 그들을 거룩하게 하소서. 아버지의 말씀은 진리예요.\\""},{"n":18,"t":"\\"아버지께서 나를 세상에 보내신 것 같이 나도 그들을 세상에 보냈어요.\\""},{"n":19,"t":"\\"그들을 위해 내가 나를 거룩하게 해요. 이는 그들도 진리로 거룩해지게 하려는 거예요.\\""},{"n":20,"t":"\\"내가 그들만을 위해 비는 게 아니라 그들의 말로 인해 나를 믿는 사람들도 위해 비는 거예요.\\""},{"n":21,"t":"\\"아버지께서 내 안에, 내가 아버지 안에 있는 것 같이 그들도 다 하나가 되어 우리 안에 있게 하소서. 세상이 아버지께서 나를 보내신 것을 믿게 하려는 거예요.\\""},{"n":22,"t":"\\"내게 주신 영광을 그들에게 주었어요. 우리가 하나인 것 같이 그들도 하나가 되게 하려는 거예요.\\""},{"n":23,"t":"\\"내가 그들 안에, 아버지께서 내 안에 계셔서 그들이 온전히 하나가 되어 아버지께서 나를 보내신 것과 나를 사랑하신 것 같이 그들도 사랑하신 줄을 세상이 알게 하려는 거예요.\\""},{"n":24,"t":"\\"아버지여, 내게 주신 사람들도 내가 있는 곳에 나와 함께 있어 내게 주신 내 영광을 보게 하기를 원해요. 창세 전부터 아버지께서 나를 사랑하셨거든요.\\""},{"n":25,"t":"\\"의로우신 아버지여, 세상이 아버지를 알지 못해도 나는 아버지를 알고 그들도 아버지께서 나를 보내신 줄을 알았어요.\\""},{"n":26,"t":"\\"내가 아버지의 이름을 그들에게 알게 했고 또 알게 할 거예요. 이는 나를 사랑하신 사랑이 그들 안에 있고 나도 그들 안에 있게 하려는 거예요.\\""}]}},{"chapter":18,"title":"잡히심과 베드로의 부인","verses":{"krv":[{"n":1,"t":"예수께서 이 말씀을 하시고 제자들과 함께 기드론 시내 저편으로 나가시니 거기 동산이 있는데 제자들과 함께 들어가시다"},{"n":2,"t":"거기는 예수께서 제자들과 가끔 모이시는 곳이므로 예수를 파는 유다도 그곳을 알더라"},{"n":3,"t":"유다가 군대와 및 대제사장들과 바리새인들에게서 얻은 하속들을 데리고 등과 홰와 병기를 가지고 그리로 오는지라"},{"n":4,"t":"예수께서 그 당할 일을 다 아시고 나아가 가라사대 너희가 누구를 찾느냐"},{"n":5,"t":"대답하되 나사렛 예수라 하거늘 가라사대 내로라 하시니라 그를 파는 유다도 저희와 함께 섰더라"},{"n":6,"t":"예수께서 저희에게 내로라 하실 때에 저희가 물러가서 땅에 엎드러지는지라"},{"n":7,"t":"이에 다시 누구를 찾느냐고 물으신대 저희가 말하되 나사렛 예수라 하거늘"},{"n":8,"t":"예수께서 대답하시되 너희에게 내로라 하였으니 나를 찾거든 이 사람들의 가는 것을 용납하라 하시니"},{"n":9,"t":"이는 아버지께서 내게 주신 자 중에서 하나도 잃지 아니하였삽나이다 하신 말씀을 응하게 하려 함이러라"},{"n":10,"t":"이에 시몬 베드로가 검을 가졌는데 이것을 빼어 대제사장의 종을 쳐서 오른편 귀를 베어버리니 그 종의 이름은 말고라"},{"n":11,"t":"예수께서 베드로더러 이르시되 검을 집에 꽂으라 아버지께서 주신 잔을 내가 마시지 아니하겠느냐 하시니라"},{"n":12,"t":"이에 군대와 천부장과 유대인의 하속들이 예수를 잡아 결박하여"},{"n":13,"t":"먼저 안나스에게로 끌고 가니 안나스는 그 해의 대제사장인 가야바의 장인이라"},{"n":14,"t":"가야바는 유대인들에게 한 사람이 백성을 위하여 죽는 것이 유익하다 권고하던 자러라"},{"n":15,"t":"시몬 베드로와 또 다른 제자 하나가 예수를 따르니 이 제자는 대제사장과 아는 사람이라 예수와 함께 대제사장의 집 뜰에 들어가고"},{"n":16,"t":"베드로는 문 밖에 섰는지라 대제사장과 아는 그 다른 제자가 나가서 문지키는 여자에게 말하여 베드로를 데리고 들어왔더니"},{"n":17,"t":"문 지키는 여종이 베드로에게 말하되 너도 이 사람의 제자 중 하나가 아니냐 하니 그가 말하되 나는 아니라 하고"},{"n":18,"t":"그 때가 추운고로 종과 하속들이 숯불을 피우고 서서 쬐니 베드로도 함께 서서 쬐더라"},{"n":19,"t":"대제사장이 예수에게 그의 제자들과 그의 교훈에 대하여 물으니"},{"n":20,"t":"예수께서 대답하시되 내가 드러내어 놓고 세상에 말하였노라 모든 유대인들의 모이는 회당과 성전에서 항상 가르쳤고 은밀히는 아무 것도 말하지 아니하였거늘"},{"n":21,"t":"어찌하여 내게 묻느냐 내가 무슨 말을 하였는지 들은 자들에게 물어 보라 저희가 나의 하던 말을 아느니라"},{"n":22,"t":"이 말씀을 하시매 곁에 섰는 하속 하나가 손으로 예수를 쳐 가로되 네가 대제사장에게 이같이 대답하느냐 하니"},{"n":23,"t":"예수께서 대답하시되 내가 말을 잘못하였으면 그 잘못한 것을 증거하라 잘하였으면 네가 어찌하여 나를 치느냐 하시더라"},{"n":24,"t":"안나스가 예수를 결박한 그대로 대제사장 가야바에게 보내니라"},{"n":25,"t":"시몬 베드로가 서서 불을 쬐더니 사람들이 묻되 너도 그 제자 중 하나가 아니냐 베드로가 부인하여 가로되 나는 아니라 하니"},{"n":26,"t":"대제사장의 종 하나는 베드로에게 귀를 베어 버리운 사람의 일가라 가로되 네가 그 사람과 함께 동산에 있던 것을 내가 보지 아니하였느냐"},{"n":27,"t":"이에 베드로가 또 부인하니 곧 닭이 울더라"},{"n":28,"t":"저희가 예수를 가야바에게서 관정으로 끌고 가니 새벽이라 저희는 더럽힘을 받지 아니하고 유월절 잔치를 먹고자 하여 관정에 들어가지 아니하더라"},{"n":29,"t":"그러므로 빌라도가 밖으로 저희에게 나가서 말하되 너희가 무슨 일로 이 사람을 고소하느냐"},{"n":30,"t":"대답하여 가로되 이 사람이 행악자가 아니었더면 우리가 당신에게 넘기지 아니하였겠나이다"},{"n":31,"t":"빌라도가 가로되 너희가 저를 데려다가 너희 법대로 재판하라 유대인들이 가로되 우리에게는 사람을 죽이는 권이 없나이다 하니"},{"n":32,"t":"이는 예수께서 자기가 어떠한 죽음으로 죽을 것을 가리켜 하신 말씀을 응하게 하려 함이러라"},{"n":33,"t":"이에 빌라도가 다시 관정에 들어가 예수를 불러 가로되 네가 유대인의 왕이냐"},{"n":34,"t":"예수께서 대답하시되 이는 네가 스스로 하는 말이뇨 다른 사람들이 나를 대하여 네게 한 말이뇨"},{"n":35,"t":"빌라도가 대답하되 내가 유대인이냐 네 나라 사람과 대제사장들이 너를 내게 넘겼으니 네가 무엇을 하였느냐"},{"n":36,"t":"예수께서 대답하시되 내 나라는 이 세상에 속한 것이 아니라 만일 내 나라가 이 세상에 속한 것이었더면 내 종들이 싸워 나로 유대인들에게 넘기우지 않게 하였으리라 이제 내 나라는 여기에 속한 것이 아니니라"},{"n":37,"t":"빌라도가 가로되 그러면 네가 왕이 아니냐 예수께서 대답하시되 네 말과 같이 내가 왕이니라 내가 이를 위하여 났으며 이를 위하여 세상에 왔나니 곧 진리에 대하여 증거하려 함이로다 무릇 진리에 속한 자는 내 소리를 듣느니라 하신대"},{"n":38,"t":"빌라도가 가로되 진리가 무엇이냐 하더라 이 말을 하고 다시 유대인들에게 나가서 이르되 나는 그에게서 아무 죄도 찾지 못하노라"},{"n":39,"t":"유월절이면 내가 너희에게 한 사람을 놓아 주는 전례가 있으니 그러면 너희는 내가 유대인의 왕을 너희에게 놓아 주기를 원하느냐 하니"},{"n":40,"t":"저희가 또 소리질러 가로되 이 사람이 아니라 바라바라 하니 바라바는 강도러라"}],"kids":[{"n":1,"t":"예수님이 이 말씀을 하시고 제자들과 함께 기드론 시내 건너편으로 나가셨어요. 거기에 동산이 있어 들어가셨어요."},{"n":2,"t":"그를 넘길 유다도 그곳을 알고 있었어요. 예수님이 자주 제자들과 거기 모이셨거든요."},{"n":3,"t":"유다가 군대와 대제사장들과 바리새인들로부터 받은 종들을 데리고 등불과 횃불과 무기를 가지고 거기로 갔어요."},{"n":4,"t":"예수님이 자기에게 임할 모든 일을 아시고 나가 \\"누구를 찾느냐?\\" 하셨어요."},{"n":5,"t":"\\"나사렛 예수\\" 했어요. 예수님이 \\"내가 그다\\" 하셨어요. 그를 넘기는 유다도 그들과 함께 서 있었어요."},{"n":6,"t":"\\"내가 그다\\" 하시자 그들이 물러나 땅에 엎드러졌어요."},{"n":7,"t":"다시 \\"누구를 찾느냐?\\" 하시니 \\"나사렛 예수\\" 했어요."},{"n":8,"t":"예수님이 \\"내가 그다 했다. 너희가 나를 찾거든 이 사람들은 가게 두어라\\" 하셨어요."},{"n":9,"t":"이는 그분이 하신 \\"아버지께서 내게 주신 사람 중 하나도 잃지 않았다\\"는 말씀을 이루려 함이에요."},{"n":10,"t":"시몬 베드로가 칼을 가지고 있어 빼어 대제사장의 종을 쳐서 오른쪽 귀를 잘랐어요. 그 종의 이름은 말고예요."},{"n":11,"t":"예수님이 베드로에게 \\"칼을 칼집에 꽂아라. 아버지께서 내게 주신 잔을 마시지 않겠느냐?\\" 하셨어요."},{"n":12,"t":"군대와 천부장과 유대인의 종들이 예수님을 잡아 묶어,"},{"n":13,"t":"먼저 안나스에게 끌고 갔어요. 그가 그 해의 대제사장 가야바의 장인이에요."},{"n":14,"t":"가야바는 한 사람이 백성을 위해 죽는 것이 유익하다고 유대인들에게 권한 사람이에요."},{"n":15,"t":"시몬 베드로와 다른 제자가 예수님을 따랐어요. 그 제자는 대제사장이 아는 사람이라 예수님과 함께 대제사장의 뜰에 들어갔어요."},{"n":16,"t":"베드로는 문 밖에 서 있었어요. 대제사장이 아는 다른 제자가 나가서 문 지키는 여자에게 말하고 베드로를 데리고 들어왔어요."},{"n":17,"t":"문 지키는 종 여자가 베드로에게 \\"너도 이 사람의 제자가 아니냐?\\" 하니 \\"아니다\\" 했어요."},{"n":18,"t":"종과 종들이 추워서 숯불을 피우고 서서 쬐고 있었어요. 베드로도 함께 서서 쬐고 있었어요."},{"n":19,"t":"대제사장이 예수님께 그분의 제자와 가르침에 대해 물었어요."},{"n":20,"t":"예수님이 \\"내가 드러내 놓고 세상에 말했다. 항상 유대인이 모두 모이는 회당과 성전에서 가르쳤고 숨겨서 말한 것이 아무것도 없다.\\""},{"n":21,"t":"\\"왜 내게 묻느냐? 내가 무엇을 말했는지 들은 사람들에게 물어 봐라. 그들이 내가 한 말을 안다\\" 하셨어요."},{"n":22,"t":"이 말씀을 하시자 곁에 선 종 중 하나가 손바닥으로 치며 \\"대제사장에게 이렇게 답하느냐?\\" 했어요."},{"n":23,"t":"예수님이 \\"내가 말을 잘못했다면 그 잘못을 증언해 봐라. 옳다면 왜 나를 치느냐?\\" 하셨어요."},{"n":24,"t":"안나스가 그분을 묶은 채로 대제사장 가야바에게 보냈어요."},{"n":25,"t":"시몬 베드로는 서서 쬐고 있었어요. 사람들이 \\"너도 그의 제자 중 하나가 아니냐?\\" 하니 부인하며 \\"아니다\\" 했어요."},{"n":26,"t":"대제사장의 종 중 베드로에게 귀가 잘린 사람의 친척이 \\"내가 너를 동산에서 그와 함께 보지 않았느냐?\\" 했어요."},{"n":27,"t":"베드로가 또 부인했고 곧 닭이 울었어요."},{"n":28,"t":"그들이 예수님을 가야바에게서 관청으로 끌고 갔어요. 새벽이었어요. 그들은 더럽혀지지 않고 유월절을 먹으려고 관청에 들어가지 않았어요."},{"n":29,"t":"빌라도가 밖으로 나가 \\"이 사람을 무슨 일로 고소하느냐?\\" 했어요."},{"n":30,"t":"\\"이 사람이 행악자가 아니면 우리가 당신께 넘기지 않았을 거예요\\" 했어요."},{"n":31,"t":"빌라도가 \\"너희가 데려다가 너희 법대로 재판하라\\" 하니 유대인들이 \\"우리는 누구도 죽일 권한이 없어요\\" 했어요."},{"n":32,"t":"이는 예수님이 자기 죽음에 대해 어떻게 죽을지 알리려고 하신 말씀을 이루려는 거예요."},{"n":33,"t":"빌라도가 다시 관청에 들어가 예수님을 불러 \\"네가 유대인의 왕이냐?\\" 했어요."},{"n":34,"t":"예수님이 \\"이 말을 네 스스로 하느냐, 다른 사람이 내게 대해 네게 말한 것이냐?\\" 하셨어요."},{"n":35,"t":"빌라도가 \\"내가 유대인이냐? 네 민족과 대제사장들이 너를 내게 넘겼다. 무슨 일을 했느냐?\\" 했어요."},{"n":36,"t":"예수님이 \\"내 나라는 이 세상에 속한 게 아니다. 만약 이 세상에 속한 것이면 내 종들이 싸워서 내가 유대인에게 넘겨지지 않게 했을 거다. 내 나라는 여기에 속한 게 아니다\\" 하셨어요."},{"n":37,"t":"빌라도가 \\"그러면 네가 왕이냐?\\" 하니 \\"네 말과 같이 내가 왕이다. 이를 위해 내가 태어났고 이를 위해 세상에 왔으니, 진리에 대해 증언하려는 거다. 진리에 속한 사람마다 내 음성을 듣는다\\" 하셨어요."},{"n":38,"t":"빌라도가 \\"진리가 무엇이냐?\\" 하고 다시 유대인들에게 나가 \\"나는 그에게서 죄를 찾지 못한다.\\""},{"n":39,"t":"\\"유월절에 너희에게 한 사람을 풀어 주는 관례가 있다. 너희는 내가 유대인의 왕을 풀어 주기를 원하느냐?\\" 했어요."},{"n":40,"t":"그들이 다시 외쳐 \\"이 사람이 아니라 바라바!\\" 했어요. 바라바는 강도였어요."}]}},{"chapter":19,"title":"십자가에 못 박히심","verses":{"krv":[{"n":1,"t":"이에 빌라도가 예수를 데려다가 채찍질하더라"},{"n":2,"t":"군병들이 가시로 면류관을 엮어 그의 머리에 씌우고 자색 옷을 입히고"},{"n":3,"t":"앞에 와서 가로되 유대인의 왕이여 평안할찌어다 하며 손바닥으로 때리더라"},{"n":4,"t":"빌라도가 다시 밖에 나가 말하되 보라 이 사람을 데리고 너희에게 나오나니 이는 내가 그에게서 아무 죄도 찾지 못한 것을 너희로 알게 하려 함이로다 하더라"},{"n":5,"t":"이에 예수께서 가시 면류관을 쓰고 자색 옷을 입고 나오시니 빌라도가 저희에게 말하되 보라 이 사람이로다 하매"},{"n":6,"t":"대제사장들과 하속들이 예수를 보고 소리질러 가로되 십자가에 못 박게 하소서 십자가에 못 박게 하소서 하는지라 빌라도가 가로되 너희가 친히 데려다가 십자가에 못 박으라 나는 그에게서 죄를 찾지 못하노라"},{"n":7,"t":"유대인들이 대답하되 우리에게 법이 있으니 그 법대로 하면 저가 당연히 죽을 것은 저가 자기를 하나님 아들이라 함이니이다"},{"n":8,"t":"빌라도가 이 말을 듣고 더욱 두려워하여"},{"n":9,"t":"다시 관정에 들어가서 예수께 말하되 너는 어디로서냐 하되 예수께서 대답하여 주지 아니하시는지라"},{"n":10,"t":"빌라도가 가로되 내게 말하지 아니하느냐 내가 너를 놓을 권세도 있고 십자가에 못 박을 권세도 있는줄 알지 못하느냐"},{"n":11,"t":"예수께서 대답하시되 위에서 주지 아니하셨더면 나를 해할 권세가 없었으리니 그러므로 나를 네게 넘겨 준 자의 죄는 더 크니라 하시니"},{"n":12,"t":"이러하므로 빌라도가 예수를 놓으려고 힘썼으나 유대인들이 소리질러 가로되 이 사람을 놓으면 가이사의 충신이 아니니이다 무릇 자기를 왕이라 하는 자는 가이사를 반역하는 것이니이다"},{"n":13,"t":"빌라도가 이 말을 듣고 예수를 끌고 나와서 박석 (히브리 말로 가바다)이란 곳에서 재판석에 앉았더라"},{"n":14,"t":"이 날은 유월절의 예비일이요 때는 제 육시라 빌라도가 유대인들에게 이르되 보라 너희 왕이로다"},{"n":15,"t":"저희가 소리지르되 없이 하소서 없이 하소서 저를 십자가에 못 박게 하소서 빌라도가 가로되 내가 너희 왕을 십자가에 못 박으랴 대제사장들이 대답하되 가이사 외에는 우리에게 왕이 없나이다 하니"},{"n":16,"t":"이에 예수를 십자가에 못 박히게 저희에게 넘겨주니라"},{"n":17,"t":"저희가 예수를 맡으매 예수께서 자기의 십자가를 지시고 해골 ( 히브리 말로 골고다)이라 하는 곳에 나오시니"},{"n":18,"t":"저희가 거기서 예수를 십자가에 못 박을새 다른 두 사람도 그와 함께 좌우편에 못 박으니 예수는 가운데 있더라"},{"n":19,"t":"빌라도가 패를 써서 십자가 위에 붙이니 나사렛 예수 유대인의 왕이라 기록되었더라"},{"n":20,"t":"예수의 못 박히신 곳이 성에서 가까운고로 많은 유대인이 이 패를 읽는데 히브리와 로마와 헬라 말로 기록되었더라"},{"n":21,"t":"유대인의 대제사장들이 빌라도에게 이르되 유대인의 왕이라 말고 자칭 유대인의 왕이라 쓰라 하니"},{"n":22,"t":"빌라도가 대답하되 나의 쓸 것을 썼다 하니라"},{"n":23,"t":"군병들이 예수를 십자가에 못 박고 그의 옷을 취하여 네 깃에 나눠 각각 한 깃씩 얻고 속옷도 취하니 이 속옷은 호지 아니하고 위에서부터 통으로 짠 것이라"},{"n":24,"t":"군병들이 서로 말하되 이것을 찢지 말고 누가 얻나 제비 뽑자 하니 이는 성경에 저희가 내 옷을 나누고 내 옷을 제비 뽑나이다 한 것을 응하게 하려 함이러라 군병들은 이런 일을 하고"},{"n":25,"t":"예수의 십자가 곁에는 그 모친과 이모와 글로바의 아내 마리아와 막달라 마리아가 섰는지라"},{"n":26,"t":"예수께서 그 모친과 사랑하시는 제자가 곁에 섰는 것을 보시고 그 모친께 말씀하시되 여자여 보소서 아들이니이다 하시고"},{"n":27,"t":"또 그 제자에게 이르시되 보라 네 어머니라 하신대 그 때부터 그 제자가 자기 집에 모시니라"},{"n":28,"t":"이 후에 예수께서 모든 일이 이미 이룬줄 아시고 성경으로 응하게 하려하사 가라사대 내가 목마르다 하시니"},{"n":29,"t":"거기 신 포도주가 가득히 담긴 그릇이 있는지라 사람들이 신 포도주를 머금은 해융을 우슬초에 매어 예수의 입에 대니"},{"n":30,"t":"예수께서 신 포도주를 받으신 후 가라사대 다 이루었다 하시고 머리를 숙이시고 영혼이 돌아가시니라"},{"n":31,"t":"이 날은 예비일이라 유대인들은 그 안식일이 큰 날이므로 그 안 식일에 시체들을 십자가에 두지 아니하려 하여 빌라도에게 그들의 다리를 꺾어 시체를 치워 달라 하니"},{"n":32,"t":"군병들이 가서 예수와 함께 못박힌 첫째 사람과 또 그 다른 사람의 다리를 꺾고"},{"n":33,"t":"예수께 이르러는 이미 죽은것을 보고 다리를 꺾지 아니하고"},{"n":34,"t":"그 중 한 군병이 창으로 옆구리를 찌르니 곧 피와 물이 나오더라"},{"n":35,"t":"이를 본 자가 증거하였으니 그 증거가 참이라 저가 자기의 말하는 것이 참인줄 알고 너희로 믿게 하려함이니라"},{"n":36,"t":"이 일이 이룬 것은 그 뼈가 하나도 꺾이우지 아니하리라 한 성경을 응하게 하려함이라"},{"n":37,"t":"또 다른 성경에 저희가 그 찌른 자를 보리라 하였느니라"},{"n":38,"t":"아리마대 사람 요셉이 예수의 제자나 유대인을 두려워하여 은휘하더니 이 일 후에 빌라도더러 예수의 시체를 가져가기를 구하매 빌라도가 허락 하는지라 이에 가서 예수의 시체를 가져가니라"},{"n":39,"t":"일찍 예수께 밤에 나아왔던 니고데모도 몰약과 침향 섞은 것을 백 근쯤 가지고 온지라"},{"n":40,"t":"이에 예수의 시체를 가져다가 유대인의 장례법대로 그 향품과 함께 세마포로 쌌더라"},{"n":41,"t":"예수의 십자가에 못 박히신 곳에 동산이 있고 동산 안에 아직 사람을 장사한 일이 없는 새 무덤이 있는지라"},{"n":42,"t":"이 날은 유대인의 예비일이요 또 무덤이 가까운고로 예수를 거기 두니라"}],"kids":[{"n":1,"t":"이에 빌라도가 예수님을 데려다 채찍질했어요."},{"n":2,"t":"군병들이 가시로 왕관을 엮어 그분의 머리에 씌우고 보라색 옷을 입혔어요."},{"n":3,"t":"앞에 가서 \\"유대인의 왕이여, 평안하라\\" 하고 손바닥으로 쳤어요."},{"n":4,"t":"빌라도가 다시 나가 \\"보라, 너희에게 이 사람을 데리고 나간다. 내가 그에게서 죄를 찾지 못한 줄을 너희가 알게 하려는 거다\\" 했어요."},{"n":5,"t":"예수님이 가시 왕관을 쓰고 보라색 옷을 입고 나오시니 빌라도가 \\"보라, 이 사람이로다!\\" 했어요."},{"n":6,"t":"대제사장과 종들이 보고 외쳐 \\"십자가에 못 박으세요, 십자가에 못 박으세요!\\" 했어요. 빌라도가 \\"너희가 데려가 못 박으라. 나는 그에게서 죄를 찾지 못한다\\" 했어요."},{"n":7,"t":"유대인들이 \\"우리에게 법이 있어요. 그 법에 의해 그가 마땅히 죽어야 해요. 자기를 하나님의 아들이라 했기 때문이에요\\" 했어요."},{"n":8,"t":"빌라도가 이 말을 듣고 더 두려워했어요."},{"n":9,"t":"다시 관청에 들어가 예수님께 \\"너는 어디서 왔느냐?\\" 하였지만 예수님이 답하지 않으셨어요."},{"n":10,"t":"빌라도가 \\"내게 말하지 않느냐? 내가 너를 풀어 줄 권한도 있고 못 박을 권한도 있는 줄 모르느냐?\\" 했어요."},{"n":11,"t":"예수님이 \\"위에서 주지 않으셨으면 나를 해할 권한이 네게 없을 거다. 그러므로 나를 네게 넘긴 사람의 죄가 더 크다\\" 하셨어요."},{"n":12,"t":"이에 빌라도가 그분을 풀어 주려 했지만 유대인들이 외쳐 \\"이 사람을 풀어 주면 당신은 가이사의 친구가 아니에요. 자기를 왕이라 하는 사람마다 가이사를 거역하는 거예요!\\" 했어요."},{"n":13,"t":"빌라도가 이 말을 듣고 예수님을 밖으로 끌고 나와 \'돌을 깐 곳\'(히브리어로 가바다)이라는 곳에 있는 재판 자리에 앉았어요."},{"n":14,"t":"이날은 유월절 예비일이고 시간은 정오쯤이었어요. 빌라도가 유대인들에게 \\"보라, 너희 왕이다!\\" 했어요."},{"n":15,"t":"그들이 외쳐 \\"없애세요, 없애세요. 십자가에 못 박으세요!\\" 했어요. 빌라도가 \\"내가 너희 왕을 십자가에 못 박으랴?\\" 하니 대제사장들이 \\"우리에게 가이사 외에는 왕이 없어요\\" 했어요."},{"n":16,"t":"이에 빌라도가 예수님을 그들에게 넘겨 십자가에 못 박게 했어요. 그들이 예수님을 끌고 갔어요."},{"n":17,"t":"그분이 자기 십자가를 지시고 \'해골의 곳\'(히브리어로 골고다)이라는 곳에 가셨어요."},{"n":18,"t":"거기서 그들이 그분을 십자가에 못 박았고 다른 두 사람도 함께, 좌우에 하나씩 그분 가운데 두었어요."},{"n":19,"t":"빌라도가 패를 적어 십자가에 붙였는데 \'나사렛 예수 유대인의 왕\'이라고 적혔어요."},{"n":20,"t":"많은 유대인이 이 패를 읽었어요. 예수님이 십자가에 못 박힌 곳이 동네에서 가까웠고 패는 히브리어와 라틴어와 헬라어로 적혔어요."},{"n":21,"t":"유대인의 대제사장들이 빌라도에게 \\"\'유대인의 왕\'이라 쓰지 말고 \'자칭 유대인의 왕\'이라 쓰세요\\" 했어요."},{"n":22,"t":"빌라도가 \\"내가 쓴 것은 쓴 것이다\\" 했어요."},{"n":23,"t":"군병들이 예수님을 십자가에 못 박고 그분의 옷을 가져다 네 부분으로 나누고 한 사람씩 하나씩 가졌어요. 속옷도 가졌는데 그 옷은 호지 않고 위에서부터 통째로 짠 것이에요."},{"n":24,"t":"군병들이 서로 \\"이 옷을 찢지 말고 누구에게 갈지 제비뽑자\\" 했어요. 이는 \\"내 옷을 자기들끼리 나누고 내 옷을 두고 제비뽑았다\\"는 성경 말씀을 이루기 위함이에요. 군병들이 이런 일을 했어요."},{"n":25,"t":"예수님의 십자가 곁에 그분의 어머니와 어머니의 자매와 글로바의 아내 마리아와 막달라 마리아가 서 있었어요."},{"n":26,"t":"예수님이 어머니와 사랑하시는 제자가 곁에 선 것을 보시고 어머니에게 \\"여인이여, 보소서, 아들이에요\\" 하셨어요."},{"n":27,"t":"그 제자에게 \\"보라, 네 어머니다\\" 하셨어요. 그 시간부터 그 제자가 자기 집에 모셨어요."},{"n":28,"t":"이 후에 예수님이 모든 일이 이미 이루어진 것을 아시고 성경을 이루려고 \\"내가 목마르다\\" 하셨어요."},{"n":29,"t":"거기 신 포도주가 가득한 그릇이 있어 사람들이 신 포도주를 머금은 해면을 우슬초에 매어 그분 입에 댔어요."},{"n":30,"t":"신 포도주를 받으신 후 \\"다 이루었다\\" 하시고 머리를 숙이고 영혼이 떠나가셨어요."},{"n":31,"t":"유대인들은 그날이 예비일이라 안식일에 시체가 십자가에 있지 않게 하려고(이 안식일은 큰 날이었어요) 빌라도에게 그들의 다리를 꺾어 시체를 치워 달라 청했어요."},{"n":32,"t":"군병들이 와서 첫 번째와 함께 못 박힌 다른 사람의 다리를 꺾고,"},{"n":33,"t":"예수님께 와서 이미 죽으신 것을 보고 다리를 꺾지 않았어요."},{"n":34,"t":"군병 중 하나가 창으로 옆구리를 찌르니 곧 피와 물이 나왔어요."},{"n":35,"t":"이를 본 사람이 증언했어요. 그 증언이 참됨을 알아요. 그는 자기 말이 참된 줄 알고 너희도 믿게 하려고 말한 거예요."},{"n":36,"t":"이런 일이 일어난 것은 \\"그분의 뼈는 하나도 꺾이지 않으리라\\"는 성경 말씀을 이루려는 거예요."},{"n":37,"t":"또 다른 성경에 \\"그들이 자기들이 찌른 분을 볼 거다\\" 했어요."},{"n":38,"t":"이 후에 아리마대 사람 요셉이 예수님의 시신을 가져가게 해 달라고 빌라도에게 청했어요. 그는 예수님의 제자이지만 유대인을 두려워해 숨겼었어요. 빌라도가 허락하니 그가 가서 예수님의 시신을 가져갔어요."},{"n":39,"t":"전에 밤에 예수님께 왔던 니고데모도 몰약과 침향 섞은 것 백 근쯤을 가지고 왔어요."},{"n":40,"t":"그들이 예수님의 시신을 가져다 유대인의 장례 관습대로 그 향품과 함께 세마포로 쌌어요."},{"n":41,"t":"예수님이 십자가에 못 박히신 곳에 동산이 있었고 그 동산에 아직 누구도 누인 적 없는 새 무덤이 있었어요."},{"n":42,"t":"유대인의 예비일이고 그 무덤이 가까워서 예수님을 거기 두었어요."}]}},{"chapter":20,"title":"부활하신 예수님","verses":{"krv":[{"n":1,"t":"안식 후 첫날 이른 아침 아직 어두울 때에 막달라 마리아가 무덤에 와서 돌이 무덤에서 옮겨간 것을 보고"},{"n":2,"t":"시몬 베드로와 예수의 사랑하시던 그 다른 제자에게 달려가서 말하되 사람이 주를 무덤에서 가져다가 어디 두었는지 우리가 알지 못하겠다 하니"},{"n":3,"t":"베드로와 그 다른 제자가 나가서 무덤으로 갈새"},{"n":4,"t":"둘이 같이 달음질하더니 그 다른 제자가 베드로보다 더 빨리 달아나서 먼저 무덤에 이르러"},{"n":5,"t":"구푸려 세마포 놓인 것을 보았으나 들어가지는 아니하였더니"},{"n":6,"t":"시몬 베드로도 따라 와서 무덤에 들어가 보니 세마포가 놓였고"},{"n":7,"t":"또 머리를 쌌던 수건은 세마포와 함께 놓이지 않고 딴 곳에 개켜 있더라"},{"n":8,"t":"그 때에야 무덤에 먼저 왔던 그 다른 제자도 들어가 보고 믿더라"},{"n":9,"t":"(저희는 성경에 그가 죽은 자 가운데서 다시 살아나야 하리라 하신 말씀을 아직 알지 못하더라)"},{"n":10,"t":"이에 두 제자가 자기 집으로 돌아가니라"},{"n":11,"t":"마리아는 무덤 밖에 서서 울고 있더니 울면서 구푸려 무덤 속을 들여다보니"},{"n":12,"t":"흰 옷 입은 두 천사가 예수의 시체 뉘었던 곳에 하나는 머리 편에 하나는 발 편에 앉았더라"},{"n":13,"t":"천사들이 가로되 여자여 어찌하여 우느냐 가로되 사람이 내 주를 가져다가 어디 두었는지 내가 알지 못함이니이다"},{"n":14,"t":"이 말을 하고 뒤로 돌이켜 예수의 서신 것을 보나 예수신줄 알지못하더라"},{"n":15,"t":"예수께서 가라사대 여자여 어찌하여 울며 누구를 찾느냐 하시니 마리아는 그가 동산지기인 줄로 알고 가로되 주여 당신이 옮겨 갔거든 어디 두었는지 내게 이르소서 그리하면 내가 가져가리이다"},{"n":16,"t":"예수께서 마리아야 하시거늘 마리아가 돌이켜 히브리 말로 랍오니여 하니 (이는 선생님이라)"},{"n":17,"t":"예수께서 이르시되 나를 만지지 말라 내가 아직 아버지께로 올라가지 못하였노라 너는 내 형제들에게 가서 이르되 내가 내 아버지 곧 너희 아버지 내 하나님 곧 너희 하나님께로 올라간다 하라 하신대"},{"n":18,"t":"막달라 마리아가 가서 제자들에게 내가 주를 보았다 하고 또 주께서 자기에게 이렇게 말씀하셨다 이르니라"},{"n":19,"t":"이 날 곧 안식 후 첫날 저녁 때에 제자들이 유대인들을 두려워하여 모인 곳에 문들을 닫았더니 예수께서 오사 가운데 서서 가라사대 너희에게 평강이 있을찌어다"},{"n":20,"t":"이 말씀을 하시고 손과 옆구리를 보이시니 제자들이 주를 보고 기뻐하더라"},{"n":21,"t":"예수께서 또 가라사대 너희에게 평강이 있을지어다 아버지께서 나를 보내신 것 같이 나도 너희를 보내노라"},{"n":22,"t":"이 말씀을 하시고 저희를 향하사 숨을 내쉬며 가라사대 성령을 받으라"},{"n":23,"t":"너희가 뉘 죄든지 사하면 사하여질 것이요 뉘 죄든지 그대로 두면 그대로 있으리라 하시니라"},{"n":24,"t":"열 두 제자 중에 하나인 디두모라 하는 도마는 예수 오셨을 때에 함께 있지 아니한지라"},{"n":25,"t":"다른 제자들이 그에게 이르되 우리가 주를 보았노라 하니 도마가 가로되 내가 그 손의 못자국을 보며 내 손가락을 그 못자국에 넣으며 내 손을 그 옆구리에 넣어 보지 않고는 믿지 아니하겠노라 하니라"},{"n":26,"t":"여드레를 지나서 제자들이 다시 집 안에 있을 때에 도마도 함께 있고 문들이 닫혔는데 예수께서 오사 가운데 서서 가라사대 너희에게 평강이 있을지어다 하시고"},{"n":27,"t":"도마에게 이르시되 네 손가락을 이리 내밀어 내 손을 보고 네 손을 내밀어 내 옆구리에 넣어보라 그리하고 믿음 없는 자가 되지 말고 믿는 자가 되라"},{"n":28,"t":"도마가 대답하여 가로되 나의 주시며 나의 하나님이시니이다"},{"n":29,"t":"예수께서 가라사대 너는 나를 본 고로 믿느냐 보지 못하고 믿는 자들은 복되도다 하시니라"},{"n":30,"t":"예수께서 제자들 앞에서 이책에 기록되지 아니한 다른 표적도 많이 행하셨으나"},{"n":31,"t":"오직 이것을 기록함은 너희로 예수께서 하나님의 아들 그리스도이심을 믿게 하려 함이요 또 너희로 믿고 그 이름을 힘입어 생명을 얻게 하려 함이니라"}],"kids":[{"n":1,"t":"안식 후 첫날 일찍, 아직 어두울 때 막달라 마리아가 무덤에 가서 돌이 무덤에서 옮겨진 것을 보았어요."},{"n":2,"t":"달려가서 시몬 베드로와 예수님이 사랑하시는 다른 제자에게 \\"사람들이 무덤에서 주를 옮겨 갔는데 어디 두었는지 모르겠어요\\" 했어요."},{"n":3,"t":"베드로와 그 다른 제자가 무덤으로 갔어요."},{"n":4,"t":"둘이 함께 달려갔는데 그 다른 제자가 더 빨리 달려 베드로보다 먼저 무덤에 이르러,"},{"n":5,"t":"굽혀 세마포가 놓인 것을 보고도 들어가지는 않았어요."},{"n":6,"t":"시몬 베드로가 따라와 무덤에 들어가 세마포가 놓인 것과,"},{"n":7,"t":"예수님의 머리를 쌌던 수건이 세마포와 함께 놓이지 않고 따로 한 곳에 개켜진 것을 보았어요."},{"n":8,"t":"먼저 무덤에 왔던 그 다른 제자도 들어가 보고 믿었어요."},{"n":9,"t":"그들은 그분이 죽은 자 가운데서 살아나야 한다는 성경 말씀을 아직 알지 못했거든요."},{"n":10,"t":"제자들이 자기 집으로 돌아갔어요."},{"n":11,"t":"마리아는 무덤 밖에 서서 울고 있었어요. 울면서 굽혀 무덤 안을 보니,"},{"n":12,"t":"흰 옷 입은 두 천사가 예수님의 시신이 놓였던 곳에 머리 편과 발 편에 각각 앉아 있었어요."},{"n":13,"t":"천사들이 \\"여인이여, 왜 우느냐?\\" 하니 \\"사람들이 내 주를 옮겨 갔는데 어디 두었는지 모르겠어요\\" 했어요."},{"n":14,"t":"이 말을 하고 뒤를 돌아보니 예수님이 서 계셨지만 그분이 예수님인 줄 알지 못했어요."},{"n":15,"t":"예수님이 \\"여인이여, 왜 우느냐? 누구를 찾느냐?\\" 하시니 마리아가 동산지기인 줄로 알고 \\"선생님, 당신이 그분을 옮겼으면 어디 두셨는지 말씀해 주세요. 제가 모셔 가겠어요\\" 했어요."},{"n":16,"t":"예수님이 \\"마리아야\\" 하셨어요. 그녀가 돌이켜 히브리어로 \\"라보니!\\" 했어요. 이는 \'선생님\'이라는 뜻이에요."},{"n":17,"t":"예수님이 \\"나를 만지지 마라. 내가 아직 아버지께 올라가지 않았다. 내 형제들에게 가서 \'내가 내 아버지 곧 너희 아버지, 내 하나님 곧 너희 하나님께로 올라간다\' 하라\\" 하셨어요."},{"n":18,"t":"막달라 마리아가 가서 \\"내가 주를 봤어요\\" 하고 그분이 자기에게 하신 말씀을 제자들에게 알렸어요."},{"n":19,"t":"그날 곧 안식 후 첫날 저녁에 제자들이 유대인을 두려워해 문을 닫고 있을 때 예수님이 오셔서 가운데 서며 \\"평안이 너희에게\\" 하셨어요."},{"n":20,"t":"이 말씀을 하시고 손과 옆구리를 보이시니 제자들이 주를 보고 기뻐했어요."},{"n":21,"t":"예수님이 다시 \\"평안이 너희에게. 아버지께서 나를 보내신 것 같이 나도 너희를 보낸다\\" 하셨어요."},{"n":22,"t":"이 말씀을 하시고 그들에게 숨을 내쉬며 \\"성령을 받아라.\\""},{"n":23,"t":"\\"너희가 누구의 죄든 용서하면 용서되고 누구의 죄든 그대로 두면 그대로 있을 거다\\" 하셨어요."},{"n":24,"t":"열둘 중 하나, 디두모라 하는 도마는 예수님이 오실 때 함께 있지 않았어요."},{"n":25,"t":"다른 제자들이 \\"우리가 주를 봤어\\" 하니 \\"내가 그분의 손에 못 자국을 보고 내 손가락을 그 자리에 넣고 내 손을 그분 옆구리에 넣지 않으면 결코 믿지 않을 거다\\" 했어요."},{"n":26,"t":"여드레가 지난 후 제자들이 또 안에 있고 도마도 함께 있었어요. 문이 닫혔는데 예수님이 오셔서 가운데 서며 \\"평안이 너희에게\\" 하셨어요."},{"n":27,"t":"도마에게 \\"네 손가락을 이리 대 보고 내 손을 보고 네 손을 내 옆구리에 넣어라. 믿지 말고 믿는 사람이 되어라\\" 하셨어요."},{"n":28,"t":"도마가 \\"내 주, 내 하나님이세요!\\" 했어요."},{"n":29,"t":"예수님이 \\"너는 나를 보고 믿느냐? 보지 않고 믿는 사람은 복이 있다\\" 하셨어요."},{"n":30,"t":"예수님이 제자들 앞에서 이 책에 적히지 않은 다른 많은 표적을 행하셨어요."},{"n":31,"t":"이것을 기록한 것은 너희가 예수께서 그리스도, 하나님의 아들이심을 믿게 하고 또 믿어 그 이름으로 생명을 얻게 하려는 거예요."}]}},{"chapter":21,"title":"부활 후 베드로에게 나타나심","verses":{"krv":[{"n":1,"t":"그 후에 예수께서 디베랴 바다에서 또 제자들에게 자기를 나타내셨으니 나타내신 일이 이러하니라"},{"n":2,"t":"시몬 베드로와 디두모라 하는 도마와 갈릴리 가나 사람 나다나엘과 세베대의 아들들과 또 다른 제자 둘이 함께 있더니"},{"n":3,"t":"시몬 베드로가 나는 물고기 잡으러 가노라 하매 저희가 우리도 함께 가겠다 하고 나가서 배에 올랐으나 이 밤에 아무 것도 잡지 못하였더니"},{"n":4,"t":"날이 새어갈 때에 예수께서 바닷가에 서셨으나 제자들이 예수신줄 알지 못하는지라"},{"n":5,"t":"예수께서 이르시되 얘들아 너희에게 고기가 있느냐 대답하되 없나이다"},{"n":6,"t":"가라사대 그물을 배 오른 편에 던지라 그리하면 얻으리라 하신대 이에 던졌더니 고기가 많아 그물을 들 수 없더라"},{"n":7,"t":"예수의 사랑하시는 그 제자가 베드로에게 이르되 주시라 하니 시몬 베드로가 벗고 있다가 주라 하는 말을 듣고 겉옷을 두른 후에 바다로 뛰어 내리더라"},{"n":8,"t":"다른 제자들은 육지에서 상거가 불과 한 오십 간쯤 되므로 작은 배를 타고 고기든 그물을 끌고 와서"},{"n":9,"t":"육지에 올라보니 숯불이 있는데 그 위에 생선이 놓였고 떡도 있더라"},{"n":10,"t":"예수께서 가라사대 지금 잡은 생선을 좀 가져오라 하신대"},{"n":11,"t":"시몬 베드로가 올라가서 그물을 육지에 끌어 올리니 가득히 찬 큰 고기가 일백 쉰 세 마리라 이같이 많으나 그물이 찢어지지 아니하였더라"},{"n":12,"t":"예수께서 가라사대 와서 조반을 먹으라 하시니 제자들이 주신 줄 아는 고로 당신이 누구냐 감히 묻는 자가 없더라"},{"n":13,"t":"예수께서 가셔서 떡을 가져다가 저희에게 주시고 생선도 그와 같이 하시니라"},{"n":14,"t":"이것은 예수께서 죽은자 가운데서 살아나신 후에 세 번째로 제자들에게 나타나신 것이라"},{"n":15,"t":"저희가 조반 먹은 후에 예수께서 시몬 베드로에게 이르시되 요한의 아들 시몬아 네가 이 사람들보다 나를 더 사랑하느냐 하시니 가로되 주여 그러하외다 내가 주를 사랑하는줄 주께서 아시나이다 가라사대 내 어린 양을 먹이라 하시고"},{"n":16,"t":"또 두번째 가라사대 요한의 아들 시몬아 네가 나를 사랑하느냐 하시니 가로되 주여 그러하외다 내가 주를 사랑하는줄 주께서 아시나이다 가라사대 내 양을 치라 하시고"},{"n":17,"t":"세 번째 가라사대 요한의 아들 시몬아 네가 나를 사랑하느냐 하시니 주께서 세번째 네가 나를 사랑하느냐 하시므로 베드로가 근심하여 가로되 주여 모든 것을 아시오매 내가 주를 사랑하는 줄을 주께서 아시나이다 예수께서 가라사대 내 양을 먹이라"},{"n":18,"t":"내가 진실로 진실로 네게 이르노니 젊어서는 네가 스스로 띠 띠고 원하는 곳으로 다녔거니와 늙어서는 네 팔을 벌리리니 남이 네게 띠 띠우고 원치 아니하는 곳으로 데려가리라"},{"n":19,"t":"이 말씀을 하심은 베드로가 어떠한 죽음으로 하나님께 영광을 돌릴 것을 가리키심이러라 이 말씀을 하시고 베드로에게 이르시되 나를 따르라 하시니"},{"n":20,"t":"베드로가 돌이켜 예수의 사랑하시는 그 제자가 따르는 것을 보니 그는 만찬석에서 예수의 품에 의지하여 주여 주를 파는 자가 누구오니이까 묻던 자러라"},{"n":21,"t":"이에 베드로가 그를 보고 예수께 여짜오되 주여 이 사람은 어떻게 되겠삽나이까"},{"n":22,"t":"예수께서 가라사대 내가 올 때까지 그를 머물게 하고자 할지라도 네게 무슨 상관이냐 너는 나를 따르라 하시더라"},{"n":23,"t":"이 말씀이 형제들에게 나가서 그 제자는 죽지 아니하겠다 하였으나 예수의 말씀은 그가 죽지 않겠다 하신 것이 아니라 내가 올 때까지 그를 머물게 하고자 할찌라도 네게 무슨 상관이냐 하신 것이러라"},{"n":24,"t":"이 일을 증거하고 이 일을 기록한 제자가 이 사람이라 우리는 그의 증거가 참인줄 아노라"},{"n":25,"t":"예수의 행하신 일이 이 외에도 많으니 만일 낱낱이 기록된다면 이 세상이라도 이 기록된 책을 두기에 부족할줄 아노라"}],"kids":[{"n":1,"t":"그 후에 예수님이 디베랴 바다에서 다시 제자들에게 자기를 나타내셨어요. 나타내신 것은 이러해요."},{"n":2,"t":"시몬 베드로와 디두모라 하는 도마와 갈릴리 가나의 나다나엘과 세베대의 아들들과 다른 제자 둘이 함께 있었어요."},{"n":3,"t":"시몬 베드로가 \\"나는 물고기 잡으러 간다\\" 하니 \\"우리도 함께 가겠다\\" 했어요. 그들이 나가 배에 올랐지만 그 밤에 아무것도 잡지 못했어요."},{"n":4,"t":"날이 밝아 올 때 예수님이 바닷가에 서셨지만 제자들은 그분이 예수님이신 줄 알지 못했어요."},{"n":5,"t":"예수님이 \\"얘들아, 너희에게 먹을 게 있느냐?\\" 하시니 \\"없어요\\" 했어요."},{"n":6,"t":"\\"그물을 배 오른쪽에 던지면 잡힐 거다\\" 하시기에 던지니 물고기가 너무 많아 끌어올릴 수 없었어요."},{"n":7,"t":"예수님이 사랑하시는 제자가 베드로에게 \\"주이시다\\" 하니 시몬 베드로가 주이신 줄 듣고 (벗고 있었기 때문에) 겉옷을 두르고 바다에 뛰어내렸어요."},{"n":8,"t":"다른 제자들은 배에 그대로 물고기 든 그물을 끌고 갔어요. 육지에서 멀지 않고 약 이백 자(약 90미터)쯤 떨어졌거든요."},{"n":9,"t":"육지에 내려 보니 숯불이 피워졌고 그 위에 물고기와 빵이 있었어요."},{"n":10,"t":"예수님이 \\"지금 잡은 물고기를 좀 가져오라\\" 하셨어요."},{"n":11,"t":"시몬 베드로가 올라가 그물을 육지에 끌어 올렸는데 가득한 큰 물고기 백쉰세 마리예요. 이렇게 많았는데 그물이 찢어지지 않았어요."},{"n":12,"t":"예수님이 \\"와서 아침을 먹어라\\" 하셨어요. 제자 중 누구도 감히 \\"당신이 누구세요?\\" 묻지 못했어요. 주이신 줄 알았기 때문이에요."},{"n":13,"t":"예수님이 가서 빵과 물고기를 가져다 그들에게 주셨어요."},{"n":14,"t":"이것이 예수님이 죽은 자 가운데서 살아나신 후에 제자들에게 세 번째로 나타나신 거예요."},{"n":15,"t":"아침을 먹은 후 예수님이 시몬 베드로에게 \\"요한의 아들 시몬아, 이 사람들보다 나를 더 사랑하느냐?\\" 하셨어요. 베드로가 \\"그래요, 주여, 제가 주를 사랑하는 줄을 주께서 아세요\\" 했어요. \\"내 어린 양을 먹여라\\" 하셨어요."},{"n":16,"t":"두 번째로 \\"요한의 아들 시몬아, 나를 사랑하느냐?\\" 하시니 \\"그래요, 주여, 제가 주를 사랑하는 줄을 주께서 아세요\\" 했어요. \\"내 양을 치라\\" 하셨어요."},{"n":17,"t":"세 번째로 \\"요한의 아들 시몬아, 나를 사랑하느냐?\\" 하시니 베드로가 세 번이나 \\"나를 사랑하느냐?\\" 하시는 게 슬퍼서 \\"주여, 모든 것을 아세요. 제가 주를 사랑하는 줄을 주께서 아세요\\" 했어요. 예수님이 \\"내 양을 먹여라.\\""},{"n":18,"t":"\\"진정으로 진정으로 너에게 말한다. 네가 젊었을 때는 스스로 띠 띠고 원하는 곳으로 다녔지만 늙어서는 손을 펴라. 다른 사람이 띠 띠고 너를 데려가 원치 않는 곳으로 갈 거다\\" 하셨어요."},{"n":19,"t":"이는 베드로가 어떤 죽음으로 하나님께 영광 돌릴지 가리키신 거예요. 이 말씀을 하시고 \\"나를 따르라\\" 하셨어요."},{"n":20,"t":"베드로가 돌아서서 예수님이 사랑하시는 제자가 따르는 것을 보았어요. 그는 만찬 자리에서 예수님의 가슴에 의지하여 \\"주여, 누가 주를 넘겨요?\\" 하던 사람이에요."},{"n":21,"t":"베드로가 그를 보고 \\"주여, 이 사람은 어떻게 되겠어요?\\" 했어요."},{"n":22,"t":"예수님이 \\"내가 올 때까지 그가 머물기를 내가 원한들 너에게 무슨 상관이냐? 너는 나를 따르라\\" 하셨어요."},{"n":23,"t":"이 말이 형제들 가운데 퍼져 그 제자가 죽지 않는다 했지만 예수님은 그가 죽지 않는다 하지 않으셨고 \\"내가 올 때까지 그를 머물게 하길 내가 원한들 너에게 무슨 상관이냐?\\" 하신 거예요."},{"n":24,"t":"이 사람이 이 일들에 대해 증언하고 또 기록한 제자이며 우리는 그의 증언이 참된 줄 알아요."},{"n":25,"t":"예수님이 행하신 일이 이 외에도 많아요. 만약 낱낱이 기록한다면 이 세상이라도 그 기록될 책을 다 두지 못할 거예요."}]}}]}');

